// ExamHub Service Worker v2 - Enhanced PWA Support
const CACHE_VERSION = 'examhub-v3';
const STATIC_CACHE = `${CACHE_VERSION}-static`;
const DYNAMIC_CACHE = `${CACHE_VERSION}-dynamic`;
const IMAGE_CACHE = `${CACHE_VERSION}-images`;

// Static assets to precache
const PRECACHE_ASSETS = [
    '/',
    '/login',
    '/register',
    '/student/dashboard',
    '/manifest.json',
    '/offline.html',
];

// Cache size limits
const CACHE_LIMITS = {
    dynamic: 50,
    images: 30,
};

// Install event - precache static assets
self.addEventListener('install', (event) => {
    event.waitUntil(
        caches.open(STATIC_CACHE)
            .then((cache) => cache.addAll(PRECACHE_ASSETS))
            .then(() => self.skipWaiting())
    );
});

// Activate event - clean up old caches
self.addEventListener('activate', (event) => {
    event.waitUntil(
        caches.keys().then((cacheNames) => {
            return Promise.all(
                cacheNames
                    .filter((name) => name.startsWith('examhub-') && !name.startsWith(CACHE_VERSION))
                    .map((name) => caches.delete(name))
            );
        }).then(() => self.clients.claim())
    );
});

// Helper: Limit cache size
async function limitCacheSize(cacheName, maxItems) {
    const cache = await caches.open(cacheName);
    const keys = await cache.keys();
    if (keys.length > maxItems) {
        await cache.delete(keys[0]);
        return limitCacheSize(cacheName, maxItems);
    }
}

// Fetch strategies
const strategies = {
    // Network first - for dynamic content
    networkFirst: async (request, cacheName) => {
        try {
            const response = await fetch(request);
            if (response.ok) {
                const cache = await caches.open(cacheName);
                cache.put(request, response.clone());
                limitCacheSize(cacheName, CACHE_LIMITS.dynamic);
            }
            return response;
        } catch (error) {
            const cached = await caches.match(request);
            return cached || caches.match('/offline.html');
        }
    },

    // Cache first - for static assets
    cacheFirst: async (request, cacheName) => {
        const cached = await caches.match(request);
        if (cached) return cached;

        try {
            const response = await fetch(request);
            if (response.ok) {
                const cache = await caches.open(cacheName);
                cache.put(request, response.clone());
            }
            return response;
        } catch (error) {
            return caches.match('/offline.html');
        }
    },

    // Stale while revalidate - for images
    staleWhileRevalidate: async (request, cacheName) => {
        const cached = await caches.match(request);

        const fetchPromise = fetch(request).then((response) => {
            if (response.ok) {
                const responseToCache = response.clone();
                caches.open(cacheName).then((cache) => {
                    cache.put(request, responseToCache);
                    limitCacheSize(cacheName, CACHE_LIMITS.images);
                });
            }
            return response;
        }).catch(() => cached);

        return cached || fetchPromise;
    },
};

// Fetch event handler
self.addEventListener('fetch', (event) => {
    const { request } = event;
    const url = new URL(request.url);

    // Skip non-GET requests
    if (request.method !== 'GET') return;

    // Skip non-http/https requests (e.g. chrome-extension://)
    if (!url.protocol.startsWith('http')) return;

    // Skip API requests - always network
    if (url.pathname.startsWith('/api')) return;

    // Skip Supabase requests
    if (url.hostname.includes('supabase')) return;

    // Skip exam taking and arena - require fresh data
    if (url.pathname.includes('/take') || url.pathname.includes('/arena')) return;

    // Images - stale while revalidate
    if (request.destination === 'image' || url.pathname.match(/\.(png|jpg|jpeg|svg|gif|webp|ico)$/i)) {
        event.respondWith(strategies.staleWhileRevalidate(request, IMAGE_CACHE));
        return;
    }

    // Static assets - cache first
    if (url.pathname.match(/\.(js|css|woff2?|ttf|eot)$/i) || PRECACHE_ASSETS.includes(url.pathname)) {
        event.respondWith(strategies.cacheFirst(request, STATIC_CACHE));
        return;
    }

    // HTML pages - network first
    if (request.headers.get('accept')?.includes('text/html')) {
        event.respondWith(strategies.networkFirst(request, DYNAMIC_CACHE));
        return;
    }

    // Default - network first
    event.respondWith(strategies.networkFirst(request, DYNAMIC_CACHE));
});

// Push notification handler
self.addEventListener('push', (event) => {
    if (!event.data) return;

    const data = event.data.json();
    const { title, body, icon, url } = data;

    event.waitUntil(
        self.registration.showNotification(title || 'ExamHub', {
            body: body || 'Bạn có thông báo mới',
            icon: icon || '/icons/icon-192.png',
            badge: '/icons/icon-192.png',
            vibrate: [200, 100, 200],
            data: { url },
            actions: [
                { action: 'open', title: 'Mở' },
                { action: 'close', title: 'Đóng' },
            ],
        })
    );
});

// Notification click handler
self.addEventListener('notificationclick', (event) => {
    event.notification.close();

    if (event.action === 'close') return;

    const url = event.notification.data?.url || '/';
    event.waitUntil(
        clients.matchAll({ type: 'window' }).then((clientList) => {
            // Focus existing window if open
            for (const client of clientList) {
                if (client.url === url && 'focus' in client) {
                    return client.focus();
                }
            }
            // Open new window
            if (clients.openWindow) {
                return clients.openWindow(url);
            }
        })
    );
});

// Background sync for offline submissions
self.addEventListener('sync', (event) => {
    if (event.tag === 'sync-submissions') {
        event.waitUntil(syncOfflineSubmissions());
    }
});

async function syncOfflineSubmissions() {
    // This would sync any offline exam submissions when back online
    // Implementation depends on IndexedDB storage of pending submissions
    console.log('[SW] Background sync triggered');
}

import { NextRequest, NextResponse } from "next/server";

// V98Store API (OpenAI compatible format)
const V98_API_KEY = process.env.GEMINI_API_KEY || "sk-ewNhLj4fTcPUGWDstbRMibwnhjtZ5gB4q4CxMhEQ0gg5xZlx";
const V98_BASE_URL = process.env.GEMINI_BASE_URL || "https://v98store.com";

// Models to try (gemini-2.0-flash first as per user preference)
const MODELS = [
    "gemini-2.0-flash",            // Primary - fast + stable
    "gemini-3-flash-preview",      // Fallback - more capable
];

interface ExtractedQuestion {
    content: string;
    options: string[];
    correct_answer: string;
    explanation?: string;
    difficulty: number;
}

// System prompt optimized for scientific content
const EXTRACTION_PROMPT = `Bạn là chuyên gia phân tích đề thi Toán/Lý/Hóa Việt Nam cấp THPT.

NHIỆM VỤ: Trích xuất TẤT CẢ câu hỏi trắc nghiệm từ tài liệu.

QUY TẮC BẮT BUỘC:
1. GIỮ NGUYÊN ký hiệu toán học: √, ∫, Σ, π, θ, Ω, μ, λ, α, β, γ, Δ, ∞
2. GIỮ NGUYÊN đơn vị SI: m/s², kg, mol/L, Pa, J, W, N, A, V, Hz, °C, K
3. GIỮ NGUYÊN hằng số khoa học:
   - g = 10 m/s² (gia tốc trọng trường)
   - c = 3×10⁸ m/s (tốc độ ánh sáng)
   - N_A = 6.022×10²³ (số Avogadro)
   - R = 8.314 J/(mol·K) (hằng số khí)
   - h = 6.626×10⁻³⁴ J·s (hằng số Planck)

4. CHUYỂN công thức sang LaTeX inline:
   - E=mc² → $E=mc^2$
   - F=ma → $F=ma$
   - v=√(2gh) → $v=\\sqrt{2gh}$
   - ∫f(x)dx → $\\int f(x)dx$

5. ĐỘ KHÓ (difficulty):
   - 1: Dễ - Nhận biết, công thức cơ bản
   - 2: Trung bình - Thông hiểu, 1-2 bước tính
   - 3: Khó - Vận dụng, nhiều bước
   - 4: Rất khó - Vận dụng cao, tổng hợp kiến thức

6. ĐÁP ÁN phải là: "A", "B", "C", hoặc "D"

OUTPUT FORMAT (JSON Array):
[
  {
    "content": "Một vật có khối lượng $m = 2$ kg chuyển động...",
    "options": ["A. 10 m/s", "B. 20 m/s", "C. 30 m/s", "D. 40 m/s"],
    "correct_answer": "B",
    "explanation": "Áp dụng công thức $v = \\sqrt{2gh}$ với $g = 10$ m/s²...",
    "difficulty": 2
  }
]

CHỈ TRẢ VỀ JSON ARRAY, KHÔNG CÓ TEXT KHÁC.`;

async function extractWithV98(
    text: string,
    model: string = MODELS[0]
): Promise<ExtractedQuestion[]> {
    try {
        // Check if this is a PDF base64
        const isPdfBase64 = text.startsWith("__PDF_BASE64__");

        let messages;
        if (isPdfBase64) {
            const base64Data = text.replace("__PDF_BASE64__", "");
            // OpenAI-compatible vision format
            messages = [{
                role: "user",
                content: [
                    { type: "text", text: EXTRACTION_PROMPT },
                    {
                        type: "image_url",
                        image_url: {
                            url: `data:application/pdf;base64,${base64Data}`
                        }
                    }
                ]
            }];
        } else {
            messages = [{
                role: "user",
                content: EXTRACTION_PROMPT + `\n\nTÀI LIỆU CẦN TRÍCH XUẤT:\n${text.slice(0, 15000)}`
            }];
        }

        const response = await fetch(`${V98_BASE_URL}/v1/chat/completions`, {
            method: "POST",
            headers: {
                "Authorization": `Bearer ${V98_API_KEY}`,
                "Content-Type": "application/json"
            },
            body: JSON.stringify({
                model,
                messages,
                temperature: 0.1,
                max_tokens: 8192
            })
        });

        if (!response.ok) {
            const errText = await response.text();
            console.error("V98 API error:", errText);
            throw new Error(`API error: ${response.status}`);
        }

        const data = await response.json();
        const responseText = data.choices?.[0]?.message?.content || "";

        // Extract JSON from response
        let jsonText = responseText.trim();
        if (jsonText.startsWith("```json")) jsonText = jsonText.slice(7);
        if (jsonText.startsWith("```")) jsonText = jsonText.slice(3);
        if (jsonText.endsWith("```")) jsonText = jsonText.slice(0, -3);
        jsonText = jsonText.trim();

        const jsonMatch = jsonText.match(/\[[\s\S]*\]/);
        if (!jsonMatch) {
            console.error("Response without JSON:", responseText.slice(0, 500));
            throw new Error("No JSON array found in response");
        }

        let parsedJson = jsonMatch[0];

        // Try to fix common JSON issues (truncated responses)
        try {
            // First try direct parse
            const questions = JSON.parse(parsedJson) as ExtractedQuestion[];
            return questions.filter(q =>
                q.content &&
                q.options &&
                q.options.length >= 4 &&
                ["A", "B", "C", "D"].includes(q.correct_answer) &&
                q.difficulty >= 1 && q.difficulty <= 4
            );
        } catch (parseError) {
            console.log("Initial JSON parse failed, attempting to fix...");

            // Try to fix truncated JSON by closing brackets
            if (parsedJson.includes('"content"') && parsedJson.includes('"options"')) {
                // Find last complete object ending with }
                const lastCompleteObj = parsedJson.lastIndexOf('},');
                if (lastCompleteObj > 0) {
                    parsedJson = parsedJson.slice(0, lastCompleteObj + 1) + ']';
                    console.log("Attempted to fix truncated JSON");
                    try {
                        const questions = JSON.parse(parsedJson) as ExtractedQuestion[];
                        console.log(`Recovered ${questions.length} questions from truncated response`);
                        return questions.filter(q =>
                            q.content &&
                            q.options &&
                            q.options.length >= 4 &&
                            ["A", "B", "C", "D"].includes(q.correct_answer) &&
                            q.difficulty >= 1 && q.difficulty <= 4
                        );
                    } catch {
                        console.error("Fixed JSON still invalid");
                    }
                }
            }

            console.error("JSON parse error, raw response:", jsonText.slice(0, 1000));
            throw new Error("Failed to parse AI response as JSON");
        }
    } catch (error) {
        console.error(`Error with model ${model}:`, error);
        throw error;
    }
}

async function extractTextFromFile(file: File): Promise<string> {
    const arrayBuffer = await file.arrayBuffer();
    const buffer = Buffer.from(arrayBuffer);

    if (file.name.endsWith(".txt")) {
        return buffer.toString("utf-8");
    }

    if (file.name.endsWith(".docx")) {
        // Use mammoth for Word files
        try {
            const mammoth = await import("mammoth");
            const result = await mammoth.extractRawText({ buffer });
            return result.value;
        } catch {
            throw new Error("Word parsing not available. Please install: npm install mammoth");
        }
    }

    if (file.name.endsWith(".xlsx") || file.name.endsWith(".xls")) {
        // Use xlsx for Excel files
        try {
            const XLSX = await import("xlsx");
            const workbook = XLSX.read(buffer, { type: "buffer" });
            let text = "";
            workbook.SheetNames.forEach(sheetName => {
                const sheet = workbook.Sheets[sheetName];
                text += XLSX.utils.sheet_to_txt(sheet) + "\n";
            });
            return text;
        } catch {
            throw new Error("Excel parsing not available. Please install: npm install xlsx");
        }
    }

    if (file.name.endsWith(".pdf")) {
        // For PDF, we'll send directly to Gemini as base64 (Gemini can read PDFs)
        // Return special marker to indicate PDF should be sent as file
        return `__PDF_BASE64__${buffer.toString("base64")}`;
    }

    throw new Error(`Unsupported file type: ${file.name}`);
}

export async function POST(request: NextRequest) {
    try {
        const formData = await request.formData();
        const file = formData.get("file") as File | null;
        const subject = formData.get("subject") as string | null;
        const defaultDifficulty = formData.get("difficulty") as string | null;

        if (!file) {
            return NextResponse.json(
                { error: "No file provided" },
                { status: 400 }
            );
        }

        // Validate file type
        const validExtensions = [".txt", ".docx", ".xlsx", ".xls", ".pdf"];
        const hasValidExtension = validExtensions.some(ext =>
            file.name.toLowerCase().endsWith(ext)
        );

        if (!hasValidExtension) {
            return NextResponse.json(
                { error: "Invalid file type. Supported: Word, Excel, PDF, TXT" },
                { status: 400 }
            );
        }

        // Extract text from file
        console.log(`Extracting text from: ${file.name}`);
        const text = await extractTextFromFile(file);

        if (!text || text.trim().length < 50) {
            return NextResponse.json(
                { error: "Could not extract enough text from file" },
                { status: 400 }
            );
        }

        console.log(`Extracted ${text.length} characters`);

        // Split into chunks for long documents
        const CHUNK_SIZE = 10000; // 10K chars per chunk
        const chunks: string[] = [];

        if (text.startsWith("__PDF_BASE64__")) {
            // For PDF base64, send as single request (can't chunk binary)
            chunks.push(text);
        } else if (text.length > CHUNK_SIZE) {
            // Split text into chunks at sentence boundaries
            let remaining = text;
            while (remaining.length > 0) {
                if (remaining.length <= CHUNK_SIZE) {
                    chunks.push(remaining);
                    break;
                }
                // Find a good break point (sentence end, paragraph, or fallback)
                let breakPoint = remaining.lastIndexOf('\n\n', CHUNK_SIZE);
                if (breakPoint < CHUNK_SIZE / 2) {
                    breakPoint = remaining.lastIndexOf('. ', CHUNK_SIZE);
                }
                if (breakPoint < CHUNK_SIZE / 2) {
                    breakPoint = remaining.lastIndexOf('\n', CHUNK_SIZE);
                }
                if (breakPoint < CHUNK_SIZE / 2) {
                    breakPoint = CHUNK_SIZE;
                }

                chunks.push(remaining.slice(0, breakPoint + 1));
                remaining = remaining.slice(breakPoint + 1);
            }
            console.log(`Split into ${chunks.length} chunks`);
        } else {
            chunks.push(text);
        }

        // Process all chunks and merge results
        let allQuestions: ExtractedQuestion[] = [];

        for (let i = 0; i < chunks.length; i++) {
            console.log(`Processing chunk ${i + 1}/${chunks.length} (${chunks[i].length} chars)...`);

            try {
                const chunkQuestions = await extractWithV98(chunks[i], MODELS[0]);
                console.log(`Chunk ${i + 1}: extracted ${chunkQuestions.length} questions`);
                allQuestions = [...allQuestions, ...chunkQuestions];
            } catch (flashError) {
                console.log(`${MODELS[0]} failed on chunk ${i + 1}, trying ${MODELS[1]}...`);
                try {
                    const chunkQuestions = await extractWithV98(chunks[i], MODELS[1]);
                    console.log(`Chunk ${i + 1} (fallback): extracted ${chunkQuestions.length} questions`);
                    allQuestions = [...allQuestions, ...chunkQuestions];
                } catch (proError) {
                    console.error(`Both models failed on chunk ${i + 1}:`, proError);
                    // Continue with other chunks even if one fails
                }
            }

            // Small delay between chunks to avoid rate limiting
            if (i < chunks.length - 1) {
                await new Promise(r => setTimeout(r, 500));
            }
        }

        console.log(`Total extracted: ${allQuestions.length} questions`);

        // Deduplicate by content (in case of overlap)
        const seen = new Set<string>();
        const questions = allQuestions.filter(q => {
            const key = q.content.slice(0, 100); // First 100 chars as key
            if (seen.has(key)) return false;
            seen.add(key);
            return true;
        });

        // Apply default subject/difficulty if provided
        let finalQuestions = questions;
        if (subject || defaultDifficulty) {
            finalQuestions = questions.map(q => ({
                ...q,
                subject: subject || undefined,
                difficulty: defaultDifficulty ? parseInt(defaultDifficulty) : q.difficulty
            }));
        }

        return NextResponse.json({
            success: true,
            count: finalQuestions.length,
            questions: finalQuestions
        });

    } catch (error) {
        console.error("Extraction error:", error);
        return NextResponse.json(
            { error: "Failed to extract questions: " + (error as Error).message },
            { status: 500 }
        );
    }
}

import { NextRequest, NextResponse } from "next/server"
import { createClient } from "@/lib/supabase/server"

const MAX_FILE_SIZE = 2 * 1024 * 1024 // 2MB
const ALLOWED_TYPES = ["image/jpeg", "image/jpg", "image/png", "image/webp"]

export async function POST(request: NextRequest) {
    try {
        const supabase = await createClient()

        // Check authentication
        const { data: { user }, error: authError } = await supabase.auth.getUser()
        if (authError || !user) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
        }

        // Get form data
        const formData = await request.formData()
        const file = formData.get("file") as File

        if (!file) {
            return NextResponse.json({ error: "No file provided" }, { status: 400 })
        }

        // Validate file type
        if (!ALLOWED_TYPES.includes(file.type)) {
            return NextResponse.json({
                error: "Invalid file type. Only JPG, PNG, and WebP are allowed."
            }, { status: 400 })
        }

        // Validate file size
        if (file.size > MAX_FILE_SIZE) {
            return NextResponse.json({
                error: "File too large. Maximum size is 2MB."
            }, { status: 400 })
        }

        // Get current avatar to delete later
        const { data: profile } = await supabase
            .from("profiles")
            .select("avatar_url")
            .eq("id", user.id)
            .single()

        // Generate unique filename
        const fileExt = file.name.split(".").pop()
        const fileName = `${user.id}-${Date.now()}.${fileExt}`
        const filePath = fileName // No "avatars/" prefix - bucket already has it

        // Upload to Supabase Storage
        const { data: uploadData, error: uploadError } = await supabase.storage
            .from("avatars")
            .upload(filePath, file, {
                contentType: file.type,
                upsert: false
            })

        if (uploadError) {
            console.error("Upload error:", uploadError)
            return NextResponse.json({
                error: "Failed to upload file"
            }, { status: 500 })
        }

        // Get public URL
        const { data: { publicUrl } } = supabase.storage
            .from("avatars")
            .getPublicUrl(filePath)

        // Update profile with new avatar URL
        const { error: updateError } = await supabase
            .from("profiles")
            .update({ avatar_url: publicUrl })
            .eq("id", user.id)

        if (updateError) {
            console.error("Profile update error:", updateError)
            // Try to delete uploaded file if profile update fails
            await supabase.storage.from("avatars").remove([filePath])
            return NextResponse.json({
                error: "Failed to update profile"
            }, { status: 500 })
        }

        // Delete old avatar if exists
        if (profile?.avatar_url) {
            try {
                // Extract filename from URL (last segment after /)
                const urlParts = profile.avatar_url.split("/")
                const oldFileName = urlParts[urlParts.length - 1]
                await supabase.storage.from("avatars").remove([oldFileName])
            } catch (e) {
                console.error("Failed to delete old avatar:", e)
                // Non-critical, continue
            }
        }

        return NextResponse.json({
            url: publicUrl,
            message: "Avatar uploaded successfully"
        })

    } catch (error) {
        console.error("Avatar upload error:", error)
        return NextResponse.json({
            error: "Internal server error"
        }, { status: 500 })
    }
}

// DELETE endpoint to remove avatar
export async function DELETE(request: NextRequest) {
    try {
        const supabase = await createClient()

        const { data: { user }, error: authError } = await supabase.auth.getUser()
        if (authError || !user) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
        }

        // Get current avatar
        const { data: profile } = await supabase
            .from("profiles")
            .select("avatar_url")
            .eq("id", user.id)
            .single()

        if (profile?.avatar_url) {
            // Delete from storage - extract filename from URL
            const urlParts = profile.avatar_url.split("/")
            const fileName = urlParts[urlParts.length - 1]
            await supabase.storage.from("avatars").remove([fileName])

            // Update profile
            await supabase
                .from("profiles")
                .update({ avatar_url: null })
                .eq("id", user.id)
        }

        return NextResponse.json({ message: "Avatar removed successfully" })

    } catch (error) {
        console.error("Avatar delete error:", error)
        return NextResponse.json({
            error: "Internal server error"
        }, { status: 500 })
    }
}

"use client"

import { useState, useEffect, useCallback } from "react"
import { useRouter, useParams } from "next/navigation"
import { createClient } from "@/lib/supabase/client"
import { Button } from "@/components/ui/button"
import { Card, CardContent } from "@/components/ui/card"
import { MathRenderer } from "@/components/ui/math-renderer"
import {
    Clock,
    Send,
    Loader2,
    Swords,
    Target,
    Trophy,
    ArrowRight,
    AlertTriangle,
    ChevronLeft,
    ChevronRight,
    CheckCircle2,
    Circle,
    Flag
} from "lucide-react"
import { cn } from "@/lib/utils"

interface Question {
    id: string
    question_text: string
    options: string[]
    correct_answer: number
}

interface ArenaSession {
    id: string
    name: string
    subject: string
    duration: number
    total_questions: number
    start_time: string
    end_time: string
}

export default function ArenaBattlePage() {
    const router = useRouter()
    const params = useParams()
    const arenaId = params.id as string
    const supabase = createClient()

    const [arena, setArena] = useState<ArenaSession | null>(null)
    const [questions, setQuestions] = useState<Question[]>([])
    const [answers, setAnswers] = useState<Record<string, string>>({})
    const [currentIndex, setCurrentIndex] = useState(0)
    const [timeLeft, setTimeLeft] = useState(0)
    const [loading, setLoading] = useState(true)
    const [submitting, setSubmitting] = useState(false)
    const [startTime] = useState(Date.now())
    const [userId, setUserId] = useState<string | null>(null)
    const [alreadySubmitted, setAlreadySubmitted] = useState(false)

    useEffect(() => {
        fetchArenaAndQuestions()
    }, [arenaId])

    const fetchArenaAndQuestions = async () => {
        const { data: { user } } = await supabase.auth.getUser()
        if (!user) {
            router.push("/login")
            return
        }
        setUserId(user.id)

        // Check if already submitted
        const { data: existingResult } = await supabase
            .from("arena_results")
            .select("id")
            .eq("arena_id", arenaId)
            .eq("student_id", user.id)
            .maybeSingle()

        if (existingResult) {
            setAlreadySubmitted(true)
            setLoading(false)
            return
        }

        // Fetch arena info
        const { data: arenaData, error: arenaError } = await supabase
            .from("arena_sessions")
            .select("*")
            .eq("id", arenaId)
            .single()

        if (arenaError || !arenaData) {
            router.push("/arena")
            return
        }

        // Check if arena is active
        const now = new Date()
        const start = new Date(arenaData.start_time)
        const end = new Date(arenaData.end_time)

        if (now < start || now > end) {
            alert("Đợt thi này chưa mở hoặc đã kết thúc")
            router.push("/arena")
            return
        }

        setArena(arenaData)
        setTimeLeft(arenaData.duration * 60)

        // Get questions from the exam linked to this arena session
        if (!arenaData.exam_id) {
            console.error("Arena session has no exam_id")
            setLoading(false)
            return
        }

        const { data: questionsData, error: questionsError } = await supabase
            .from("questions")
            .select("id, question_text, options, correct_answer")
            .eq("exam_id", arenaData.exam_id)
            .order("order_index")

        if (questionsError) {
            console.error("Error fetching questions:", questionsError)
        }

        if (questionsData && questionsData.length > 0) {
            // Map to correct format
            const mappedQuestions = questionsData.map((q: any) => ({
                id: q.id,
                question_text: q.question_text,
                options: q.options || ['A', 'B', 'C', 'D'],
                correct_answer: ['A', 'B', 'C', 'D'][q.correct_answer] || 'A'
            }))
            setQuestions(mappedQuestions)
        }

        setLoading(false)
    }

    // Timer
    useEffect(() => {
        if (timeLeft <= 0 || loading || alreadySubmitted) return

        const timer = setInterval(() => {
            setTimeLeft(prev => {
                if (prev <= 1) {
                    clearInterval(timer)
                    handleSubmit(true)
                    return 0
                }
                return prev - 1
            })
        }, 1000)

        return () => clearInterval(timer)
    }, [timeLeft, loading, alreadySubmitted])

    const handleAnswer = (questionId: string, answer: string) => {
        setAnswers(prev => ({
            ...prev,
            [questionId]: answer
        }))
    }

    const handleSubmit = useCallback(async (autoSubmit = false) => {
        if (submitting || !arena || !userId) return

        if (!autoSubmit && !confirm("Bạn chắc chắn muốn nộp bài?")) return

        setSubmitting(true)

        try {
            // Calculate score
            let correct = 0
            const answerDetails = questions.map(q => {
                const userAnswer = answers[q.id] || null
                const correctAnswerLetter = ['A', 'B', 'C', 'D'][q.correct_answer] || 'A'
                const isCorrect = userAnswer === correctAnswerLetter
                if (isCorrect) correct++
                return {
                    question_id: q.id,
                    answer: userAnswer,
                    correct_answer: correctAnswerLetter,
                    is_correct: isCorrect
                }
            })

            const score = (correct / questions.length) * 10
            const timeSpent = Math.floor((Date.now() - startTime) / 1000)

            // Save result
            const { error } = await supabase
                .from("arena_results")
                .insert({
                    arena_id: arenaId,
                    student_id: userId,
                    score,
                    correct_count: correct,
                    total_questions: questions.length,
                    time_spent: timeSpent,
                    answers: answerDetails,
                    question_ids: questions.map(q => q.id)
                })

            if (error) throw error

            router.push(`/arena/${arenaId}/result`)
        } catch (err) {
            console.error("Submit error:", err)
            alert("Lỗi nộp bài: " + (err as Error).message)
            setSubmitting(false)
        }
    }, [arena, userId, questions, answers, startTime, arenaId, router, submitting, supabase])

    const formatTime = (seconds: number) => {
        const mins = Math.floor(seconds / 60)
        const secs = seconds % 60
        return `${mins.toString().padStart(2, "0")}:${secs.toString().padStart(2, "0")}`
    }

    const getDifficultyLabel = (difficulty: number) => {
        const labels = ["", "Dễ", "Trung bình", "Khó", "Rất khó"]
        return labels[difficulty] || ""
    }

    const getDifficultyColor = (difficulty: number) => {
        const colors = [
            "",
            "text-green-600 bg-green-50 border-green-200",
            "text-yellow-600 bg-yellow-50 border-yellow-200",
            "text-orange-600 bg-orange-50 border-orange-200",
            "text-red-600 bg-red-50 border-red-200"
        ]
        return colors[difficulty] || ""
    }

    const answeredCount = Object.keys(answers).length

    if (loading) {
        return (
            <div className="min-h-screen bg-gray-50 dark:bg-slate-950 flex items-center justify-center">
                <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
            </div>
        )
    }

    if (alreadySubmitted) {
        return (
            <div className="min-h-screen bg-gray-50 dark:bg-slate-950 flex items-center justify-center p-4">
                <Card className="w-full max-w-md bg-white dark:bg-slate-900 shadow-xl border-gray-200 dark:border-slate-800">
                    <CardContent className="p-8 text-center">
                        <div className="w-20 h-20 bg-yellow-50 dark:bg-yellow-900/30 rounded-full flex items-center justify-center mx-auto mb-6">
                            <Trophy className="w-10 h-10 text-yellow-600 dark:text-yellow-400" />
                        </div>
                        <h2 className="text-2xl font-bold text-gray-800 dark:text-white mb-2">Bạn đã hoàn thành bài thi!</h2>
                        <p className="text-gray-500 dark:text-gray-400 mb-8">Kết quả của bạn đã được ghi nhận.</p>
                        <Button
                            onClick={() => router.push(`/arena/${arenaId}/result`)}
                            className="w-full bg-blue-600 hover:bg-blue-700"
                        >
                            Xem kết quả chi tiết
                        </Button>
                    </CardContent>
                </Card>
            </div>
        )
    }

    if (!arena || questions.length === 0) {
        return (
            <div className="min-h-screen bg-gray-50 dark:bg-slate-950 flex items-center justify-center p-4">
                <Card className="w-full max-w-md bg-white dark:bg-slate-900 shadow-xl border-gray-200 dark:border-slate-800">
                    <CardContent className="p-8 text-center">
                        <div className="w-20 h-20 bg-red-50 dark:bg-red-900/30 rounded-full flex items-center justify-center mx-auto mb-6">
                            <AlertTriangle className="w-10 h-10 text-red-500" />
                        </div>
                        <h2 className="text-xl font-bold text-gray-800 dark:text-white mb-2">Không tìm thấy câu hỏi</h2>
                        <p className="text-gray-500 dark:text-gray-400 mb-8">Hệ thống chưa có đủ dữ liệu câu hỏi cho môn thi này.</p>
                        <Button
                            onClick={() => router.push("/arena")}
                            variant="outline"
                        >
                            Quay lại Đấu trường
                        </Button>
                    </CardContent>
                </Card>
            </div>
        )
    }

    const currentQuestion = questions[currentIndex]

    return (
        <div className="min-h-screen bg-gray-50 dark:bg-slate-950 flex flex-col">
            {/* Header */}
            <header className="bg-white dark:bg-slate-900 border-b border-gray-200 dark:border-slate-800 sticky top-0 z-50 h-16 shadow-sm">
                <div className="max-w-7xl mx-auto px-4 h-full flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-lg bg-orange-100 dark:bg-orange-900/30 flex items-center justify-center text-orange-600 dark:text-orange-400">
                            <Swords className="w-5 h-5" />
                        </div>
                        <div>
                            <span className="font-bold text-gray-800 dark:text-white block text-sm md:text-base">{arena.name}</span>
                            <span className="text-xs text-gray-500 dark:text-gray-400 md:hidden">
                                {answeredCount}/{questions.length} câu
                            </span>
                        </div>
                    </div>

                    <div className="flex items-center gap-4">
                        <div className="hidden md:flex items-center gap-3 px-4 py-2 bg-gray-50 dark:bg-slate-800 rounded-full border border-gray-100 dark:border-slate-700">
                            <Target className="w-4 h-4 text-gray-400" />
                            <span className="text-sm font-medium text-gray-600 dark:text-gray-300">
                                Đã làm: <span className="text-blue-600 dark:text-blue-400">{answeredCount}</span>/{questions.length}
                            </span>
                        </div>

                        <div className={cn(
                            "flex items-center gap-2 px-3 py-1.5 rounded-lg font-mono font-bold border",
                            timeLeft <= 60
                                ? "bg-red-50 dark:bg-red-900/20 border-red-100 dark:border-red-900 text-red-600 dark:text-red-400 animate-pulse"
                                : timeLeft <= 300
                                    ? "bg-yellow-50 dark:bg-yellow-900/20 border-yellow-100 dark:border-yellow-900 text-yellow-600 dark:text-yellow-400"
                                    : "bg-white dark:bg-slate-800 border-gray-200 dark:border-slate-700 text-blue-600 dark:text-blue-400"
                        )}>
                            <Clock className="w-4 h-4" />
                            {formatTime(timeLeft)}
                        </div>

                        <Button
                            onClick={() => handleSubmit(false)}
                            disabled={submitting}
                            size="sm"
                            className="bg-green-600 hover:bg-green-700 shadow-md shadow-green-200 hidden md:flex"
                        >
                            {submitting ? (
                                <Loader2 className="w-4 h-4 animate-spin" />
                            ) : (
                                <>
                                    <Send className="w-4 h-4 mr-2" />
                                    Nộp bài
                                </>
                            )}
                        </Button>
                    </div>
                </div>
            </header>

            {/* Main Content */}
            <div className="flex-1 max-w-6xl mx-auto w-full p-4 md:p-6 grid md:grid-cols-[1fr_240px] gap-6">
                {/* Question Area */}
                <div className="flex flex-col gap-6">
                    <Card className="border-gray-200 dark:border-slate-800 shadow-sm bg-white dark:bg-slate-900 overflow-hidden">
                        <CardContent className="p-0">
                            {/* Question Header */}
                            <div className="p-6 border-b border-gray-100 dark:border-slate-800 bg-gray-50/50 dark:bg-slate-800/50 flex items-center justify-between">
                                <div className="flex items-center gap-4">
                                    <div className="px-3 py-1 rounded-md bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 shadow-sm font-bold text-gray-700 dark:text-gray-300">
                                        Câu {currentIndex + 1}
                                    </div>
                                </div>
                            </div>

                            {/* Question Content */}
                            <div className="p-6 md:p-8">
                                <div className="text-gray-800 dark:text-white text-lg leading-relaxed mb-8">
                                    <MathRenderer content={currentQuestion.question_text} />
                                </div>

                                <div className="grid gap-3">
                                    {currentQuestion.options.map((option, idx) => {
                                        const optionLetter = ["A", "B", "C", "D"][idx]
                                        const isSelected = answers[currentQuestion.id] === optionLetter

                                        return (
                                            <button
                                                key={idx}
                                                onClick={() => handleAnswer(currentQuestion.id, optionLetter)}
                                                className={cn(
                                                    "w-full p-4 rounded-xl border-2 text-left transition-all relative group",
                                                    isSelected
                                                        ? "border-blue-500 bg-blue-50 dark:bg-blue-900/30 text-blue-900 dark:text-blue-100"
                                                        : "border-gray-200 dark:border-slate-700 hover:border-blue-300 dark:hover:border-blue-500 hover:bg-gray-50 dark:hover:bg-slate-800 text-gray-700 dark:text-gray-300"
                                                )}
                                            >
                                                <div className="flex items-start gap-4">
                                                    <div className={cn(
                                                        "flex-shrink-0 w-8 h-8 rounded-lg flex items-center justify-center font-bold transition-colors",
                                                        isSelected
                                                            ? "bg-blue-500 text-white"
                                                            : "bg-gray-100 dark:bg-slate-800 text-gray-500 dark:text-gray-400 group-hover:bg-blue-100 dark:group-hover:bg-blue-900/50 group-hover:text-blue-600 dark:group-hover:text-blue-400"
                                                    )}>
                                                        {optionLetter}
                                                    </div>
                                                    <div className="flex-1 pt-1">
                                                        <MathRenderer content={option.replace(/^[A-D]\.\s*/, "")} className="inline" />
                                                    </div>
                                                </div>
                                                {isSelected && (
                                                    <div className="absolute right-4 top-1/2 -translate-y-1/2 text-blue-500">
                                                        <CheckCircle2 className="w-5 h-5" />
                                                    </div>
                                                )}
                                            </button>
                                        )
                                    })}
                                </div>
                            </div>
                        </CardContent>
                    </Card>

                    {/* Navigation Buttons */}
                    <div className="flex items-center justify-between">
                        <Button
                            variant="outline"
                            onClick={() => setCurrentIndex(prev => prev - 1)}
                            disabled={currentIndex === 0}
                            className="bg-white dark:bg-slate-800 border-gray-200 dark:border-slate-700 text-gray-600 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-slate-700"
                        >
                            <ChevronLeft className="w-4 h-4 mr-2" />
                            Câu trước
                        </Button>

                        <div className="hidden md:block text-sm text-gray-400">
                            Câu {currentIndex + 1} / {questions.length}
                        </div>

                        {currentIndex < questions.length - 1 ? (
                            <Button
                                onClick={() => setCurrentIndex(prev => prev + 1)}
                                className="bg-blue-600 hover:bg-blue-700"
                            >
                                Câu sau
                                <ChevronRight className="w-4 h-4 ml-2" />
                            </Button>
                        ) : (
                            <Button
                                onClick={() => handleSubmit(false)}
                                disabled={submitting}
                                className="bg-green-600 hover:bg-green-700 shadow-lg shadow-green-200"
                            >
                                Nộp bài
                                <Send className="w-4 h-4 ml-2" />
                            </Button>
                        )}
                    </div>
                </div>

                {/* Question Navigator Sidebar */}
                <div className="hidden md:block">
                    <Card className="border-gray-200 dark:border-slate-800 shadow-sm bg-white dark:bg-slate-900 sticky top-20">
                        <CardContent className="p-4">
                            <h3 className="text-sm font-bold text-gray-700 dark:text-gray-300 uppercase tracking-wide mb-4 flex items-center gap-2">
                                <Flag className="w-4 h-4" />
                                Tổng quan
                            </h3>

                            <div className="grid grid-cols-5 gap-2 max-h-[calc(100vh-250px)] overflow-y-auto custom-scrollbar pr-1">
                                {questions.map((q, idx) => {
                                    const isAnswered = !!answers[q.id]
                                    const isCurrent = currentIndex === idx

                                    return (
                                        <button
                                            key={q.id}
                                            onClick={() => setCurrentIndex(idx)}
                                            className={cn(
                                                "aspect-square rounded-lg text-sm font-bold transition-all flex items-center justify-center border",
                                                isCurrent
                                                    ? "bg-blue-600 text-white border-blue-600 ring-2 ring-blue-200 dark:ring-blue-900"
                                                    : isAnswered
                                                        ? "bg-green-50 dark:bg-green-900/30 text-green-700 dark:text-green-400 border-green-200 dark:border-green-900"
                                                        : "bg-white dark:bg-slate-800 text-gray-400 dark:text-gray-500 border-gray-100 dark:border-slate-700 hover:border-blue-300"
                                            )}
                                        >
                                            {idx + 1}
                                        </button>
                                    )
                                })}
                            </div>

                            <div className="mt-6 pt-4 border-t border-gray-100 dark:border-slate-800 space-y-2">
                                <div className="flex items-center gap-2 text-xs text-gray-500 dark:text-gray-400">
                                    <div className="w-3 h-3 rounded bg-blue-600" />
                                    <span>Đang chọn</span>
                                </div>
                                <div className="flex items-center gap-2 text-xs text-gray-500 dark:text-gray-400">
                                    <div className="w-3 h-3 rounded bg-green-50 dark:bg-green-900/30 border border-green-200 dark:border-green-900" />
                                    <span>Đã trả lời</span>
                                </div>
                                <div className="flex items-center gap-2 text-xs text-gray-500 dark:text-gray-400">
                                    <div className="w-3 h-3 rounded bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700" />
                                    <span>Chưa trả lời</span>
                                </div>
                            </div>
                        </CardContent>
                    </Card>
                </div>
            </div>

            {/* Mobile Submit FAB */}
            <div className="md:hidden fixed bottom-6 right-6 z-50">
                <Button
                    onClick={() => handleSubmit(false)}
                    disabled={submitting}
                    size="icon"
                    className="h-14 w-14 rounded-full bg-green-600 hover:bg-green-700 shadow-lg shadow-green-300"
                >
                    <Send className="w-6 h-6 ml-1" />
                </Button>
            </div>
        </div>
    )
}

"use client"

import { useState, useEffect } from "react"
import { useRouter } from "next/navigation"
import Link from "next/link"
import { createClient } from "@/lib/supabase/client"
import { Button } from "@/components/ui/button"
import { cn } from "@/lib/utils"
import { NotificationBell } from "@/components/NotificationBell"
import { UserMenu } from "@/components/UserMenu"
import { BottomNav } from "@/components/BottomNav"

interface ArenaSession {
    id: string
    name: string
    description: string | null
    subject: string
    start_time: string
    end_time: string
    duration: number
    total_questions: number
    status: string
}

interface ArenaResult {
    arena_id: string
    score: number
    rank: number | null
    student_id: string
    profiles?: {
        full_name: string | null
    }
}

const SUBJECT_COLORS: Record<string, string> = {
    physics: "bg-blue-600",
    chemistry: "bg-green-600",
    math: "bg-purple-600",
    biology: "bg-yellow-600",
}

export default function ArenaPage() {
    const router = useRouter()
    const supabase = createClient()

    const [sessions, setSessions] = useState<ArenaSession[]>([])
    const [myResults, setMyResults] = useState<ArenaResult[]>([])
    const [topPlayers, setTopPlayers] = useState<ArenaResult[]>([])
    const [loading, setLoading] = useState(true)
    const [user, setUser] = useState<{ id: string; full_name?: string } | null>(null)
    const [selectedTab, setSelectedTab] = useState("all")
    const [searchQuery, setSearchQuery] = useState("")

    useEffect(() => {
        fetchData()
    }, [])

    const fetchData = async () => {
        const { data: { user: authUser } } = await supabase.auth.getUser()
        if (!authUser) {
            router.push("/login")
            return
        }

        const { data: profile } = await supabase.from("profiles").select("full_name").eq("id", authUser.id).single()
        setUser({ id: authUser.id, full_name: profile?.full_name })

        const { data: sessionsData } = await supabase
            .from("arena_sessions")
            .select("*")
            .order("start_time", { ascending: false })
        if (sessionsData) setSessions(sessionsData)

        const { data: resultsData } = await supabase
            .from("arena_results")
            .select("arena_id, score, rank")
            .eq("student_id", authUser.id)
        if (resultsData) setMyResults(resultsData)

        // Get top players
        const { data: topData } = await supabase
            .from("arena_results")
            .select("*, profiles!student_id(full_name)")
            .order("score", { ascending: false })
            .limit(10)
        if (topData) setTopPlayers(topData)

        setLoading(false)
    }

    const handleLogout = async () => {
        await supabase.auth.signOut()
        router.push("/login")
    }

    const getMyResult = (arenaId: string) => myResults.find(r => r.arena_id === arenaId)

    const getStatusInfo = (session: ArenaSession) => {
        const now = new Date()
        const start = new Date(session.start_time)
        const end = new Date(session.end_time)
        if (now < start) return { status: "upcoming", label: "Sắp diễn ra", color: "bg-yellow-500" }
        if (now >= start && now <= end) return { status: "active", label: "Đang mở", color: "bg-green-500" }
        return { status: "ended", label: "Đang đóng", color: "bg-gray-500" }
    }

    const filteredSessions = sessions
        .filter(s => {
            if (selectedTab === "all") return true
            if (selectedTab === "active") return getStatusInfo(s).status === "active"
            if (selectedTab === "upcoming") return getStatusInfo(s).status === "upcoming"
            if (selectedTab === "ended") return getStatusInfo(s).status === "ended"
            return true
        })
        .filter(s => s.name.toLowerCase().includes(searchQuery.toLowerCase()))

    if (loading) {
        return (
            <div className="min-h-screen bg-gray-100 dark:bg-slate-900 flex items-center justify-center">
                <div className="w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full animate-spin" />
            </div>
        )
    }

    return (
        <div className="min-h-screen bg-gray-100 dark:bg-slate-950 flex flex-col">
            {/* Header */}
            <nav className="fixed top-0 w-full z-50 bg-white/95 dark:bg-slate-900/95 backdrop-blur-md border-b border-gray-200 dark:border-slate-800 h-16 flex items-center justify-between px-4 lg:px-8">
                <div className="flex items-center gap-4">
                    <Link href="/student/dashboard" className="flex items-center gap-2">
                        <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white font-bold text-xl">E</div>
                        <span className="font-bold text-xl text-blue-600 hidden md:block tracking-tight">ExamHub</span>
                    </Link>
                    <div className="hidden sm:block ml-2">
                        <div className="relative">
                            <input
                                type="text"
                                placeholder="Tìm kiếm..."
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}

                                className="pl-9 pr-4 py-2 bg-gray-100 dark:bg-slate-700 border-none rounded-full text-sm w-64 focus:ring-2 focus:ring-blue-600 dark:text-white dark:placeholder-gray-400"
                            />
                            <span className="absolute left-3 top-2 text-gray-400">🔍</span>
                        </div>
                    </div>
                </div>
                <div className="hidden md:flex items-center gap-6 text-sm font-medium text-gray-600 dark:text-gray-300">
                    <Link href="/student/dashboard" className="hover:text-blue-600 dark:hover:text-blue-400 flex items-center gap-1">🏠 Trang chủ</Link>
                    <Link href="/resources" className="hover:text-blue-600 dark:hover:text-blue-400 flex items-center gap-1">📚 Tài liệu</Link>
                </div>
                <div className="flex items-center gap-3">
                    <NotificationBell />
                    <UserMenu userName={user?.full_name || ""} onLogout={handleLogout} role="student" />
                </div>
            </nav>

            {/* Main Content */}
            <div className="pt-20 pb-12 px-4 lg:px-8 max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8 flex-grow w-full">
                {/* Left - Arena List */}
                <div className="lg:col-span-8">
                    {/* Breadcrumb */}
                    <div className="flex items-center gap-2 text-sm text-gray-500 dark:text-gray-400 mb-6">
                        <Link href="/student/dashboard" className="hover:text-blue-600 dark:hover:text-blue-400">🏠</Link>
                        <span>›</span>
                        <span className="font-medium text-gray-800 dark:text-gray-200">Đấu trường lý thuyết</span>
                    </div>

                    {/* Title */}
                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
                        <h1 className="text-2xl font-bold text-blue-600 flex items-center gap-2 uppercase tracking-wide">
                            ĐẤU TRƯỜNG LÝ THUYẾT 🎮
                        </h1>
                    </div>

                    {/* Status Tabs */}
                    <div className="flex items-center gap-6 border-b border-gray-200 dark:border-slate-800 mb-6 overflow-x-auto">
                        {[
                            { key: "all", label: "Tất cả" },
                            { key: "vip", label: "Vip" },
                            { key: "active", label: "Đang mở" },
                            { key: "upcoming", label: "Sắp diễn ra" },
                            { key: "ended", label: "Đã đóng" }
                        ].map(tab => (
                            <button
                                key={tab.key}
                                onClick={() => setSelectedTab(tab.key)}
                                className={cn(
                                    "pb-3 border-b-2 font-medium text-sm whitespace-nowrap transition-colors",
                                    selectedTab === tab.key
                                        ? "border-blue-600 text-blue-600"
                                        : "border-transparent text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-300"
                                )}
                            >
                                {tab.label}
                            </button>
                        ))}
                    </div>

                    {/* Search */}
                    <div className="relative mb-8">
                        <input
                            type="text"
                            placeholder="Tìm kiếm..."
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="w-full pl-10 pr-4 py-3 bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-800 rounded-xl shadow-sm focus:ring-2 focus:ring-blue-600 focus:border-transparent outline-none dark:text-white dark:placeholder-gray-400"
                        />
                        <span className="absolute left-3 top-3.5 text-gray-400">🔍</span>
                    </div>

                    {/* Arena List */}
                    <div className="space-y-4">
                        {filteredSessions.length === 0 ? (
                            <div className="bg-white dark:bg-slate-900 rounded-xl shadow-sm p-12 text-center border border-gray-100 dark:border-slate-800">
                                <span className="text-5xl mb-4 block">🎮</span>
                                <p className="text-gray-500 dark:text-gray-400">Chưa có đợt thi nào</p>
                            </div>
                        ) : (
                            filteredSessions.map(session => {
                                const statusInfo = getStatusInfo(session)
                                const myResult = getMyResult(session.id)

                                return (
                                    <div
                                        key={session.id}
                                        className="bg-white dark:bg-slate-900 rounded-xl shadow-sm hover:shadow-md transition-shadow border border-gray-100 dark:border-slate-800 overflow-hidden flex flex-col sm:flex-row"
                                    >
                                        {/* Left Icon Area */}
                                        <div className={cn(
                                            "sm:w-48 bg-gray-500 flex items-center justify-center p-6 relative flex-col text-center",
                                            session.subject === "physics" && "bg-blue-600",
                                            session.subject === "chemistry" && "bg-green-600",
                                            session.subject === "math" && "bg-purple-600"
                                        )}>
                                            <div className="text-6xl font-black text-white/30 select-none">
                                                {session.subject === "physics" ? "⚛️" : session.subject === "chemistry" ? "🧪" : "📐"}
                                            </div>
                                            <div className="absolute bottom-4 font-bold text-white tracking-widest text-sm uppercase">
                                                {session.subject === "physics" ? "VẬT LÝ" : session.subject === "chemistry" ? "HÓA HỌC" : "TOÁN"}
                                            </div>
                                            {statusInfo.status === "active" && (
                                                <div className="absolute top-2 left-2 bg-red-500 text-white text-[10px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider">
                                                    Hot
                                                </div>
                                            )}
                                        </div>

                                        {/* Content */}
                                        <div className="p-5 flex-1 flex flex-col justify-between">
                                            <div>
                                                <h3 className="text-lg font-bold text-gray-800 dark:text-white mb-2 line-clamp-2">{session.name}</h3>
                                                <div className="flex flex-wrap gap-2 mb-4">
                                                    <span className={cn(
                                                        "px-2.5 py-0.5 rounded text-xs font-medium text-white flex items-center gap-1",
