"use client";

import { useState, useEffect, useMemo } from "react";
import Link from "next/link";
import { createClient } from "@/lib/supabase/client";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
    Video,
    Calendar,
    Clock,
    BookOpen,
    ArrowLeft,
    Plus,
    Edit,
    Trash2,
    ExternalLink,
    GraduationCap,
    User,
    X,
    Save,
    Youtube,
    Settings,
    Play,
    MessageCircle
} from "lucide-react";
import { cn } from "@/lib/utils";
import { ThemeToggle } from "@/components/ui/ThemeToggle";

interface LiveConfig {
    id: string;
    youtube_video_id: string | null;
    youtube_chat_enabled: boolean;
    is_live: boolean;
    title: string | null;
}

interface ScheduleItem {
    id: string;
    day: string;
    time: string;
    topic: string;
    host: string;
    sort_order: number;
}

export default function LiveRoomPage() {
    const [user, setUser] = useState<{ name: string; email: string; role?: string } | null>(null);
    const [schedule, setSchedule] = useState<ScheduleItem[]>([]);
    const [liveConfig, setLiveConfig] = useState<LiveConfig | null>(null);
    const [showEditor, setShowEditor] = useState(false);
    const [showLiveSettings, setShowLiveSettings] = useState(false);
    const [editItem, setEditItem] = useState<ScheduleItem | null>(null);
    const [formDay, setFormDay] = useState("");
    const [formTime, setFormTime] = useState("");
    const [formTopic, setFormTopic] = useState("");
    const [formHost, setFormHost] = useState("");

    // Live settings form
    const [youtubeUrl, setYoutubeUrl] = useState("");
    const [liveTitle, setLiveTitle] = useState("");
    const [chatEnabled, setChatEnabled] = useState(true);
    const [isLive, setIsLive] = useState(false);

    const supabase = useMemo(() => {
        if (typeof window === 'undefined') return null;
        return createClient();
    }, []);

    useEffect(() => {
        if (supabase) {
            checkAuth();
            fetchSchedule();
            fetchLiveConfig();
        }
    }, [supabase]);

    const checkAuth = async () => {
        if (!supabase) return;
        const { data: { session } } = await supabase.auth.getSession();
        if (session) {
            const { data: profile } = await supabase
                .from("profiles")
                .select("full_name, email, role")
                .eq("id", session.user.id)
                .single();
            setUser({
                name: profile?.full_name || session.user.email?.split("@")[0] || "Học sinh",
                email: session.user.email || "",
                role: profile?.role,
            });
        }
    };

    const fetchSchedule = async () => {
        if (!supabase) return;
        const { data } = await supabase
            .from("live_schedule")
            .select("*")
            .eq("is_active", true)
            .order("sort_order");
        if (data) setSchedule(data);
    };

    const fetchLiveConfig = async () => {
        if (!supabase) return;
        const { data } = await supabase
            .from("live_config")
            .select("*")
            .single();
        if (data) {
            setLiveConfig(data);
            setYoutubeUrl(data.youtube_video_id || "");
            setLiveTitle(data.title || "");
            setChatEnabled(data.youtube_chat_enabled);
            setIsLive(data.is_live);
        }
    };

    // Extract YouTube video ID from various URL formats
    const extractYoutubeId = (url: string): string | null => {
        if (!url) return null;

        // Already just an ID
        if (/^[a-zA-Z0-9_-]{11}$/.test(url)) return url;

        // Various YouTube URL formats
        const patterns = [
            /(?:youtube\.com\/watch\?v=|youtu\.be\/|youtube\.com\/live\/)([a-zA-Z0-9_-]{11})/,
            /youtube\.com\/embed\/([a-zA-Z0-9_-]{11})/,
        ];

        for (const pattern of patterns) {
            const match = url.match(pattern);
            if (match) return match[1];
        }

        return null;
    };

    const saveLiveSettings = async () => {
        if (!supabase) return;

        const videoId = extractYoutubeId(youtubeUrl);

        const configData = {
            youtube_video_id: videoId,
            youtube_chat_enabled: chatEnabled,
            is_live: isLive,
            title: liveTitle,
        };

        if (liveConfig) {
            await supabase
                .from("live_config")
                .update(configData)
                .eq("id", liveConfig.id);
        } else {
            await supabase
                .from("live_config")
                .insert(configData);
        }

        fetchLiveConfig();
        setShowLiveSettings(false);
    };

    const openEditor = (item?: ScheduleItem) => {
        if (item) {
            setEditItem(item);
            setFormDay(item.day);
            setFormTime(item.time);
            setFormTopic(item.topic);
            setFormHost(item.host || "");
        } else {
            setEditItem(null);
            setFormDay("");
            setFormTime("");
            setFormTopic("");
            setFormHost("");
        }
        setShowEditor(true);
    };

    const handleSave = async () => {
        if (!supabase) return;
        if (!formDay || !formTime || !formTopic) return;

        if (editItem) {
            await supabase
                .from("live_schedule")
                .update({ day: formDay, time: formTime, topic: formTopic, host: formHost })
                .eq("id", editItem.id);
        } else {
            await supabase
                .from("live_schedule")
                .insert({ day: formDay, time: formTime, topic: formTopic, host: formHost, sort_order: schedule.length + 1 });
        }

        setShowEditor(false);
        fetchSchedule();
    };

    const handleDelete = async (id: string) => {
        if (!supabase) return;
        if (confirm("Xóa lịch này?")) {
            await supabase.from("live_schedule").delete().eq("id", id);
            fetchSchedule();
        }
    };

    const ADMIN_EMAIL = "ptan12209@gmail.com";
    const canEdit = user?.email === ADMIN_EMAIL || user?.role === "teacher";

    return (
        <div className="min-h-screen bg-gradient-to-br from-slate-900 via-purple-900/20 to-slate-900">
            {/* Navigation */}
            <nav className="border-b border-white/10 bg-black/30 backdrop-blur-xl sticky top-0 z-50">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                    <div className="flex justify-between h-16 items-center">
                        <div className="flex items-center gap-4">
                            <Link href="/">
                                <div className="flex items-center gap-3">
                                    <div className="w-10 h-10 bg-gradient-to-br from-red-600 to-pink-600 rounded-xl flex items-center justify-center shadow-lg shadow-red-500/20">
                                        <Youtube className="w-5 h-5 text-white" />
                                    </div>
                                    <span className="text-xl font-bold text-white">Live Class</span>
                                </div>
                            </Link>
                        </div>
                        <div className="flex items-center gap-3">
                            <ThemeToggle />
                            {canEdit && (
                                <Button
                                    onClick={() => setShowLiveSettings(true)}
                                    variant="outline"
                                    className="border-white/20 text-white hover:bg-white/10"
                                >
                                    <Settings className="w-4 h-4 mr-2" />
                                    Cài đặt Live
                                </Button>
                            )}
                            {user ? (
                                <div className="flex items-center gap-2 text-sm text-gray-300">
                                    <User className="w-4 h-4" />
                                    <span>{user.name}</span>
                                </div>
                            ) : (
                                <Link href="/login">
                                    <Button className="bg-red-600 hover:bg-red-700 text-white">
                                        Đăng nhập
                                    </Button>
                                </Link>
                            )}
                        </div>
                    </div>
                </div>
            </nav>

            <div className="max-w-7xl mx-auto px-4 py-8">
                <Link href="/student/dashboard" className="inline-flex items-center gap-2 text-gray-400 hover:text-white mb-6 transition-colors">
                    <ArrowLeft className="w-4 h-4" />
                    Quay lại Dashboard
                </Link>

                {/* Live Status Badge */}
                {liveConfig?.is_live && (
                    <div className="flex items-center gap-2 mb-6">
                        <span className="relative flex h-3 w-3">
                            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
                            <span className="relative inline-flex rounded-full h-3 w-3 bg-red-500"></span>
                        </span>
                        <span className="text-red-400 font-semibold uppercase tracking-wider text-sm">Đang phát trực tiếp</span>
                    </div>
                )}

                {/* Main Content */}
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    {/* Video Player - Takes 2 columns */}
                    <div className="lg:col-span-2 space-y-4">
                        {liveConfig?.youtube_video_id ? (
                            <>
                                {/* Video Title */}
                                <h1 className="text-2xl font-bold text-white">
                                    {liveConfig.title || "Buổi Live Chữa Đề"}
                                </h1>

                                {/* YouTube Embed */}
                                <div className="relative aspect-video bg-black rounded-2xl overflow-hidden shadow-2xl shadow-purple-500/10 ring-1 ring-white/10">
                                    <iframe
                                        src={`https://www.youtube.com/embed/${liveConfig.youtube_video_id}?autoplay=1&rel=0`}
                                        title="YouTube Live"
                                        allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                                        allowFullScreen
                                        className="absolute inset-0 w-full h-full"
                                    />
                                </div>

                                {/* Quick Actions */}
                                <div className="flex flex-wrap gap-3">
                                    <a
                                        href={`https://youtube.com/watch?v=${liveConfig.youtube_video_id}`}
                                        target="_blank"
                                        rel="noopener noreferrer"
                                        className="flex items-center gap-2 px-4 py-2 bg-red-600 hover:bg-red-700 text-white rounded-lg transition-colors"
                                    >
                                        <Youtube className="w-4 h-4" />
                                        Xem trên YouTube
                                    </a>
                                </div>
                            </>
                        ) : (
                            /* No Live Stream */
                            <Card className="border-white/10 bg-white/5 backdrop-blur-sm">
                                <CardContent className="py-20 text-center">
                                    <div className="w-20 h-20 bg-gradient-to-br from-gray-700 to-gray-800 rounded-2xl mx-auto mb-6 flex items-center justify-center">
                                        <Video className="w-10 h-10 text-gray-400" />
                                    </div>
                                    <h2 className="text-2xl font-bold text-white mb-3">
                                        Chưa có buổi Live
                                    </h2>
                                    <p className="text-gray-400 mb-6 max-w-md mx-auto">
                                        Hiện tại chưa có buổi học trực tuyến nào. Hãy xem lịch học bên cạnh để biết thời gian sắp tới.
                                    </p>
                                    {canEdit && (
                                        <Button
                                            onClick={() => setShowLiveSettings(true)}
                                            className="bg-red-600 hover:bg-red-700"
                                        >
                                            <Settings className="w-4 h-4 mr-2" />
                                            Thiết lập Live Stream
                                        </Button>
                                    )}
                                </CardContent>
                            </Card>
                        )}
                    </div>

                    {/* Sidebar - Chat or Schedule */}
                    <div className="space-y-6">
                        {/* YouTube Chat Embed */}
                        {liveConfig?.youtube_video_id && liveConfig?.youtube_chat_enabled && (
                            <Card className="border-white/10 bg-white/5 backdrop-blur-sm overflow-hidden">
                                <CardHeader className="border-b border-white/10 py-3">
                                    <CardTitle className="text-white flex items-center gap-2 text-base">
                                        <MessageCircle className="w-4 h-4 text-red-400" />
                                        Chat Trực Tiếp
                                    </CardTitle>
                                </CardHeader>
                                <div className="aspect-[9/16] max-h-[500px]">
                                    <iframe
                                        src={`https://www.youtube.com/live_chat?v=${liveConfig.youtube_video_id}&embed_domain=${typeof window !== 'undefined' ? window.location.hostname : 'localhost'}`}
                                        className="w-full h-full"
                                    />
                                </div>
                            </Card>
                        )}

                        {/* Schedule */}
                        <Card className="border-white/10 bg-white/5 backdrop-blur-sm">
                            <CardHeader className="border-b border-white/10 flex flex-row items-center justify-between py-3">
                                <CardTitle className="text-white flex items-center gap-2 text-base">
                                    <Calendar className="w-4 h-4 text-blue-400" />
                                    Lịch Live Tuần Này
                                </CardTitle>
                                {canEdit && (
                                    <Button
                                        onClick={() => openEditor()}
                                        size="sm"
                                        className="bg-green-600 hover:bg-green-700 text-white h-8"
                                    >
                                        <Plus className="w-3 h-3 mr-1" />
                                        Thêm
                                    </Button>
                                )}
                            </CardHeader>
                            <CardContent className="p-0">
                                {schedule.length === 0 ? (
                                    <div className="py-8 text-center">
                                        <Calendar className="w-8 h-8 text-gray-600 mx-auto mb-2" />
                                        <p className="text-gray-400 text-sm">Chưa có lịch</p>
                                    </div>
                                ) : (
                                    <div className="divide-y divide-white/5">
                                        {schedule.map((item) => (
                                            <div
                                                key={item.id}
                                                className="p-4 hover:bg-white/5 transition-colors group"
                                            >
                                                <div className="flex items-start justify-between gap-2">
                                                    <div>
                                                        <p className="text-white font-medium text-sm">{item.topic}</p>
                                                        <p className="text-gray-400 text-xs mt-1 flex items-center gap-2">
                                                            <span className="flex items-center gap-1">
                                                                <Calendar className="w-3 h-3" />
                                                                {item.day}
                                                            </span>
                                                            <span className="flex items-center gap-1">
                                                                <Clock className="w-3 h-3" />
                                                                {item.time}
                                                            </span>
                                                        </p>
                                                        {item.host && (
                                                            <p className="text-blue-400 text-xs mt-1">{item.host}</p>
                                                        )}
                                                    </div>
                                                    {canEdit && (
                                                        <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                                            <button
                                                                onClick={() => openEditor(item)}
                                                                className="p-1.5 text-gray-400 hover:text-blue-400 transition-colors"
                                                            >
                                                                <Edit className="w-3.5 h-3.5" />
                                                            </button>
                                                            <button
                                                                onClick={() => handleDelete(item.id)}
                                                                className="p-1.5 text-gray-400 hover:text-red-400 transition-colors"
                                                            >
                                                                <Trash2 className="w-3.5 h-3.5" />
                                                            </button>
                                                        </div>
                                                    )}
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                )}
                            </CardContent>
                        </Card>

                        {/* Quick Links */}
                        <div className="grid grid-cols-2 gap-3">
                            <Link href="/resources">
                                <Card className="border-white/10 bg-white/5 hover:bg-white/10 transition-colors cursor-pointer h-full">
                                    <CardContent className="p-4 text-center">
                                        <BookOpen className="w-6 h-6 text-blue-400 mx-auto mb-2" />
                                        <p className="text-white text-sm font-medium">Tài liệu</p>
                                    </CardContent>
                                </Card>
                            </Link>
                            <Link href="/student/exams">
                                <Card className="border-white/10 bg-white/5 hover:bg-white/10 transition-colors cursor-pointer h-full">
                                    <CardContent className="p-4 text-center">
                                        <GraduationCap className="w-6 h-6 text-green-400 mx-auto mb-2" />
                                        <p className="text-white text-sm font-medium">Luyện đề</p>
                                    </CardContent>
                                </Card>
                            </Link>
                        </div>
                    </div>
                </div>
            </div>

            {/* Live Settings Modal */}
            {showLiveSettings && (
                <div className="fixed inset-0 bg-black/70 backdrop-blur-sm flex items-center justify-center z-50 p-4">
                    <Card className="w-full max-w-lg border-white/10 bg-slate-900 shadow-2xl">
                        <CardHeader className="flex flex-row items-center justify-between border-b border-white/10 pb-4">
                            <CardTitle className="text-white text-lg flex items-center gap-2">
                                <Youtube className="w-5 h-5 text-red-500" />
                                Cài đặt YouTube Live
                            </CardTitle>
                            <Button
                                variant="ghost"
                                size="icon"
                                onClick={() => setShowLiveSettings(false)}
                                className="text-gray-400 hover:text-white hover:bg-white/10"
                            >
                                <X className="w-5 h-5" />
                            </Button>
                        </CardHeader>
                        <CardContent className="pt-5 space-y-5">
                            {/* Instructions */}
                            <div className="bg-blue-500/10 border border-blue-500/30 rounded-lg p-4">
                                <h4 className="text-blue-400 font-medium mb-2 text-sm">📌 Hướng dẫn nhanh:</h4>
                                <ol className="text-gray-300 text-sm space-y-1 list-decimal list-inside">
                                    <li>Vào YouTube Studio → Tạo Live Stream</li>
                                    <li>Copy link video (VD: youtube.com/watch?v=ABC123)</li>
                                    <li>Dán vào ô bên dưới</li>
                                    <li>Bật "Đang phát trực tiếp" khi bắt đầu</li>
                                </ol>
                            </div>

                            <div className="space-y-2">
                                <Label className="text-gray-300 font-medium">Tiêu đề buổi Live</Label>
                                <Input
                                    value={liveTitle}
                                    onChange={(e) => setLiveTitle(e.target.value)}
                                    placeholder="VD: Chữa đề Toán THPT 2026 - Buổi 5"
                                    className="bg-white/5 border-white/10 text-white placeholder-gray-500"
                                />
                            </div>

                            <div className="space-y-2">
                                <Label className="text-gray-300 font-medium">Link hoặc ID Video YouTube</Label>
                                <Input
                                    value={youtubeUrl}
                                    onChange={(e) => setYoutubeUrl(e.target.value)}
                                    placeholder="VD: https://youtube.com/watch?v=dQw4w9WgXcQ"
                                    className="bg-white/5 border-white/10 text-white placeholder-gray-500"
                                />
                                <p className="text-gray-500 text-xs">
                                    Hỗ trợ: youtube.com/watch?v=..., youtu.be/..., youtube.com/live/...
                                </p>
                            </div>

                            <div className="flex items-center justify-between py-2">
                                <div>
                                    <Label className="text-gray-300 font-medium">Hiển thị Chat</Label>
                                    <p className="text-gray-500 text-xs">Cho phép học sinh chat trực tiếp</p>
                                </div>
                                <button
                                    onClick={() => setChatEnabled(!chatEnabled)}
                                    className={cn(
                                        "w-12 h-6 rounded-full transition-colors relative",
                                        chatEnabled ? "bg-green-600" : "bg-gray-600"
                                    )}
                                >
                                    <span className={cn(
                                        "absolute top-1 w-4 h-4 bg-white rounded-full transition-all",
                                        chatEnabled ? "right-1" : "left-1"
                                    )} />
                                </button>
                            </div>

                            <div className="flex items-center justify-between py-2 border-t border-white/10 pt-4">
                                <div>
                                    <Label className="text-gray-300 font-medium flex items-center gap-2">
                                        <span className="relative flex h-2 w-2">
                                            <span className={cn(
                                                "absolute inline-flex h-full w-full rounded-full opacity-75",
                                                isLive ? "animate-ping bg-red-400" : "bg-gray-400"
                                            )}></span>
                                            <span className={cn(
                                                "relative inline-flex rounded-full h-2 w-2",
                                                isLive ? "bg-red-500" : "bg-gray-500"
                                            )}></span>
                                        </span>
                                        Đang phát trực tiếp
                                    </Label>
                                    <p className="text-gray-500 text-xs">Bật khi bạn bắt đầu stream</p>
                                </div>
                                <button
                                    onClick={() => setIsLive(!isLive)}
                                    className={cn(
                                        "w-12 h-6 rounded-full transition-colors relative",
                                        isLive ? "bg-red-600" : "bg-gray-600"
                                    )}
                                >
                                    <span className={cn(
                                        "absolute top-1 w-4 h-4 bg-white rounded-full transition-all",
                                        isLive ? "right-1" : "left-1"
                                    )} />
                                </button>
                            </div>

                            <div className="flex gap-3 pt-4">
                                <Button
                                    variant="outline"
                                    onClick={() => setShowLiveSettings(false)}
                                    className="flex-1 border-white/20 text-gray-300 hover:bg-white/10"
                                >
                                    Hủy
                                </Button>
                                <Button
                                    onClick={saveLiveSettings}
                                    className="flex-1 bg-red-600 hover:bg-red-700 text-white"
                                >
                                    <Save className="w-4 h-4 mr-2" />
                                    Lưu cài đặt
                                </Button>
                            </div>
                        </CardContent>
                    </Card>
                </div>
            )}

            {/* Schedule Editor Modal */}
            {showEditor && (
                <div className="fixed inset-0 bg-black/70 backdrop-blur-sm flex items-center justify-center z-50 p-4">
                    <Card className="w-full max-w-md border-white/10 bg-slate-900 shadow-2xl">
                        <CardHeader className="flex flex-row items-center justify-between border-b border-white/10 pb-4">
                            <CardTitle className="text-white text-lg">
                                {editItem ? "Sửa lịch" : "Thêm lịch mới"}
                            </CardTitle>
                            <Button
                                variant="ghost"
                                size="icon"
                                onClick={() => setShowEditor(false)}
                                className="text-gray-400 hover:text-white hover:bg-white/10"
                            >
                                <X className="w-5 h-5" />
                            </Button>
                        </CardHeader>
                        <CardContent className="pt-5 space-y-4">
                            <div className="space-y-2">
                                <Label className="text-gray-300 font-medium">Ngày</Label>
                                <Input
                                    value={formDay}
                                    onChange={(e) => setFormDay(e.target.value)}
                                    placeholder="VD: Thứ 7"
                                    className="bg-white/5 border-white/10 text-white"
                                />
                            </div>
                            <div className="space-y-2">
                                <Label className="text-gray-300 font-medium">Giờ</Label>
                                <Input
                                    value={formTime}
                                    onChange={(e) => setFormTime(e.target.value)}
                                    placeholder="VD: 20:00 - 22:00"
                                    className="bg-white/5 border-white/10 text-white"
                                />
                            </div>
                            <div className="space-y-2">
                                <Label className="text-gray-300 font-medium">Chủ đề</Label>
                                <Input
                                    value={formTopic}
                                    onChange={(e) => setFormTopic(e.target.value)}
                                    placeholder="VD: Chữa đề Toán THPT 2026"
                                    className="bg-white/5 border-white/10 text-white"
                                />
                            </div>
                            <div className="space-y-2">
                                <Label className="text-gray-300 font-medium">Người dạy</Label>
                                <Input
                                    value={formHost}
                                    onChange={(e) => setFormHost(e.target.value)}
                                    placeholder="VD: Thầy Ái"
                                    className="bg-white/5 border-white/10 text-white"
                                />
                            </div>

                            <div className="flex gap-3 pt-4">
                                <Button
                                    variant="outline"
                                    onClick={() => setShowEditor(false)}
                                    className="flex-1 border-white/20 text-gray-300 hover:bg-white/10"
                                >
                                    Hủy
                                </Button>
                                <Button
                                    onClick={handleSave}
                                    disabled={!formDay || !formTime || !formTopic}
                                    className="flex-1 bg-blue-600 hover:bg-blue-700 text-white"
                                >
                                    <Save className="w-4 h-4 mr-2" />
                                    Lưu
                                </Button>
                            </div>
                        </CardContent>
                    </Card>
                </div>
            )}
        </div>
    );
}

"use client"

import { useEffect, useState } from "react"
import { useRouter, useParams } from "next/navigation"
import { createClient } from "@/lib/supabase/client"
import { ArrowLeft, Loader2, User, Mail, Award, BookOpen, Calendar } from "lucide-react"
import Link from "next/link"
import { Button } from "@/components/ui/button"

interface PublicProfile {
    id: string
    full_name: string
    avatar_url?: string | null
    nickname?: string | null
    bio?: string | null
    role: "student" | "teacher"
    class?: string | null
    created_at: string
}

export default function PublicProfilePage() {
    const params = useParams()
    const router = useRouter()
    const supabase = createClient()
    const userId = params.userId as string

    const [loading, setLoading] = useState(true)
    const [profile, setProfile] = useState<PublicProfile | null>(null)
    const [stats, setStats] = useState<any>(null)

    useEffect(() => {
        async function fetchProfile() {
            if (!userId) return

            // Get public profile info
            const { data: profileData, error } = await supabase
                .from("profiles")
                .select("id, full_name, avatar_url, nickname, bio, role, class, created_at")
                .eq("id", userId)
                .single()

            if (error || !profileData) {
                router.push("/")
                return
            }

            setProfile(profileData)

            // Get stats based on role
            if (profileData.role === "student") {
                const { data: statsData } = await supabase
                    .from("user_stats")
                    .select("*")
                    .eq("user_id", userId)
                    .single()

                setStats(statsData)
            } else if (profileData.role === "teacher") {
                const { data: exams } = await supabase
                    .from("exams")
                    .select("id, status")
                    .eq("teacher_id", userId)

                setStats({
                    totalExams: exams?.length || 0,
                    publishedExams: exams?.filter((e: { status: string }) => e.status === "published").length || 0
                })
            }

            setLoading(false)
        }

        fetchProfile()
    }, [userId, router, supabase])

    if (loading) {
        return (
            <div className="min-h-screen bg-gray-100 dark:bg-slate-950 flex items-center justify-center">
                <Loader2 className="w-8 h-8 text-blue-600 animate-spin" />
            </div>
        )
    }

    if (!profile) {
        return (
            <div className="min-h-screen bg-gray-100 dark:bg-slate-950 flex items-center justify-center">
                <div className="text-center">
                    <h1 className="text-2xl font-bold text-gray-900 dark:text-white mb-4">
                        Không tìm thấy người dùng
                    </h1>
                    <Link href="/">
                        <Button>Quay lại trang chủ</Button>
                    </Link>
                </div>
            </div>
        )
    }

    const isStudent = profile.role === "student"
    const joinedDate = new Date(profile.created_at).toLocaleDateString("vi-VN", {
        month: "long",
        year: "numeric"
    })

    return (
        <div className="min-h-screen bg-gray-100 dark:bg-slate-950 py-8">
            <div className="max-w-4xl mx-auto px-4">
                {/* Back button */}
                <Link href="/" className="inline-flex items-center text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white mb-6">
                    <ArrowLeft className="w-4 h-4 mr-2" />
                    Quay lại
                </Link>

                {/* Profile Card */}
                <div className="bg-white dark:bg-slate-900 rounded-xl shadow-sm border border-gray-200 dark:border-slate-800 overflow-hidden">
                    {/* Header gradient */}
                    <div className={`h-32 bg-gradient-to-r ${isStudent ? "from-blue-500 to-purple-500" : "from-purple-500 to-blue-600"}`} />

                    {/* Profile content */}
                    <div className="px-6 pb-6">
                        <div className="flex flex-col md:flex-row gap-6 -mt-16 md:items-end">
                            {/* Avatar */}
                            <div className={`w-32 h-32 rounded-full border-4 border-white dark:border-slate-900 ${isStudent ? "bg-gradient-to-r from-blue-500 to-purple-500" : "bg-gradient-to-br from-purple-500 to-blue-600"} flex items-center justify-center text-5xl font-bold text-white shadow-lg overflow-hidden`}>
                                {profile.avatar_url ? (
                                    <img src={profile.avatar_url} alt={profile.full_name} className="w-full h-full object-cover" />
                                ) : (
                                    profile.full_name.charAt(0).toUpperCase()
                                )}
                            </div>

                            {/* Name and role */}
                            <div className="flex-1 text-center md:text-left">
                                <h1 className="text-3xl font-bold text-gray-900 dark:text-white mb-2">
                                    {profile.full_name}
                                </h1>
                                {profile.nickname && (
                                    <p className="text-lg text-gray-600 dark:text-gray-400 mb-2">
                                        @{profile.nickname}
                                    </p>
                                )}
                                <div className="flex items-center justify-center md:justify-start gap-3 flex-wrap">
                                    <span className={`inline-flex items-center gap-2 px-3 py-1 rounded-full text-xs font-semibold ${isStudent ? "bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-400" : "bg-purple-100 dark:bg-purple-900/30 text-purple-700 dark:text-purple-400"}`}>
                                        <User className="w-3 h-3" />
                                        {isStudent ? "Học sinh" : "Giáo viên"}
                                    </span>
                                    {isStudent && profile.class && (
                                        <span className="inline-flex items-center gap-2 px-3 py-1 bg-gray-100 dark:bg-slate-800 rounded-full text-xs font-semibold text-gray-700 dark:text-gray-300">
                                            <BookOpen className="w-3 h-3" />
                                            Lớp {profile.class}
                                        </span>
                                    )}
                                    <span className="inline-flex items-center gap-2 px-3 py-1 bg-gray-100 dark:bg-slate-800 rounded-full text-xs font-semibold text-gray-700 dark:text-gray-300">
                                        <Calendar className="w-3 h-3" />
                                        Tham gia {joinedDate}
                                    </span>
                                </div>
                            </div>
                        </div>

                        {/* Bio */}
                        {profile.bio && (
                            <div className="mt-6 p-4 bg-gray-50 dark:bg-slate-800 rounded-lg">
                                <h3 className="text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">
                                    Giới thiệu
                                </h3>
                                <p className="text-gray-600 dark:text-gray-400">
                                    {profile.bio}
                                </p>
                            </div>
                        )}

                        {/* Stats */}
                        {stats && (
                            <div className="mt-6 grid grid-cols-2 md:grid-cols-4 gap-4">
                                {isStudent ? (
                                    <>
                                        <div className="p-4 bg-blue-50 dark:bg-blue-900/20 rounded-lg text-center">
                                            <div className="text-2xl font-bold text-blue-600 dark:text-blue-400">
                                                {stats.total_xp || 0}
                                            </div>
                                            <div className="text-xs text-gray-600 dark:text-gray-400 mt-1">
                                                Tổng XP
                                            </div>
                                        </div>
                                        <div className="p-4 bg-green-50 dark:bg-green-900/20 rounded-lg text-center">
                                            <div className="text-2xl font-bold text-green-600 dark:text-green-400">
                                                {stats.streak_days || 0}
                                            </div>
                                            <div className="text-xs text-gray-600 dark:text-gray-400 mt-1">
                                                Ngày streak
                                            </div>
                                        </div>
                                        <div className="p-4 bg-purple-50 dark:bg-purple-900/20 rounded-lg text-center">
                                            <div className="text-2xl font-bold text-purple-600 dark:text-purple-400">
                                                {stats.correct_answers || 0}
                                            </div>
                                            <div className="text-xs text-gray-600 dark:text-gray-400 mt-1">
                                                Câu đúng
                                            </div>
                                        </div>
                                        <div className="p-4 bg-orange-50 dark:bg-orange-900/20 rounded-lg text-center">
                                            <div className="text-2xl font-bold text-orange-600 dark:text-orange-400">
                                                {stats.total_questions || 0}
                                            </div>
                                            <div className="text-xs text-gray-600 dark:text-gray-400 mt-1">
                                                Tổng câu hỏi
                                            </div>
                                        </div>
                                    </>
                                ) : (
                                    <>
                                        <div className="p-4 bg-purple-50 dark:bg-purple-900/20 rounded-lg text-center">
                                            <div className="text-2xl font-bold text-purple-600 dark:text-purple-400">
                                                {stats.totalExams || 0}
                                            </div>
                                            <div className="text-xs text-gray-600 dark:text-gray-400 mt-1">
                                                Tổng đề thi
                                            </div>
                                        </div>
                                        <div className="p-4 bg-green-50 dark:bg-green-900/20 rounded-lg text-center">
                                            <div className="text-2xl font-bold text-green-600 dark:text-green-400">
                                                {stats.publishedExams || 0}
                                            </div>
                                            <div className="text-xs text-gray-600 dark:text-gray-400 mt-1">
                                                Đã xuất bản
                                            </div>
                                        </div>
                                    </>
                                )}
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    )
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { createClient } from "@/lib/supabase/client";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import {
    Search,
    Upload,
    FileText,
    Download,
    Eye,
    Trash2,
    Filter,
    Grid3X3,
    List,
    BookOpen,
    GraduationCap,
    MoreVertical,
    Calendar,
    User,
    X,
    Loader2,
    FolderOpen
} from "lucide-react";
import { cn } from "@/lib/utils";
import { NotificationBell } from "@/components/NotificationBell";
import { UserMenu } from "@/components/UserMenu";
import { BottomNav } from "@/components/BottomNav";

interface Resource {
    id: string;
    title: string;
    type: "document" | "exam";
    subject: string;
    file_url: string;
    description: string;
    tags: string[];
    view_count: number;
    download_count: number;
    created_at: string;
    uploader_id: string;
}

const SUBJECTS = [
    { value: "", label: "Tất cả", icon: "📚", color: "bg-gray-500" },
    { value: "math", label: "Toán", icon: "🔢", color: "bg-blue-600" },
    { value: "physics", label: "Vật lý", icon: "⚛️", color: "bg-purple-600" },
    { value: "chemistry", label: "Hóa học", icon: "🧪", color: "bg-green-600" },
    { value: "biology", label: "Sinh học", icon: "🧬", color: "bg-yellow-600" },
    { value: "english", label: "Tiếng Anh", icon: "🇬🇧", color: "bg-red-600" },
    { value: "literature", label: "Ngữ văn", icon: "📖", color: "bg-pink-600" },
    { value: "history", label: "Lịch sử", icon: "🏛️", color: "bg-amber-600" },
    { value: "geography", label: "Địa lý", icon: "🌍", color: "bg-cyan-600" },
];

export default function ResourcesPage() {
    const [resources, setResources] = useState<Resource[]>([]);
    const [loading, setLoading] = useState(true);
    const [filterSubject, setFilterSubject] = useState("");
    const [filterType, setFilterType] = useState("");
    const [searchQuery, setSearchQuery] = useState("");
    const [user, setUser] = useState<{ id: string; role?: string; full_name?: string } | null>(null);
    const [viewMode, setViewMode] = useState<"grid" | "list">("grid");
    const [showFilters, setShowFilters] = useState(false);
    const [deleting, setDeleting] = useState<string | null>(null);

    const supabase = createClient();
    const router = useRouter();

    useEffect(() => {
        fetchResources();
        checkAuth();
    }, [filterType, filterSubject]);

    const checkAuth = async () => {
        const { data: { session } } = await supabase.auth.getSession();
        if (session) {
            const { data: profile } = await supabase
                .from("profiles")
                .select("role, full_name")
                .eq("id", session.user.id)
                .single();
            setUser({ id: session.user.id, role: profile?.role, full_name: profile?.full_name });
        }
    };

    const fetchResources = async () => {
        setLoading(true);
        let query = supabase
            .from("resources")
            .select("*")
            .order("created_at", { ascending: false });

        if (filterType) query = query.eq("type", filterType);
        if (filterSubject) query = query.eq("subject", filterSubject);

        const { data, error } = await query;
        console.log("Resources fetch:", { data, error }); // Debug log
        if (!error && data) setResources(data);
        setLoading(false);
    };

    const filteredResources = resources.filter((r) =>
        r.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
        r.description?.toLowerCase().includes(searchQuery.toLowerCase())
    );

    const handleView = async (resource: Resource) => {
        await supabase.rpc("increment_resource_view", { resource_id: resource.id });
        window.open(resource.file_url, "_blank");
    };

    const handleDelete = async (resource: Resource) => {
        if (!confirm(`Xóa tài liệu "${resource.title}"?`)) return;

        setDeleting(resource.id);
        try {
            // Delete from storage if possible
            const fileName = resource.file_url.split("/").pop();
            if (fileName) {
                await supabase.storage.from("exam-pdfs").remove([`resources/${fileName}`]);
            }

            // Delete from database
            await supabase.from("resources").delete().eq("id", resource.id);

            // Refresh list
            fetchResources();
        } catch (err) {
            console.error("Delete error:", err);
            alert("Không thể xóa tài liệu");
        } finally {
            setDeleting(null);
        }
    };

    const handleLogout = async () => {
        await supabase.auth.signOut();
        router.push("/login");
    };

    const getSubjectInfo = (subject: string) => SUBJECTS.find((s) => s.value === subject) || SUBJECTS[0];
    const formatDate = (dateStr: string) => new Date(dateStr).toLocaleDateString("vi-VN");

    const canUpload = user?.role === "teacher";
    const canDelete = (resource: Resource) => user?.id === resource.uploader_id || user?.role === "teacher";

    return (
        <div className="min-h-screen bg-gradient-to-br from-slate-50 via-blue-50/30 to-indigo-50/50 dark:from-slate-950 dark:via-slate-900 dark:to-slate-950 pb-24 lg:pb-8">
            {/* Header */}
            <header className="bg-white/80 dark:bg-slate-900/80 backdrop-blur-xl sticky top-0 z-50 border-b border-gray-200/50 dark:border-slate-800/50">
                <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
                    <div className="flex items-center gap-4">
                        <Link href="/" className="flex items-center gap-2">
                            <div className="w-9 h-9 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-xl flex items-center justify-center shadow-lg shadow-blue-500/20">
                                <GraduationCap className="w-5 h-5 text-white" />
                            </div>
                            <span className="font-bold text-xl text-gray-900 dark:text-white hidden sm:block">ExamHub</span>
                        </Link>
                    </div>

                    {/* Search - Desktop */}
                    <div className="hidden md:flex flex-1 max-w-md mx-8">
                        <div className="relative w-full">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                            <Input
                                type="text"
                                placeholder="Tìm kiếm tài liệu..."
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                className="pl-10 bg-gray-100/80 dark:bg-slate-800/80 border-0 focus:ring-2 focus:ring-blue-500"
                            />
                        </div>
                    </div>

                    <div className="flex items-center gap-3">
                        {user ? (
                            <>
                                <NotificationBell />
                                <UserMenu
                                    userName={user.full_name || ""}
                                    onLogout={handleLogout}
                                    role={user.role === "teacher" ? "teacher" : "student"}
                                />
                            </>
                        ) : (
                            <Link href="/login">
                                <Button className="bg-blue-600 hover:bg-blue-700 text-white">Đăng nhập</Button>
                            </Link>
                        )}
                    </div>
                </div>
            </header>

            <main className="max-w-7xl mx-auto px-4 py-6">
                {/* Page Header */}
                <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 mb-8">
                    <div>
                        <h1 className="text-3xl font-bold text-gray-900 dark:text-white flex items-center gap-3">
                            <div className="w-10 h-10 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-xl flex items-center justify-center">
                                <FolderOpen className="w-5 h-5 text-white" />
                            </div>
                            Kho Tài Liệu
                        </h1>
                        <p className="text-gray-500 dark:text-gray-400 mt-1">
                            {filteredResources.length} tài liệu • Chia sẻ và học tập cùng nhau
                        </p>
                    </div>

                    <div className="flex items-center gap-3">
                        {/* View Mode Toggle */}
                        <div className="hidden sm:flex items-center bg-gray-100 dark:bg-slate-800 rounded-lg p-1">
                            <button
                                onClick={() => setViewMode("grid")}
                                className={cn(
                                    "p-2 rounded-md transition-colors",
                                    viewMode === "grid"
                                        ? "bg-white dark:bg-slate-700 text-blue-600 shadow-sm"
                                        : "text-gray-500 hover:text-gray-700 dark:hover:text-gray-300"
                                )}
                            >
                                <Grid3X3 className="w-4 h-4" />
                            </button>
                            <button
                                onClick={() => setViewMode("list")}
                                className={cn(
                                    "p-2 rounded-md transition-colors",
                                    viewMode === "list"
                                        ? "bg-white dark:bg-slate-700 text-blue-600 shadow-sm"
                                        : "text-gray-500 hover:text-gray-700 dark:hover:text-gray-300"
                                )}
                            >
                                <List className="w-4 h-4" />
                            </button>
                        </div>

                        {/* Filter Toggle - Mobile */}
                        <Button
                            variant="outline"
                            onClick={() => setShowFilters(!showFilters)}
                            className="lg:hidden"
                        >
                            <Filter className="w-4 h-4 mr-2" />
                            Lọc
                        </Button>

                        {/* Upload Button */}
                        {canUpload && (
                            <Link href="/resources/upload">
                                <Button className="bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 text-white shadow-lg shadow-blue-500/25">
                                    <Upload className="w-4 h-4 mr-2" />
                                    <span className="hidden sm:inline">Tải lên</span>
                                </Button>
                            </Link>
                        )}
                    </div>
                </div>

                {/* Mobile Search */}
                <div className="md:hidden mb-4">
                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                        <Input
                            type="text"
                            placeholder="Tìm kiếm tài liệu..."
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="pl-10 bg-white dark:bg-slate-800"
                        />
                    </div>
                </div>

                {/* Filters */}
                <div className={cn(
                    "mb-6 transition-all",
                    showFilters ? "block" : "hidden lg:block"
                )}>
                    {/* Subject Filter Pills */}
                    <div className="flex flex-wrap gap-2 mb-4">
                        {SUBJECTS.map((subject) => (
                            <button
                                key={subject.value}
                                onClick={() => setFilterSubject(subject.value)}
                                className={cn(
                                    "px-4 py-2 rounded-full text-sm font-medium transition-all flex items-center gap-2",
                                    filterSubject === subject.value
                                        ? "bg-blue-600 text-white shadow-lg shadow-blue-500/25"
                                        : "bg-white dark:bg-slate-800 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-slate-700 border border-gray-200 dark:border-slate-700"
                                )}
                            >
                                <span>{subject.icon}</span>
                                {subject.label}
                            </button>
                        ))}
                    </div>

                    {/* Type Filter */}
                    <div className="flex gap-2">
                        <button
                            onClick={() => setFilterType("")}
                            className={cn(
                                "px-3 py-1.5 rounded-lg text-sm font-medium transition-colors",
                                filterType === ""
                                    ? "bg-gray-900 dark:bg-white text-white dark:text-gray-900"
                                    : "text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-slate-800"
                            )}
                        >
                            Tất cả
                        </button>
                        <button
                            onClick={() => setFilterType("document")}
                            className={cn(
                                "px-3 py-1.5 rounded-lg text-sm font-medium transition-colors flex items-center gap-1.5",
                                filterType === "document"
                                    ? "bg-gray-900 dark:bg-white text-white dark:text-gray-900"
                                    : "text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-slate-800"
                            )}
                        >
                            <BookOpen className="w-3.5 h-3.5" />
                            Tài liệu
                        </button>
                        <button
                            onClick={() => setFilterType("exam")}
                            className={cn(
                                "px-3 py-1.5 rounded-lg text-sm font-medium transition-colors flex items-center gap-1.5",
                                filterType === "exam"
                                    ? "bg-gray-900 dark:bg-white text-white dark:text-gray-900"
                                    : "text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-slate-800"
                            )}
                        >
                            <FileText className="w-3.5 h-3.5" />
                            Đề thi
                        </button>
                    </div>
                </div>

                {/* Content */}
                {loading ? (
                    <div className="flex items-center justify-center py-20">
                        <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
                    </div>
                ) : filteredResources.length === 0 ? (
                    <Card className="border-dashed border-2 border-gray-300 dark:border-slate-700 bg-transparent">
                        <CardContent className="py-16 text-center">
                            <div className="w-16 h-16 bg-gray-100 dark:bg-slate-800 rounded-2xl flex items-center justify-center mx-auto mb-4">
                                <FolderOpen className="w-8 h-8 text-gray-400" />
                            </div>
                            <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-2">
                                Chưa có tài liệu nào
                            </h3>
                            <p className="text-gray-500 dark:text-gray-400 mb-6">
                                {canUpload ? "Hãy là người đầu tiên chia sẻ tài liệu!" : "Hãy quay lại sau nhé!"}
                            </p>
                            {canUpload && (
                                <Link href="/resources/upload">
                                    <Button className="bg-blue-600 hover:bg-blue-700">
                                        <Upload className="w-4 h-4 mr-2" />
                                        Tải lên tài liệu đầu tiên
                                    </Button>
                                </Link>
                            )}
                        </CardContent>
                    </Card>
                ) : viewMode === "grid" ? (
                    /* Grid View */
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-5">
                        {filteredResources.map((resource) => {
                            const subjectInfo = getSubjectInfo(resource.subject);
                            return (
                                <Card
                                    key={resource.id}
                                    className="group border-gray-200/50 dark:border-slate-800/50 bg-white dark:bg-slate-900/50 hover:shadow-xl hover:shadow-gray-200/50 dark:hover:shadow-slate-900/50 transition-all duration-300 overflow-hidden"
                                >
                                    {/* Card Header with Subject Color */}
                                    <div className={cn("h-2", subjectInfo.color)} />

                                    <CardContent className="p-5">
                                        {/* Type Badge & Actions */}
                                        <div className="flex items-center justify-between mb-3">
                                            <div className="flex items-center gap-2">
                                                <span className={cn(
                                                    "px-2.5 py-1 rounded-full text-xs font-medium",
                                                    resource.type === "exam"
                                                        ? "bg-blue-100 text-blue-700 dark:bg-blue-900/40 dark:text-blue-300"
                                                        : "bg-emerald-100 text-emerald-700 dark:bg-emerald-900/40 dark:text-emerald-300"
                                                )}>
                                                    {resource.type === "exam" ? "📝 Đề thi" : "📚 Tài liệu"}
                                                </span>
                                            </div>
                                            {canDelete(resource) && (
                                                <button
                                                    onClick={() => handleDelete(resource)}
                                                    disabled={deleting === resource.id}
                                                    className="opacity-0 group-hover:opacity-100 p-1.5 text-gray-400 hover:text-red-500 transition-all"
                                                >
                                                    {deleting === resource.id ? (
                                                        <Loader2 className="w-4 h-4 animate-spin" />
                                                    ) : (
                                                        <Trash2 className="w-4 h-4" />
                                                    )}
                                                </button>
                                            )}
                                        </div>

                                        {/* Icon */}
                                        <div className={cn(
                                            "w-14 h-14 rounded-2xl flex items-center justify-center mb-4",
                                            subjectInfo.color + "/10"
                                        )}>
                                            <span className="text-3xl">{subjectInfo.icon}</span>
                                        </div>

                                        {/* Title */}
                                        <h3 className="font-semibold text-gray-900 dark:text-white mb-2 line-clamp-2 group-hover:text-blue-600 transition-colors">
                                            {resource.title}
                                        </h3>

                                        {/* Description */}
                                        {resource.description && (
                                            <p className="text-sm text-gray-500 dark:text-gray-400 line-clamp-2 mb-4">
                                                {resource.description}
                                            </p>
                                        )}

                                        {/* Meta */}
                                        <div className="flex items-center gap-3 text-xs text-gray-400 dark:text-gray-500 mb-4">
                                            <span className="flex items-center gap-1">
                                                <Eye className="w-3.5 h-3.5" />
                                                {resource.view_count || 0}
                                            </span>
                                            <span className="flex items-center gap-1">
                                                <Calendar className="w-3.5 h-3.5" />
                                                {formatDate(resource.created_at)}
                                            </span>
                                        </div>

                                        {/* Action Button */}
                                        <Button
                                            onClick={() => handleView(resource)}
                                            className="w-full bg-gray-100 hover:bg-blue-600 text-gray-700 hover:text-white dark:bg-slate-800 dark:hover:bg-blue-600 dark:text-gray-300 transition-colors"
                                        >
                                            <Eye className="w-4 h-4 mr-2" />
                                            Xem tài liệu
                                        </Button>
                                    </CardContent>
                                </Card>
                            );
                        })}
                    </div>
                ) : (
                    /* List View */
                    <div className="space-y-3">
                        {filteredResources.map((resource) => {
                            const subjectInfo = getSubjectInfo(resource.subject);
                            return (
                                <Card
                                    key={resource.id}
                                    className="group border-gray-200/50 dark:border-slate-800/50 bg-white dark:bg-slate-900/50 hover:shadow-lg transition-all"
                                >
                                    <CardContent className="p-4 flex items-center gap-4">
                                        {/* Icon */}
                                        <div className={cn(
                                            "w-12 h-12 rounded-xl flex items-center justify-center shrink-0",
                                            subjectInfo.color + "/10"
                                        )}>
                                            <span className="text-2xl">{subjectInfo.icon}</span>
                                        </div>

                                        {/* Content */}
                                        <div className="flex-1 min-w-0">
                                            <div className="flex items-center gap-2 mb-1">
                                                <h3 className="font-semibold text-gray-900 dark:text-white truncate">
                                                    {resource.title}
                                                </h3>
                                                <span className={cn(
                                                    "px-2 py-0.5 rounded text-xs font-medium shrink-0",
                                                    resource.type === "exam"
                                                        ? "bg-blue-100 text-blue-700 dark:bg-blue-900/40 dark:text-blue-300"
                                                        : "bg-emerald-100 text-emerald-700 dark:bg-emerald-900/40 dark:text-emerald-300"
                                                )}>
                                                    {resource.type === "exam" ? "Đề thi" : "Tài liệu"}
                                                </span>
                                            </div>
                                            <div className="flex items-center gap-4 text-sm text-gray-500 dark:text-gray-400">
                                                <span className="flex items-center gap-1">
                                                    <Eye className="w-3.5 h-3.5" />
                                                    {resource.view_count || 0} lượt xem
                                                </span>
                                                <span className="flex items-center gap-1">
                                                    <Calendar className="w-3.5 h-3.5" />
                                                    {formatDate(resource.created_at)}
                                                </span>
                                            </div>
                                        </div>

                                        {/* Actions */}
                                        <div className="flex items-center gap-2">
                                            <Button
                                                size="sm"
                                                onClick={() => handleView(resource)}
                                                className="bg-blue-600 hover:bg-blue-700 text-white"
                                            >
                                                <Eye className="w-4 h-4 mr-1.5" />
                                                Xem
                                            </Button>
                                            {canDelete(resource) && (
                                                <Button
                                                    size="sm"
                                                    variant="outline"
                                                    onClick={() => handleDelete(resource)}
                                                    disabled={deleting === resource.id}
                                                    className="text-red-600 border-red-200 hover:bg-red-50 dark:border-red-800 dark:hover:bg-red-900/30"
                                                >
                                                    {deleting === resource.id ? (
                                                        <Loader2 className="w-4 h-4 animate-spin" />
                                                    ) : (
                                                        <Trash2 className="w-4 h-4" />
                                                    )}
                                                </Button>
                                            )}
                                        </div>
                                    </CardContent>
                                </Card>
                            );
                        })}
                    </div>
                )}
            </main>

            <BottomNav />
        </div>
    );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { createClient } from "@/lib/supabase/client";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
    Upload,
    ArrowLeft,
    FileText,
    CheckCircle,
    X,
    Loader2,
    GraduationCap
} from "lucide-react";
import { cn } from "@/lib/utils";
import { ThemeToggle } from "@/components/ui/ThemeToggle";

const SUBJECTS = [
    { value: "math", label: "Toán" },
    { value: "physics", label: "Vật lý" },
    { value: "chemistry", label: "Hóa học" },
    { value: "english", label: "Tiếng Anh" },
    { value: "literature", label: "Ngữ văn" },
    { value: "biology", label: "Sinh học" },
    { value: "history", label: "Lịch sử" },
    { value: "geography", label: "Địa lý" },
    { value: "other", label: "Khác" },
];

export default function UploadResourcePage() {
    const [title, setTitle] = useState("");
    const [type, setType] = useState<"document" | "exam">("document");
    const [subject, setSubject] = useState("math");
    const [description, setDescription] = useState("");
    const [tags, setTags] = useState("");
    const [file, setFile] = useState<File | null>(null);
    const [uploading, setUploading] = useState(false);
    const [error, setError] = useState("");
    const [uploadProgress, setUploadProgress] = useState(0);
    const [user, setUser] = useState<{ id: string } | null>(null);
    const [isDragging, setIsDragging] = useState(false);

    const supabase = createClient();
    const router = useRouter();

    useEffect(() => {
        checkAuth();
    }, []);

    const checkAuth = async () => {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session) {
            router.push("/login");
            return;
        }
        setUser({ id: session.user.id });
    };

    const handleDrop = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        setIsDragging(false);
        const droppedFile = e.dataTransfer.files[0];
        if (droppedFile && droppedFile.type === "application/pdf") {
            setFile(droppedFile);
            if (!title) {
                setTitle(droppedFile.name.replace(".pdf", ""));
            }
        }
    }, [title]);

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = e.target.files?.[0];
        if (selectedFile) {
            setFile(selectedFile);
            if (!title) {
                setTitle(selectedFile.name.replace(".pdf", ""));
            }
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!file || !user) return;

        setUploading(true);
        setError("");
        setUploadProgress(10);

        try {
            const fileExt = file.name.split(".").pop();
            const fileName = `resources/${Date.now()}_${Math.random().toString(36).substr(2, 9)}.${fileExt}`;

            setUploadProgress(30);

            const { error: uploadError } = await supabase.storage
                .from("exam-pdfs")
                .upload(fileName, file, {
                    cacheControl: "3600",
                    upsert: false,
                });

            if (uploadError) {
                throw new Error("Không thể upload file: " + uploadError.message);
            }

            const { data: urlData } = supabase.storage
                .from("exam-pdfs")
                .getPublicUrl(fileName);

            setUploadProgress(70);

            const tagArray = tags
                .split(",")
                .map((t) => t.trim())
                .filter((t) => t.length > 0);

            const { error: insertError } = await supabase.from("resources").insert({
                title,
                type,
                subject,
                description,
                tags: tagArray,
                file_url: urlData.publicUrl,
                uploader_id: user.id,
            });

            if (insertError) throw insertError;

            setUploadProgress(100);

            setTimeout(() => {
                router.push("/resources");
            }, 500);
        } catch (err: unknown) {
            const errorMessage = err instanceof Error ? err.message : "Có lỗi xảy ra";
            setError(errorMessage);
            setUploading(false);
        }
    };

    return (
        <div className="min-h-screen bg-gray-50 dark:bg-slate-950">
            {/* Navigation */}
            <nav className="border-b border-gray-100 dark:border-slate-800 bg-white/80 dark:bg-slate-950/80 backdrop-blur-md sticky top-0 z-50">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                    <div className="flex justify-between h-16 items-center">
                        <Link href="/">
                            <div className="flex items-center gap-3">
                                <div className="w-10 h-10 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-xl flex items-center justify-center shadow-lg shadow-blue-500/20">
                                    <GraduationCap className="w-5 h-5 text-white" />
                                </div>
                                <span className="text-xl font-bold text-gray-900 dark:text-white">LuyenDe 2026</span>
                            </div>
                        </Link>
                        <ThemeToggle />
                    </div>
                </div>
            </nav>

            <div className="max-w-2xl mx-auto px-4 py-8">
                <Link href="/resources" className="inline-flex items-center gap-2 text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200 mb-6">
                    <ArrowLeft className="w-4 h-4" />
                    Quay lại Kho tài liệu
                </Link>

                <Card className="border-gray-200 dark:border-slate-800 shadow-sm bg-white dark:bg-slate-900">
                    <CardHeader className="border-b border-gray-50 dark:border-slate-800">
                        <CardTitle className="text-xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
                            <Upload className="w-5 h-5 text-blue-600" />
                            Tải lên tài liệu
                        </CardTitle>
                        <CardDescription className="dark:text-gray-400">Chia sẻ tài liệu, đề thi với nhóm học tập</CardDescription>
                    </CardHeader>
                    <CardContent className="p-6">
                        <form onSubmit={handleSubmit} className="space-y-6">
                            {error && (
                                <div className="bg-red-50 dark:bg-red-900/30 border border-red-200 dark:border-red-800 text-red-700 dark:text-red-400 px-4 py-3 rounded-lg flex items-center gap-2">
                                    <X className="w-4 h-4" />
                                    {error}
                                </div>
                            )}

                            {/* File Upload */}
                            <div
                                className={cn(
                                    "border-2 border-dashed rounded-xl p-8 text-center transition-all",
                                    isDragging
                                        ? "border-blue-500 bg-blue-50 dark:bg-blue-900/40"
                                        : file
                                            ? "border-green-500 bg-green-50 dark:bg-green-900/40"
                                            : "border-gray-300 dark:border-slate-700 hover:border-blue-400 dark:hover:border-blue-500 hover:bg-blue-50/50 dark:hover:bg-blue-900/20"
                                )}
                                onDragOver={(e) => {
                                    e.preventDefault();
                                    setIsDragging(true);
                                }}
                                onDragLeave={() => setIsDragging(false)}
                                onDrop={handleDrop}
                            >
                                {file ? (
                                    <div className="text-green-700 dark:text-green-400">
                                        <CheckCircle className="w-12 h-12 mx-auto mb-3 text-green-500" />
                                        <p className="font-semibold text-lg">{file.name}</p>
                                        <p className="text-sm text-gray-500 dark:text-gray-400">
                                            {(file.size / 1024 / 1024).toFixed(2)} MB
                                        </p>
                                        <button
                                            type="button"
                                            onClick={() => setFile(null)}
                                            className="mt-3 text-sm text-red-600 dark:text-red-400 hover:text-red-700 dark:hover:text-red-300 font-medium"
                                        >
                                            Xóa và chọn file khác
                                        </button>
                                    </div>
                                ) : (
                                    <div className="text-gray-500 dark:text-gray-400">
                                        <FileText className="w-12 h-12 mx-auto mb-3 text-gray-400 dark:text-slate-500" />
                                        <p className="font-semibold text-gray-700 dark:text-gray-200">Kéo thả file PDF vào đây</p>
                                        <p className="text-sm mb-4">hoặc</p>
                                        <label className="inline-block px-5 py-2.5 bg-blue-600 text-white rounded-lg cursor-pointer hover:bg-blue-700 font-medium shadow-md">
                                            Chọn file
                                            <input
                                                type="file"
                                                accept=".pdf"
                                                onChange={handleFileChange}
                                                className="hidden"
                                            />
                                        </label>
                                    </div>
                                )}
                            </div>

                            {/* Title */}
                            <div className="space-y-2">
                                <Label className="text-gray-700 dark:text-gray-300 font-medium">Tiêu đề *</Label>
                                <Input
                                    type="text"
                                    value={title}
                                    onChange={(e) => setTitle(e.target.value)}
                                    required
                                    placeholder="VD: Đề thi thử THPT 2026 - Lần 5"
                                    className="bg-white dark:bg-slate-800 border-gray-300 dark:border-slate-700 dark:text-white"
                                />
                            </div>

                            {/* Type & Subject */}
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-2">
                                    <Label className="text-gray-700 dark:text-gray-300 font-medium">Loại *</Label>
                                    <select
                                        value={type}
                                        onChange={(e) => setType(e.target.value as "document" | "exam")}
                                        className="w-full px-3 py-2 border border-gray-300 dark:border-slate-700 rounded-md text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500 bg-white dark:bg-slate-800 dark:text-white"
                                    >
                                        <option value="document">📚 Tài liệu</option>
                                        <option value="exam">📝 Đề thi</option>
                                    </select>
                                </div>
                                <div className="space-y-2">
                                    <Label className="text-gray-700 dark:text-gray-300 font-medium">Môn học *</Label>
                                    <select
                                        value={subject}
                                        onChange={(e) => setSubject(e.target.value)}
                                        className="w-full px-3 py-2 border border-gray-300 dark:border-slate-700 rounded-md text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500 bg-white dark:bg-slate-800 dark:text-white"
                                    >
                                        {SUBJECTS.map((s) => (
                                            <option key={s.value} value={s.value}>
                                                {s.label}
                                            </option>
                                        ))}
                                    </select>
                                </div>
                            </div>

                            {/* Description */}
                            <div className="space-y-2">
                                <Label className="text-gray-700 dark:text-gray-300 font-medium">Mô tả</Label>
                                <Textarea
                                    value={description}
                                    onChange={(e) => setDescription(e.target.value)}
                                    rows={3}
                                    placeholder="Mô tả ngắn về tài liệu..."
                                    className="bg-white dark:bg-slate-800 border-gray-300 dark:border-slate-700 resize-none dark:text-white"
                                />
                            </div>

                            {/* Tags */}
                            <div className="space-y-2">
                                <Label className="text-gray-700 dark:text-gray-300 font-medium">Tags (phân cách bằng dấu phẩy)</Label>
                                <Input
                                    type="text"
                                    value={tags}
                                    onChange={(e) => setTags(e.target.value)}
                                    placeholder="VD: THPT 2026, đại số, khó"
                                    className="bg-white dark:bg-slate-800 border-gray-300 dark:border-slate-700 dark:text-white"
                                />
                            </div>

                            {/* Progress Bar */}
                            {uploading && (
                                <div className="bg-gray-100 dark:bg-slate-700 rounded-full overflow-hidden h-2">
                                    <div
                                        className="h-full bg-gradient-to-r from-blue-500 to-indigo-600 transition-all duration-300"
                                        style={{ width: `${uploadProgress}%` }}
                                    />
                                </div>
                            )}

                            {/* Submit */}
                            <Button
                                type="submit"
                                disabled={!file || !title || uploading}
                                className={cn(
                                    "w-full h-12 text-base font-semibold",
                                    !file || !title || uploading
                                        ? "bg-gray-300 dark:bg-slate-700 text-gray-500 dark:text-gray-400"
                                        : "bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 text-white shadow-lg shadow-blue-500/20"
                                )}
                            >
                                {uploading ? (
                                    <span className="flex items-center justify-center gap-2">
                                        <Loader2 className="w-5 h-5 animate-spin" />
                                        Đang tải lên... {uploadProgress}%
                                    </span>
                                ) : (
                                    <span className="flex items-center justify-center gap-2">
                                        <Upload className="w-5 h-5" />
                                        Tải lên
                                    </span>
                                )}
                            </Button>
                        </form>
                    </CardContent>
                </Card>
            </div>
        </div>
    );
}

"use client"

import { useEffect, useState } from "react"
import { useRouter, useParams } from "next/navigation"
import Link from "next/link"
import { createClient } from "@/lib/supabase/client"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import {
    Trophy,
    CheckCircle2,
    XCircle,
    Clock,
    Home,
    Loader2,
    Medal,
    ArrowRight,
    Share2,
    RotateCcw,
    GraduationCap,
    Lock
} from "lucide-react"
import { cn } from "@/lib/utils"
import { updateStudentStats } from "@/lib/gamification"
import { XpGainAnimation, LevelUpAnimation } from "@/components/gamification/XpBar"
import { NotificationBell } from "@/components/NotificationBell"
import { UserMenu } from "@/components/UserMenu"

// Type definitions
type TFAnswer = { question: number; a: boolean; b: boolean; c: boolean; d: boolean }
type SAAnswer = { question: number; answer: number | string }
type TFStudentAnswer = { question: number; a: boolean | null; b: boolean | null; c: boolean | null; d: boolean | null }
type SAStudentAnswer = { question: number; answer: string }

interface Exam {
    id: string
    title: string
    total_questions: number
    correct_answers: string[]
    mc_answers?: { question: number; answer: string }[]
    tf_answers?: TFAnswer[]
    sa_answers?: SAAnswer[]
    score_visibility_mode?: string
    score_visibility_threshold?: number
}

interface Submission {
    id: string
    student_answers: string[]
    score: number
    correct_count: number
    time_spent: number
    submitted_at: string
    mc_correct?: number
    tf_correct?: number
    sa_correct?: number
    mc_student_answers?: { question: number; answer: string }[]
    tf_student_answers?: TFStudentAnswer[]
    sa_student_answers?: SAStudentAnswer[]
}

interface LeaderboardEntry {
    id: string
    score: number
    time_spent: number
    profile: {
        full_name: string | null
    }
}

export default function ExamResultPage() {
    const router = useRouter()
    const params = useParams()
    const examId = params.id as string
    const supabase = createClient()

    const [exam, setExam] = useState<Exam | null>(null)
    const [submission, setSubmission] = useState<Submission | null>(null)
    const [leaderboard, setLeaderboard] = useState<LeaderboardEntry[]>([])
    const [loading, setLoading] = useState(true)
    const [fullName, setFullName] = useState("")

    // Gamification states
    const [xpGained, setXpGained] = useState<number | null>(null)
    const [showLevelUp, setShowLevelUp] = useState(false)
    const [newLevel, setNewLevel] = useState(1)

    // Retake states
    const [canRetake, setCanRetake] = useState(false)
    const [attemptsUsed, setAttemptsUsed] = useState(0)
    const [maxAttempts, setMaxAttempts] = useState(1)

    // Score visibility
    const [canViewScore, setCanViewScore] = useState(true)

    useEffect(() => {
        const fetchData = async () => {
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) {
                router.push("/login")
                return
            }

            const { data: profile } = await supabase
                .from("profiles")
                .select("full_name")
                .eq("id", user.id)
                .single()

            if (profile) setFullName(profile.full_name || "")

            // Get exam
            const { data: examData } = await supabase
                .from("exams")
                .select("*")
                .eq("id", examId)
                .single()

            if (!examData) {
                router.push("/student/dashboard")
                return
            }

            setExam(examData)
            const examMaxAttempts = examData.max_attempts ?? 1
            setMaxAttempts(examMaxAttempts)

            // Get ALL submissions for this exam by this student
            const { data: allSubmissions, count } = await supabase
                .from("submissions")
                .select("*", { count: "exact" })
                .eq("exam_id", examId)
                .eq("student_id", user.id)
                .order("score", { ascending: false }) // Best score first

            if (!allSubmissions || allSubmissions.length === 0) {
                router.push(`/student/exams/${examId}/take`)
                return
            }

            // Use best score submission for display
            setSubmission(allSubmissions[0])
            setAttemptsUsed(count ?? allSubmissions.length)

            // Check if can retake
            if (examMaxAttempts === 0 || (count ?? 0) < examMaxAttempts) {
                setCanRetake(true)
            }

            // Check score visibility
            const scoreVisMode = examData.score_visibility_mode || 'always'
            const scoreThresh = examData.score_visibility_threshold || 0
            const studentScore = allSubmissions[0].score

            const shouldShowScore =
                scoreVisMode === 'always' ||
                (scoreVisMode === 'threshold' && studentScore >= scoreThresh)

            setCanViewScore(shouldShowScore)

            // Get leaderboard
            const { data: leaderboardData } = await supabase
                .from("submissions")
                .select("id, score, time_spent, student_id, profile:profiles(full_name)")
                .eq("exam_id", examId)
                .order("score", { ascending: false })
                .order("time_spent", { ascending: true })
                .limit(10)

            if (leaderboardData) {
                // Transform data to match LeaderboardEntry type
                const transformedData = leaderboardData.map((item: { id: string, score: number, time_spent: number, profile: { full_name: string | null } | { full_name: string | null }[] | null }) => {
                    const profileData = Array.isArray(item.profile) ? item.profile[0] : item.profile
                    return {
                        id: item.id,
                        score: item.score,
                        time_spent: item.time_spent,
                        profile: { full_name: profileData?.full_name ?? null }
                    }
                })
                setLeaderboard(transformedData)
            }

            // Award XP logic
            const xpAwardedKey = `xp_awarded_${examId}_${user.id}_${allSubmissions[0].id}`
            if (!localStorage.getItem(xpAwardedKey)) {
                try {
                    const result = await updateStudentStats(user.id, allSubmissions[0].score)
                    setXpGained(result.xpGained)
                    setNewLevel(result.newLevel)

                    if (result.leveledUp) {
                        setShowLevelUp(true)
                    }

                    localStorage.setItem(xpAwardedKey, "true")
                } catch (err) {
                    console.error("Failed to update stats:", err)
                }
            }

            setLoading(false)
        }

        fetchData()
    }, [examId, router, supabase])

    const handleLogout = async () => {
        await supabase.auth.signOut()
        router.push("/login")
    }

    const formatTime = (seconds: number) => {
        const mins = Math.floor(seconds / 60)
        const secs = seconds % 60
        return `${mins}:${secs.toString().padStart(2, "0")}`
    }

    const getScoreColor = (score: number) => {
        if (score >= 9) return "text-emerald-600"
        if (score >= 8) return "text-green-600"
        if (score >= 6.5) return "text-blue-600"
        if (score >= 5) return "text-yellow-600"
        return "text-red-600"
    }

    const getScoreMessage = (score: number) => {
        if (score >= 9) return "Xuất sắc! 🎉"
        if (score >= 8) return "Làm tốt lắm! 👏"
        if (score >= 6.5) return "Khá tốt! 👍"
        if (score >= 5) return "Đạt yêu cầu"
        return "Cần cố gắng thêm"
    }

    if (loading) {
        return (
            <div className="min-h-screen bg-gray-50 dark:bg-slate-950 flex items-center justify-center">
                <Loader2 className="w-8 h-8 animate-spin text-blue-600 dark:text-blue-400" />
            </div>
        )
    }

    if (!exam || !submission) return null

    return (
        <div className="min-h-screen bg-gray-50 dark:bg-slate-950 flex flex-col">
            {/* Gamification Animations */}
            {xpGained !== null && xpGained > 0 && (
                <XpGainAnimation xpGained={xpGained} onComplete={() => setXpGained(null)} />
            )}
            {showLevelUp && (
                <LevelUpAnimation newLevel={newLevel} onComplete={() => setShowLevelUp(false)} />
            )}

            {/* Header */}
            <header className="bg-white dark:bg-slate-900 border-b border-gray-200 dark:border-slate-800 sticky top-0 z-50">
                <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
                    <div className="flex items-center gap-6">
                        <Link href="/student/dashboard" className="flex items-center gap-2">
                            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center shadow-lg shadow-blue-200 dark:shadow-blue-900/30">
                                <GraduationCap className="w-6 h-6 text-white" />
                            </div>
                            <span className="font-bold text-xl text-gray-800 dark:text-white hidden md:block">ExamHub</span>
                        </Link>
                    </div>
                    <div className="flex items-center gap-3">
                        <NotificationBell />
                        <UserMenu userName={fullName} onLogout={handleLogout} role="student" />
                    </div>
                </div>
            </header>

            <main className="flex-grow w-full max-w-5xl mx-auto px-4 py-8">
                {/* Result Title */}
                <div className="text-center mb-8">
                    <h1 className="text-2xl font-bold text-gray-800 dark:text-white mb-2">{exam.title}</h1>
                    <p className="text-gray-500 dark:text-gray-400">Kết quả bài làm của bạn</p>
                </div>

                <div className="grid md:grid-cols-3 gap-6">
                    {/* Left Column: Score & Details (2/3) */}
                    <div className="md:col-span-2 space-y-6">
                        {canViewScore ? (
                            <>
                                {/* Score Card */}
                                <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-gray-100 dark:border-slate-800 overflow-hidden relative">
                                    {/* Decorative Background */}
                                    <div className={cn(
                                        "absolute top-0 left-0 w-full h-2",
                                        submission.score >= 8 ? "bg-gradient-to-r from-green-400 to-emerald-500" :
                                            submission.score >= 5 ? "bg-gradient-to-r from-yellow-400 to-orange-500" :
                                                "bg-gradient-to-r from-red-400 to-pink-500"
                                    )} />

                                    <div className="p-8 text-center relative z-10">
                                        <div className="inline-flex items-center justify-center w-28 h-28 rounded-full bg-gray-50 dark:bg-white/5 mb-6 shadow-inner relative">
                                            <Trophy className={cn("w-14 h-14", getScoreColor(submission.score))} />
                                            {submission.score >= 9 && (
                                                <div className="absolute -top-2 -right-2 text-2xl animate-bounce">👑</div>
                                            )}
                                        </div>

                                        <div className="space-y-2 mb-6">
                                            <h2 className={cn("text-6xl font-black tracking-tight", getScoreColor(submission.score))}>
                                                {submission.score.toFixed(1)}
                                            </h2>
                                            <p className="text-xl font-medium text-gray-600 dark:text-gray-300">{getScoreMessage(submission.score)}</p>
                                        </div>

                                        <div className="flex items-center justify-center gap-4 md:gap-12 py-6 border-t border-gray-50 dark:border-white/10">
                                            <div className="text-center">
                                                <div className="flex items-center justify-center gap-2 mb-1">
                                                    <CheckCircle2 className="w-5 h-5 text-green-500" />
                                                    <span className="text-xl font-bold text-gray-800 dark:text-white">{submission.correct_count}</span>
                                                </div>
                                                <p className="text-xs text-gray-400 uppercase tracking-wide">Câu đúng</p>
                                            </div>
                                            <div className="w-px h-12 bg-gray-100 dark:bg-white/10" />
                                            <div className="text-center">
                                                <div className="flex items-center justify-center gap-2 mb-1">
                                                    <XCircle className="w-5 h-5 text-red-500" />
                                                    <span className="text-xl font-bold text-gray-800 dark:text-white">
                                                        {exam.total_questions - submission.correct_count}
                                                    </span>
                                                </div>
                                                <p className="text-xs text-gray-400 uppercase tracking-wide">Câu sai</p>
                                            </div>
                                            <div className="w-px h-12 bg-gray-100 dark:bg-white/10" />
                                            <div className="text-center">
                                                <div className="flex items-center justify-center gap-2 mb-1">
                                                    <Clock className="w-5 h-5 text-blue-500" />
                                                    <span className="text-xl font-bold text-gray-800 dark:text-white">
                                                        {formatTime(submission.time_spent)}
                                                    </span>
                                                </div>
                                                <p className="text-xs text-gray-400 uppercase tracking-wide">Thời gian</p>
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                {/* Detailed Answers Section */}
                                <Card className="border-gray-100 dark:border-slate-800 shadow-sm bg-white dark:bg-slate-900">
                                    <CardHeader className="border-b border-gray-50 dark:border-slate-800">
                                        <CardTitle className="text-gray-800 dark:text-white flex items-center gap-2">
                                            Chi tiết bài làm
                                        </CardTitle>
                                    </CardHeader>
                                    <CardContent className="p-6">
                                        {/* MC Answers */}
                                        {exam.correct_answers && exam.correct_answers.length > 0 && (
                                            <div className="mb-8">
                                                <h3 className="text-sm font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wide mb-4 flex items-center gap-2">
                                                    <span className="w-2 h-2 rounded-full bg-blue-500"></span>
                                                    Trắc nghiệm
                                                </h3>
                                                <div className="grid grid-cols-5 md:grid-cols-8 lg:grid-cols-10 gap-2">
                                                    {exam.correct_answers.map((correct, i) => {
                                                        const studentAnswer = submission.student_answers?.[i]
                                                        const isCorrect = studentAnswer === correct

                                                        return (
                                                            <div
                                                                key={i}
                                                                className={cn(
                                                                    "relative aspect-square flex flex-col items-center justify-center rounded-lg border",
                                                                    isCorrect
                                                                        ? "bg-green-50 dark:bg-green-900/20 border-green-200 dark:border-green-800"
                                                                        : "bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-800"
                                                                )}
                                                            >
                                                                <span className="text-[10px] text-gray-400 absolute top-1">{i + 1}</span>
                                                                <span className={cn(
                                                                    "font-bold text-lg",
                                                                    isCorrect ? "text-green-700 dark:text-green-400" : "text-red-700 dark:text-red-400"
                                                                )}>
                                                                    {studentAnswer || "-"}
                                                                </span>
                                                                {!isCorrect && (
                                                                    <div className="absolute -bottom-2 -right-2 w-5 h-5 rounded-full bg-green-100 dark:bg-green-900 border border-green-200 dark:border-green-800 flex items-center justify-center text-xs font-bold text-green-700 dark:text-green-400 shadow-sm z-10">
                                                                        {correct}
                                                                    </div>
                                                                )}
                                                            </div>
                                                        )
                                                    })}
                                                </div>
                                            </div>
                                        )}

                                        {/* True/False Answers */}
                                        {exam.tf_answers && exam.tf_answers.length > 0 && (
                                            <div className="mb-8">
                                                <h3 className="text-sm font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wide mb-4 flex items-center gap-2">
                                                    <span className="w-2 h-2 rounded-full bg-green-500"></span>
                                                    Đúng / Sai
                                                </h3>
                                                <div className="space-y-3">
                                                    {exam.tf_answers.map((tf, i) => {
                                                        const studentTf = submission.tf_student_answers?.find(a => a.question === tf.question)
                                                        return (
                                                            <div key={i} className="p-4 bg-gray-50 dark:bg-slate-800 rounded-lg border border-gray-100 dark:border-slate-700">
                                                                <div className="mb-2 font-medium text-gray-700 dark:text-gray-300 flex items-center justify-between">
                                                                    <span>Câu {tf.question}</span>
                                                                </div>
                                                                <div className="grid grid-cols-4 gap-2">
                                                                    {(['a', 'b', 'c', 'd'] as const).map((sub) => {
                                                                        const correct = tf[sub]
                                                                        const student = studentTf?.[sub]
                                                                        const isCorrect = student === correct

                                                                        return (
                                                                            <div key={sub} className={cn(
                                                                                "p-2 rounded text-center text-xs relative",
                                                                                isCorrect
                                                                                    ? "bg-white dark:bg-slate-900 border border-green-200 dark:border-green-800 text-green-700 dark:text-green-400 shadow-sm"
                                                                                    : "bg-white dark:bg-slate-900 border border-red-200 dark:border-red-800 text-red-700 dark:text-red-400 shadow-sm"
                                                                            )}>
                                                                                <span className="absolute top-1 left-2 text-[10px] text-gray-400 uppercase">{sub}</span>
                                                                                <span className="font-bold block mt-3">
                                                                                    {student === true ? "Đúng" : student === false ? "Sai" : "-"}
                                                                                </span>
                                                                                {!isCorrect && (
                                                                                    <span className="text-[10px] text-green-600 font-medium block mt-1">
                                                                                        Đáp án: {correct ? "Đúng" : "Sai"}
                                                                                    </span>
                                                                                )}
                                                                            </div>
                                                                        )
                                                                    })}
                                                                </div>
                                                            </div>
                                                        )
                                                    })}
                                                </div>
                                            </div>
                                        )}

                                        {/* Short Answer Answers */}
                                        {exam.sa_answers && exam.sa_answers.length > 0 && (
                                            <div className="mb-8">
                                                <h3 className="text-sm font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wide mb-4 flex items-center gap-2">
                                                    <span className="w-2 h-2 rounded-full bg-purple-500"></span>
                                                    Trả lời ngắn ({exam.sa_answers.length} câu)
                                                </h3>
                                                <div className="space-y-3">
                                                    {exam.sa_answers.map((sa, i) => {
                                                        const studentSa = submission.sa_student_answers?.find(a => a.question === sa.question)
                                                        const correctVal = parseFloat(sa.answer.toString().replace(',', '.'))
                                                        const studentVal = studentSa?.answer ? parseFloat(studentSa.answer.replace(',', '.')) : NaN
                                                        const tolerance = Math.abs(correctVal) * 0.05
                                                        const isCorrect = !isNaN(studentVal) && Math.abs(correctVal - studentVal) <= tolerance

                                                        return (
                                                            <div key={i} className={cn(
                                                                "p-4 rounded-lg border",
                                                                isCorrect
                                                                    ? "bg-green-50 dark:bg-green-900/20 border-green-200 dark:border-green-800"
                                                                    : "bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-800"
                                                            )}>
                                                                <div className="flex items-center justify-between mb-2">
                                                                    <span className="font-medium text-gray-700 dark:text-gray-300">Câu {sa.question}</span>
                                                                    {isCorrect ? (
                                                                        <CheckCircle2 className="w-5 h-5 text-green-600" />
                                                                    ) : (
                                                                        <XCircle className="w-5 h-5 text-red-600" />
                                                                    )}
                                                                </div>
                                                                <div className="grid grid-cols-2 gap-4 text-sm">
                                                                    <div>
                                                                        <span className="text-gray-500 dark:text-gray-400">Câu trả lời:</span>
                                                                        <p className={cn(
                                                                            "font-bold",
                                                                            isCorrect ? "text-green-700 dark:text-green-400" : "text-red-700 dark:text-red-400"
                                                                        )}>
                                                                            {studentSa?.answer || "-"}
                                                                        </p>
                                                                    </div>
                                                                    <div>
                                                                        <span className="text-gray-500 dark:text-gray-400">Đáp án đúng:</span>
                                                                        <p className="font-bold text-green-700 dark:text-green-400">
                                                                            {sa.answer}
                                                                        </p>
                                                                    </div>
                                                                </div>
                                                            </div>
                                                        )
                                                    })}
                                                </div>
                                            </div>
                                        )}
                                    </CardContent>
                                </Card>
                            </>
                        ) : (
                            /* Hidden Score UI */
                            <div className="bg-yellow-50 dark:bg-yellow-900/20 border-2 border-yellow-200 dark:border-yellow-800 rounded-2xl p-8 text-center">
                                <div className="inline-flex items-center justify-center w-20 h-20 rounded-full bg-yellow-100 dark:bg-yellow-900/30 mb-6">
                                    <Lock className="w-10 h-10 text-yellow-600 dark:text-yellow-400" />
                                </div>
                                <h3 className="text-2xl font-bold text-yellow-800 dark:text-yellow-400 mb-3">
                                    Bài làm đã được nộp thành công
                                </h3>
                                <div className="space-y-2 text-yellow-700 dark:text-yellow-300">
                                    {exam.score_visibility_mode === 'never' ? (
                                        <p>Giáo viên không cho phép xem điểm cho đề thi này.</p>
                                    ) : (
                                        <p>
                                            Bạn cần đạt tối thiểu <span className="font-bold">{exam.score_visibility_threshold?.toFixed(1)}</span> điểm để xem kết quả.
                                        </p>
                                    )}
                                    <p className="text-sm">Vui lòng liên hệ giáo viên để biết thêm chi tiết.</p>
                                </div>
                            </div>
                        )}
                    </div>

                    {/* Right Column: Actions & Leaderboard (1/3) */}
                    <div className="space-y-6">
                        {/* Action Card */}
                        <div className="bg-white dark:bg-slate-900 rounded-xl shadow-sm border border-gray-100 dark:border-slate-800 p-6">
                            <h3 className="text-sm font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wide mb-4">Thao tác</h3>
                            <div className="space-y-3">
                                {canRetake && (
                                    <Link href={`/student/exams/${examId}/take`} className="block">
                                        <Button className="w-full bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 text-white shadow-md shadow-blue-200">
                                            <RotateCcw className="w-4 h-4 mr-2" />
                                            Làm lại bài thi
                                        </Button>
                                    </Link>
                                )}

                                <div className="text-center text-xs text-gray-400 mb-2">
                                    {maxAttempts === 0
                                        ? `Đã làm ${attemptsUsed} lần (Không giới hạn)`
                                        : `Đã dùng ${attemptsUsed}/${maxAttempts} lượt làm bài`
                                    }
                                </div>

                                <Link href="/student/dashboard" className="block">
                                    <Button variant="outline" className="w-full border-gray-200 dark:border-slate-700 text-gray-600 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-slate-800">
                                        <Home className="w-4 h-4 mr-2" />
                                        Về trang chủ
                                    </Button>
                                </Link>

                                <Button variant="ghost" className="w-full text-gray-500 dark:text-gray-400 hover:text-blue-600 dark:hover:text-blue-400">
                                    <Share2 className="w-4 h-4 mr-2" />
                                    Chia sẻ kết quả
                                </Button>
                            </div>
                        </div>

                        {/* Leaderboard Widget - Only show if score is visible */}
                        {canViewScore && (
                            <Card className="border-gray-100 dark:border-slate-800 shadow-sm bg-white dark:bg-slate-900 overflow-hidden">
                                <CardHeader className="bg-yellow-50 dark:bg-yellow-900/20 border-b border-yellow-100 dark:border-yellow-800 pb-4">
                                    <CardTitle className="text-yellow-800 dark:text-yellow-400 flex items-center gap-2 text-base">
                                        <Medal className="w-5 h-5 text-yellow-600 dark:text-yellow-400" />
                                        Bảng xếp hạng
                                    </CardTitle>
                                </CardHeader>
                                <CardContent className="p-0">
                                    <div className="divide-y divide-gray-50 dark:divide-slate-800">
                                        {leaderboard.map((entry, index) => (
                                            <div
                                                key={entry.id}
                                                className={cn(
                                                    "flex items-center justify-between p-4 hover:bg-gray-50 dark:hover:bg-slate-800 transition-colors",
                                                    entry.id === submission.id ? "bg-blue-50 dark:bg-blue-900/20 hover:bg-blue-50/80 dark:hover:bg-blue-900/30" : ""
                                                )}
                                            >
                                                <div className="flex items-center gap-3">
                                                    <div className={cn(
                                                        "w-6 h-6 rounded-full flex items-center justify-center font-bold text-xs",
                                                        index === 0 ? "bg-yellow-100 dark:bg-yellow-900/30 text-yellow-700 dark:text-yellow-400" :
                                                            index === 1 ? "bg-gray-100 dark:bg-slate-700 text-gray-700 dark:text-gray-300" :
                                                                index === 2 ? "bg-orange-100 dark:bg-orange-900/30 text-orange-700 dark:text-orange-400" :
                                                                    "text-gray-400"
                                                    )}>
                                                        {index + 1}
                                                    </div>
                                                    <div>
                                                        <p className={cn(
                                                            "text-sm font-medium",
                                                            entry.id === submission.id ? "text-blue-700 dark:text-blue-400" : "text-gray-700 dark:text-gray-300"
                                                        )}>
                                                            {entry.profile?.full_name || "Ẩn danh"}
                                                            {entry.id === submission.id && " (Bạn)"}
                                                        </p>
                                                        <p className="text-xs text-gray-400">{formatTime(entry.time_spent)}</p>
                                                    </div>
                                                </div>
                                                <div className="font-bold text-gray-800 dark:text-white">
                                                    {entry.score.toFixed(1)}
                                                </div>
                                            </div>
                                        ))}
                                        {leaderboard.length === 0 && (
                                            <div className="p-8 text-center text-gray-400 text-sm">
                                                Chưa có bảng xếp hạng
                                            </div>
                                        )}
                                    </div>
                                </CardContent>
                            </Card>
                        )}
                    </div>
                </div>
            </main>
        </div>
    )
}

"use client"

import { useEffect, useState, useCallback, useRef, useMemo } from "react"
import { useRouter, useParams } from "next/navigation"
import { createClient } from "@/lib/supabase/client"
import { Button } from "@/components/ui/button"
import { Card, CardContent } from "@/components/ui/card"
import {
    Clock,
    Send,
    AlertTriangle,
    Loader2,
    FileText,
    ChevronLeft,
    ChevronRight,
    Shield,
    AlertOctagon,
    Maximize
} from "lucide-react"
import { cn } from "@/lib/utils"
import { AntiCheatProvider } from "@/components/exam/AntiCheatProvider"
import { AntiCheatWarning, FullscreenPrompt, ViolationIndicator } from "@/components/exam/AntiCheatUI"
import { createShuffleSeed, shuffleWithMapping } from "@/lib/shuffle"

const OPTIONS = ["A", "B", "C", "D"] as const
type Option = typeof OPTIONS[number]

// Type definitions
type TFStudentAnswer = { question: number; a: boolean | null; b: boolean | null; c: boolean | null; d: boolean | null }
type SAStudentAnswer = { question: number; answer: string }
type TFAnswer = { question: number; a: boolean; b: boolean; c: boolean; d: boolean }
type SAAnswer = { question: number; answer: number | string }

interface Exam {
    id: string
    title: string
    duration: number
    total_questions: number
    pdf_url: string | null
    // REMOVED: correct_answers, mc_answers, tf_answers, sa_answers - these are SECRET
    // Safe question structures (no answers)
    mc_questions?: { question: number }[]
    tf_questions?: { question: number }[]
    sa_questions?: { question: number }[]
    // Scheduling fields
    is_scheduled?: boolean
    start_time?: string
    end_time?: string
    max_attempts?: number
    attempts_used?: number
}

export default function TakeExamPage() {
    const router = useRouter()
    const params = useParams()
    const examId = params.id as string
    const supabase = useMemo(() => createClient(), [])

    // Race condition guard for submit
    const isSubmittingRef = useRef(false)

    const [exam, setExam] = useState<Exam | null>(null)
    const [studentAnswers, setStudentAnswers] = useState<(Option | null)[]>([])

    // Multi-type student answers
    const [tfStudentAnswers, setTfStudentAnswers] = useState<TFStudentAnswer[]>([])
    const [saStudentAnswers, setSaStudentAnswers] = useState<SAStudentAnswer[]>([])
    const [activeTab, setActiveTab] = useState<"mc" | "tf" | "sa">("mc")

    const [timeLeft, setTimeLeft] = useState(0) // seconds
    const [loading, setLoading] = useState(true)
    const [submitting, setSubmitting] = useState(false)
    const [showConfirm, setShowConfirm] = useState(false)
    const [startTime] = useState(Date.now())
    const [pdfPage, setPdfPage] = useState(1)
    const [examStarted, setExamStarted] = useState(false)
    const [antiCheatEnabled, setAntiCheatEnabled] = useState(true)
    const [userId, setUserId] = useState<string | null>(null)

    // Question randomization
    const [mcQuestionOrder, setMcQuestionOrder] = useState<number[]>([])
    const [shuffleEnabled, setShuffleEnabled] = useState(true)

    // Session tracking for ranking
    const [sessionId, setSessionId] = useState<string | null>(null)
    const [isRanked, setIsRanked] = useState(true)
    const [sessionNumber, setSessionNumber] = useState(1)
    const [showSessionChoice, setShowSessionChoice] = useState(false)
    const [existingSession, setExistingSession] = useState<{
        id: string
        answers_snapshot: Record<string, unknown>
        is_ranked: boolean
        session_number: number
    } | null>(null)
    const [tabSwitchCount, setTabSwitchCount] = useState(0)

    // 🐛 FIX BUG-007: Load from localStorage with userId to prevent conflicts
    const LOCAL_STORAGE_KEY = useMemo(() =>
        userId ? `exam_${examId}_${userId}_answers` : `exam_${examId}_answers`,
        [examId, userId]
    )

    useEffect(() => {
        const fetchExam = async () => {
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) {
                router.push("/login")
                return
            }

            // Get exam questions via SECURE API (no answer keys exposed)
            const examResponse = await fetch(`/api/exams/${examId}/questions`)

            if (!examResponse.ok) {
                const errorData = await examResponse.json()
                if (examResponse.status === 403) {
                    if (errorData.error === 'Maximum attempts reached') {
                        router.push(`/student/exams/${examId}/result`)
                        return
                    }
                    if (errorData.start_time) {
                        alert(`Đề thi này sẽ mở lúc ${new Date(errorData.start_time).toLocaleString("vi-VN")}`)
                    } else {
                        alert(errorData.error || "Không thể truy cập đề thi")
                    }
                }
                router.push("/student/dashboard")
                return
            }

            const examData = await examResponse.json()

            setExam(examData)
            setTimeLeft(examData.duration * 60)
            setUserId(user.id)

            // Disable anti-cheat if exam has PDF (mobile can't display inline)
            if (examData.pdf_url) {
                setAntiCheatEnabled(false)
            }

            // Check for existing session
            const { data: existingSessionData } = await supabase
                .from("exam_sessions")
                .select("*")
                .eq("exam_id", examId)
                .eq("student_id", user.id)
                .eq("status", "in_progress")
                .order("created_at", { ascending: false })
                .limit(1)
                .single()

            if (existingSessionData) {
                // Found existing session - show choice to continue or restart
                setExistingSession(existingSessionData)
                setShowSessionChoice(true)
                setLoading(false)
                return // Don't continue loading, wait for user choice
            }

            // Check session count to determine if ranked
            const { count: sessionCount } = await supabase
                .from("exam_sessions")
                .select("*", { count: "exact", head: true })
                .eq("exam_id", examId)
                .eq("student_id", user.id)

            const isFirstSession = (sessionCount ?? 0) === 0
            setIsRanked(isFirstSession)
            setSessionNumber((sessionCount ?? 0) + 1)

            // Create new session
            const { data: newSession } = await supabase
                .from("exam_sessions")
                .insert({
                    exam_id: examId,
                    student_id: user.id,
                    session_number: (sessionCount ?? 0) + 1,
                    is_ranked: isFirstSession,
                    status: "in_progress"
                })
                .select()
                .single()

            if (newSession) {
                setSessionId(newSession.id)

                // Register as participant for real-time tracking
                const { data: profile } = await supabase
                    .from("profiles")
                    .select("full_name")
                    .eq("id", user.id)
                    .single()

                await supabase.from("exam_participants").upsert({
                    exam_id: examId,
                    user_id: user.id,
                    student_name: profile?.full_name || "Học sinh",
                    started_at: new Date().toISOString(),
                    last_active: new Date().toISOString(),
                    status: "active"
                }, { onConflict: "exam_id,user_id" })
            }

            // Create shuffle order for MC questions (consistent per student per exam)
            const mcCount = examData.mc_questions?.length || examData.total_questions || 12
            if (shuffleEnabled) {
                const seed = createShuffleSeed(examId, user.id)
                const indices = Array.from({ length: mcCount }, (_, i) => i)
                const { shuffled } = shuffleWithMapping(indices, seed)
                setMcQuestionOrder(shuffled)
            } else {
                setMcQuestionOrder(Array.from({ length: mcCount }, (_, i) => i))
            }

            // Load saved answers from localStorage
            const saved = localStorage.getItem(LOCAL_STORAGE_KEY)
            if (saved) {
                const savedData = JSON.parse(saved)
                if (savedData.mc) setStudentAnswers(savedData.mc)
                if (savedData.tf) setTfStudentAnswers(savedData.tf)
                if (savedData.sa) setSaStudentAnswers(savedData.sa)
            } else {
                // Initialize MC answers
                setStudentAnswers(Array(mcCount).fill(null))

                // Initialize TF student answers
                if (examData.tf_questions && examData.tf_questions.length > 0) {
                    const tfInit: TFStudentAnswer[] = examData.tf_questions.map((tf: { question: number }) => ({
                        question: tf.question,
                        a: null, b: null, c: null, d: null
                    }))
                    setTfStudentAnswers(tfInit)
                }

                // Initialize SA student answers
                if (examData.sa_questions && examData.sa_questions.length > 0) {
                    const saInit: SAStudentAnswer[] = examData.sa_questions.map((sa: { question: number }) => ({
                        question: sa.question,
                        answer: ""
                    }))
                    setSaStudentAnswers(saInit)
                }
            }

            setLoading(false)
        }

        fetchExam()
    }, [examId, router, supabase, LOCAL_STORAGE_KEY, shuffleEnabled])

    // Countdown timer
    useEffect(() => {
        if (timeLeft <= 0 || loading) return

        const timer = setInterval(() => {
            setTimeLeft(prev => {
                if (prev <= 1) {
                    clearInterval(timer)
                    // 🐛 FIX BUG-001: Guard against race condition
                    if (!isSubmittingRef.current) {
                        isSubmittingRef.current = true
                        handleSubmit(true) // Auto-submit
                    }
                    return 0
                }
                return prev - 1
            })
        }, 1000)

        return () => clearInterval(timer)
    }, [timeLeft, loading])

    // Auto-save to localStorage
    useEffect(() => {
        if (studentAnswers.length > 0 || tfStudentAnswers.length > 0 || saStudentAnswers.length > 0) {
            localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify({
                mc: studentAnswers,
                tf: tfStudentAnswers,
                sa: saStudentAnswers
            }))
        }
    }, [studentAnswers, tfStudentAnswers, saStudentAnswers, LOCAL_STORAGE_KEY])

    // Sync to server periodically (every 30s)
    const [syncError, setSyncError] = useState(false)

    useEffect(() => {
        if (!sessionId) return

        const syncInterval = setInterval(async () => {
            try {
                // 🐛 FIX BUG-002: Add error handling for sync
                const { error } = await supabase
                    .from("exam_sessions")
                    .update({
                        answers_snapshot: {
                            mc: studentAnswers,
                            tf: tfStudentAnswers,
                            sa: saStudentAnswers
                        },
                        last_active_at: new Date().toISOString(),
                        tab_switch_count: tabSwitchCount
                    })
                    .eq("id", sessionId)

                if (error) {
                    console.warn("Sync failed:", error.message)
                    setSyncError(true)
                } else {
                    setSyncError(false)
                }
            } catch (err) {
                console.warn("Sync error:", err)
                setSyncError(true)
            }
        }, 30000)

        return () => clearInterval(syncInterval)
    }, [sessionId, studentAnswers, tfStudentAnswers, saStudentAnswers, tabSwitchCount, supabase])

    const handleAnswerSelect = (questionIndex: number, option: Option) => {
        setStudentAnswers(prev => {
            const newAnswers = [...prev]
            newAnswers[questionIndex] = option
            return newAnswers
        })
    }

    const handleSubmit = useCallback(async (autoSubmit = false) => {
        if (submitting) return
        setSubmitting(true)

        try {
            if (!exam) {
                setSubmitting(false)
                return
            }

            const timeSpent = Math.floor((Date.now() - startTime) / 1000)

            // SECURE SUBMIT: Send answers to server API, server calculates score
            const response = await fetch('/api/exams/submit', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    exam_id: examId,
                    mc_answers: studentAnswers,
                    tf_answers: tfStudentAnswers,
                    sa_answers: saStudentAnswers,
                    session_id: sessionId,
                    time_spent: timeSpent,
                    cheat_flags: {
                        tab_switches: tabSwitchCount,
                        multi_browser: false
                    }
                })
            })

            if (!response.ok) {
                const errorData = await response.json()
                throw new Error(errorData.error || 'Submission failed')
            }

            // Server returns the score (we don't calculate it client-side anymore)
            const result = await response.json()
            console.log('Submission result:', result)

            localStorage.removeItem(LOCAL_STORAGE_KEY)
            router.push(`/student/exams/${examId}/result`)
        } catch (err) {
            console.error("Submit error:", err)
            alert("Lỗi nộp bài: " + (err instanceof Error ? err.message : 'Unknown error'))
            setSubmitting(false)
        }
    }, [exam, examId, studentAnswers, tfStudentAnswers, saStudentAnswers, startTime, router, submitting, LOCAL_STORAGE_KEY, sessionId, tabSwitchCount])

    const formatTime = (seconds: number) => {
        const mins = Math.floor(seconds / 60)
        const secs = seconds % 60
        return `${mins.toString().padStart(2, "0")}:${secs.toString().padStart(2, "0")}`
    }

    const mcAnsweredCount = studentAnswers.filter(a => a !== null).length
    const tfAnsweredCount = tfStudentAnswers.filter(a =>
        a.a !== null || a.b !== null || a.c !== null || a.d !== null
    ).length
    const saAnsweredCount = saStudentAnswers.filter(a => a.answer && a.answer.trim() !== "").length
    const answeredCount = mcAnsweredCount + tfAnsweredCount + saAnsweredCount

    const handleViolation = useCallback((type: string, count: number) => {
        setTabSwitchCount(count)
        if (count >= 5 && isRanked) {
            setIsRanked(false)
            if (sessionId) {
                supabase
                    .from("exam_sessions")
                    .update({ is_ranked: false, tab_switch_count: count })
                    .eq("id", sessionId)
            }
        }
    }, [isRanked, sessionId, supabase])

    const handleMaxViolations = () => {
        handleSubmit(true)
    }

    const handleContinueSession = async () => {
        if (!existingSession) return
        setSessionId(existingSession.id)
        setIsRanked(existingSession.is_ranked)
        setSessionNumber(existingSession.session_number)

        if (existingSession.answers_snapshot) {
            // 🐛 FIX BUG-004: Proper type definition instead of `as any`
            interface AnswerSnapshot {
                mc?: (Option | null)[]
                tf?: TFStudentAnswer[]
                sa?: SAStudentAnswer[]
            }
            const snapshot = existingSession.answers_snapshot as AnswerSnapshot
            if (snapshot.mc) setStudentAnswers(snapshot.mc)
            if (snapshot.tf) setTfStudentAnswers(snapshot.tf)
            if (snapshot.sa) setSaStudentAnswers(snapshot.sa)
        }

        setShowSessionChoice(false)
        setLoading(false)
    }

    const handleRestartSession = async () => {
        if (!userId || !existingSession) return

        await supabase
            .from("exam_sessions")
            .update({ status: "abandoned", is_ranked: false })
            .eq("id", existingSession.id)

        const { data: newSession } = await supabase
            .from("exam_sessions")
            .insert({
                exam_id: examId,
                student_id: userId,
                session_number: existingSession.session_number + 1,
                is_ranked: false,
                status: "in_progress"
            })
            .select()
            .single()

        if (newSession) {
            setSessionId(newSession.id)
            setIsRanked(false)
            setSessionNumber(newSession.session_number)
        }

        if (exam) {
            setStudentAnswers(Array(exam.total_questions).fill(null))
            setTfStudentAnswers([])
            setSaStudentAnswers([])
        }
        localStorage.removeItem(LOCAL_STORAGE_KEY)
        setShowSessionChoice(false)
        setLoading(false)
    }

    if (loading) {
        return (
            <div className="min-h-screen bg-gray-50 dark:bg-slate-950 flex items-center justify-center">
                <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
            </div>
        )
    }

    if (!exam) return null

    if (showSessionChoice && existingSession) {
        return (
            <div className="min-h-screen bg-gray-100 dark:bg-slate-950 flex items-center justify-center p-4">
                <Card className="w-full max-w-md bg-white dark:bg-slate-900 border-gray-200 dark:border-slate-800 shadow-xl">
                    <CardContent className="p-6 space-y-6">
                        <div className="text-center space-y-2">
                            <div className="w-16 h-16 bg-yellow-50 dark:bg-yellow-900/20 rounded-full flex items-center justify-center mx-auto">
                                <AlertTriangle className="w-8 h-8 text-yellow-500" />
                            </div>
                            <h2 className="text-xl font-bold text-gray-800 dark:text-white">Phát hiện phiên làm bài</h2>
                            <p className="text-gray-500 dark:text-gray-400 text-sm">
                                Bạn có một phiên làm bài chưa hoàn thành. Bạn muốn tiếp tục hay làm lại từ đầu?
                            </p>
                        </div>

                        {existingSession.is_ranked && (
                            <div className="p-3 bg-green-50 border border-green-100 rounded-lg">
                                <p className="text-sm text-green-700 text-center font-medium">
                                    ⭐ Phiên này ĐƯỢC TÍNH xếp hạng
                                </p>
                            </div>
                        )}

                        <div className="space-y-3">
                            <Button
                                onClick={handleContinueSession}
                                className="w-full bg-blue-600 hover:bg-blue-700 text-white font-medium"
                            >
                                ✅ Tiếp tục làm bài
                            </Button>

                            <Button
                                onClick={handleRestartSession}
                                variant="outline"
                                className="w-full border-red-200 text-red-600 hover:bg-red-50 hover:text-red-700 hover:border-red-300"
                            >
                                🔄 Làm lại từ đầu (Không tính xếp hạng)
                            </Button>
                        </div>
                    </CardContent>
                </Card>
            </div>
        )
    }

    return (
        <AntiCheatProvider
            enabled={antiCheatEnabled}
            onMaxViolations={handleMaxViolations}
            onViolation={handleViolation}
        >
            {!examStarted && antiCheatEnabled && (
                <FullscreenPrompt onStart={() => setExamStarted(true)} />
            )}

            {examStarted && <AntiCheatWarning />}

            <div className="min-h-screen bg-gray-50 dark:bg-slate-950 flex flex-col select-none">
                {/* Header */}
                <header className="bg-white dark:bg-slate-900 border-b border-gray-200 dark:border-slate-800 sticky top-0 z-50 shadow-sm h-16">
                    <div className="max-w-screen-2xl mx-auto px-4 h-full flex items-center justify-between">
                        <div className="flex items-center gap-4">
                            <div className="w-8 h-8 bg-blue-100 dark:bg-blue-900/30 rounded-lg flex items-center justify-center text-blue-600 dark:text-blue-400">
                                <FileText className="w-5 h-5" />
                            </div>
                            <div>
                                <h1 className="font-bold text-gray-800 dark:text-white text-sm md:text-base truncate max-w-[200px] md:max-w-md">
                                    {exam.title}
                                </h1>
                                {isRanked ? (
                                    <div className="flex items-center gap-1 text-xs text-green-600 dark:text-green-400 font-medium">
                                        <Shield className="w-3 h-3" />
                                        Tính xếp hạng
                                    </div>
                                ) : (
                                    <div className="flex items-center gap-1 text-xs text-gray-500 dark:text-gray-400">
                                        <AlertOctagon className="w-3 h-3" />
                                        Không xếp hạng
                                    </div>
                                )}
                            </div>
                        </div>

                        <div className="flex items-center gap-4">
                            {/* Timer */}
                            <div className={cn(
                                "flex items-center gap-2 px-4 py-2 rounded-full font-mono font-bold shadow-sm border transition-colors",
                                timeLeft <= 60
                                    ? "bg-red-50 border-red-100 text-red-600 dark:bg-red-900/20 dark:border-red-800 dark:text-red-400 animate-pulse"
                                    : timeLeft <= 300
                                        ? "bg-yellow-50 border-yellow-100 text-yellow-600 dark:bg-yellow-900/20 dark:border-yellow-800 dark:text-yellow-400"
                                        : "bg-white border-gray-100 text-blue-600 dark:bg-slate-800 dark:border-slate-700 dark:text-blue-400"
                            )}>
                                <Clock className="w-4 h-4" />
                                {formatTime(timeLeft)}
                            </div>

                            {/* Submit Button */}
                            <Button
                                onClick={() => setShowConfirm(true)}
                                disabled={submitting}
                                className="hidden md:flex bg-green-600 hover:bg-green-700 shadow-md shadow-green-200"
                            >
                                <Send className="w-4 h-4 mr-2" />
                                Nộp bài
                            </Button>
                        </div>
                    </div>
                </header>

                <main className="flex-1 flex flex-col lg:flex-row overflow-hidden">
                    {/* Left Panel: Review Materials / Question List */}
                    <div className="lg:w-1/2 flex flex-col p-4 overflow-hidden border-r border-gray-200 dark:border-slate-800 bg-white dark:bg-slate-900 shadow-sm z-10">
                        {exam.pdf_url ? (
                            <div className="flex-1 rounded-xl overflow-hidden border border-gray-100 dark:border-slate-700 flex flex-col bg-gray-50 dark:bg-slate-800">
                                <iframe
                                    src={`${exam.pdf_url}#page=${pdfPage}`}
                                    className="flex-1 w-full bg-white"
                                    title="Đề thi PDF"
                                />
                                <div className="p-2 bg-white dark:bg-slate-900 border-t border-gray-100 dark:border-slate-800 flex items-center justify-center gap-4">
                                    <Button
                                        variant="outline"
                                        size="sm"
                                        onClick={() => setPdfPage(p => Math.max(1, p - 1))}
                                        disabled={pdfPage <= 1}
                                        className="border-gray-200 dark:border-slate-700 text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-slate-800"
                                    >
                                        <ChevronLeft className="w-4 h-4" />
                                    </Button>
                                    <span className="text-sm font-medium text-gray-600 dark:text-gray-400">Trang {pdfPage}</span>
                                    <Button
                                        variant="outline"
                                        size="sm"
                                        onClick={() => setPdfPage(p => p + 1)}
                                        className="border-gray-200 dark:border-slate-700 text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-slate-800"
                                    >
                                        <ChevronRight className="w-4 h-4" />
                                    </Button>
                                </div>
                            </div>
                        ) : (
                            <div className="flex-1 flex flex-col items-center justify-center text-gray-400 dark:text-gray-500">
                                <div className="w-20 h-20 bg-gray-50 dark:bg-slate-800 rounded-full flex items-center justify-center mb-4">
                                    <FileText className="w-10 h-10 text-gray-300 dark:text-gray-600" />
                                </div>
                                <p className="font-medium text-gray-500 dark:text-gray-400">Không có file đề thi</p>
                                <p className="text-sm">Vui lòng đọc câu hỏi trực tiếp trên phiếu</p>
                            </div>
                        )}
                    </div>

                    {/* Right Panel: Answer Sheet */}
                    <div className="lg:w-1/2 flex flex-col bg-gray-50 dark:bg-slate-950 h-full overflow-hidden">
                        <div className="p-4 bg-white dark:bg-slate-900 border-b border-gray-200 dark:border-slate-800 shadow-sm z-20">
                            <div className="flex items-center justify-between mb-4">
                                <div>
                                    <h2 className="font-bold text-gray-800 dark:text-white text-lg">Phiếu trả lời</h2>
                                    <p className="text-sm text-gray-500 dark:text-gray-400">
                                        Đã hoàn thành <span className="font-medium text-blue-600 dark:text-blue-400">{answeredCount}</span>/{exam.total_questions} câu
                                    </p>
                                </div>
                                <div className="text-right">
                                    <div className="w-32 h-2 bg-gray-100 dark:bg-slate-700 rounded-full overflow-hidden">
                                        <div
                                            className="h-full bg-blue-500 transition-all duration-500"
                                            style={{ width: `${(answeredCount / exam.total_questions) * 100}%` }}
                                        />
                                    </div>
                                    <p className="text-xs text-gray-400 mt-1">Tiến độ làm bài</p>
                                </div>
                            </div>

                            {/* Answer Type Tabs */}
                            <div className="flex p-1 bg-gray-100 dark:bg-slate-800 rounded-lg">
                                <button
                                    onClick={() => setActiveTab("mc")}
                                    className={cn(
                                        "flex-1 py-2 text-sm font-medium rounded-md transition-all",
                                        activeTab === "mc" ? "bg-white dark:bg-slate-700 text-blue-600 dark:text-blue-400 shadow-sm" : "text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200"
                                    )}
                                >
                                    Trắc nghiệm
                                </button>
                                {exam.tf_questions && exam.tf_questions.length > 0 && (
                                    <button
                                        onClick={() => setActiveTab("tf")}
                                        className={cn(
                                            "flex-1 py-2 text-sm font-medium rounded-md transition-all",
                                            activeTab === "tf" ? "bg-white dark:bg-slate-700 text-green-600 dark:text-green-400 shadow-sm" : "text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200"
                                        )}
                                    >
                                        Đúng/Sai
                                    </button>
                                )}
                                {exam.sa_questions && exam.sa_questions.length > 0 && (
                                    <button
                                        onClick={() => setActiveTab("sa")}
                                        className={cn(
                                            "flex-1 py-2 text-sm font-medium rounded-md transition-all",
                                            activeTab === "sa" ? "bg-white dark:bg-slate-700 text-purple-600 dark:text-purple-400 shadow-sm" : "text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200"
                                        )}
                                    >
                                        Điền đáp án
                                    </button>
                                )}
                            </div>
                        </div>

                        <div className="flex-1 overflow-y-auto p-4 content-start">
                            {/* Multiple Choice Grid */}
                            {activeTab === "mc" && (
                                <div className="space-y-6">
                                    <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-4">
                                        {Array.from({ length: exam.mc_questions?.length || exam.total_questions }, (_, i) => (
                                            <div key={i} id={`q-${i}`} className="bg-white dark:bg-slate-900 p-3 rounded-lg border border-gray-100 dark:border-slate-800 shadow-sm hover:shadow-md transition-shadow">
                                                <div className="flex items-center justify-between mb-2">
                                                    <span className="text-sm font-bold text-gray-700 dark:text-gray-300">Câu {i + 1}</span>
                                                    {studentAnswers[i] && (
                                                        <span className="w-2 h-2 bg-blue-500 rounded-full"></span>
                                                    )}
                                                </div>
                                                <div className="grid grid-cols-4 gap-1">
                                                    {OPTIONS.map((option) => (
                                                        <button
                                                            key={option}
                                                            onClick={() => handleAnswerSelect(i, option)}
                                                            className={cn(
                                                                "h-8 rounded text-sm font-medium transition-all active:scale-95",
                                                                studentAnswers[i] === option
                                                                    ? "bg-blue-600 text-white shadow-blue-200 dark:shadow-none shadow"
                                                                    : "bg-gray-50 dark:bg-slate-800 text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-slate-700"
                                                            )}
                                                        >
                                                            {option}
                                                        </button>
                                                    ))}
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {/* True/False Grid */}
                            {activeTab === "tf" && exam.tf_questions && (
                                <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
                                    {exam.tf_questions.map((tf: { question: number }, i: number) => {
                                        const studentTf = tfStudentAnswers.find(a => a.question === tf.question) ||
                                            { question: tf.question, a: null, b: null, c: null, d: null }
                                        return (
                                            <div key={i} className="bg-white dark:bg-slate-900 p-4 rounded-lg border border-gray-100 dark:border-slate-800 shadow-sm">
                                                <div className="flex items-center justify-between mb-3 border-b border-gray-50 dark:border-slate-800 pb-2">
                                                    <span className="font-bold text-gray-700 dark:text-gray-300">Câu {tf.question}</span>
                                                </div>
                                                <div className="space-y-2">
                                                    {(['a', 'b', 'c', 'd'] as const).map((sub) => (
                                                        <div key={sub} className="flex items-center justify-between gap-2">
                                                            <span className="text-sm text-gray-500 font-medium uppercase w-4">{sub}</span>
                                                            <div className="flex gap-2 flex-1">
                                                                <button
                                                                    onClick={() => {
                                                                        const newTf = [...tfStudentAnswers]
                                                                        const idx = newTf.findIndex(a => a.question === tf.question)
                                                                        if (idx >= 0) newTf[idx] = { ...newTf[idx], [sub]: true }
                                                                        else newTf.push({ question: tf.question, a: null, b: null, c: null, d: null, [sub]: true })
                                                                        setTfStudentAnswers(newTf)
                                                                    }}
                                                                    className={cn(
                                                                        "flex-1 py-1 rounded text-xs font-medium transition-colors border",
                                                                        studentTf[sub] === true
                                                                            ? "bg-green-100 border-green-200 text-green-700"
                                                                            : "bg-white border-gray-200 text-gray-400 hover:border-gray-300"
                                                                    )}
                                                                >
                                                                    Đúng
                                                                </button>
                                                                <button
                                                                    onClick={() => {
                                                                        const newTf = [...tfStudentAnswers]
                                                                        const idx = newTf.findIndex(a => a.question === tf.question)
                                                                        if (idx >= 0) newTf[idx] = { ...newTf[idx], [sub]: false }
                                                                        else newTf.push({ question: tf.question, a: null, b: null, c: null, d: null, [sub]: false })
                                                                        setTfStudentAnswers(newTf)
                                                                    }}
                                                                    className={cn(
                                                                        "flex-1 py-1 rounded text-xs font-medium transition-colors border",
                                                                        studentTf[sub] === false
                                                                            ? "bg-red-100 border-red-200 text-red-700"
                                                                            : "bg-white border-gray-200 text-gray-400 hover:border-gray-300"
                                                                    )}
                                                                >
                                                                    Sai
                                                                </button>
                                                            </div>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        )
                                    })}
                                </div>
                            )}

                            {/* Short Answer Grid */}
                            {activeTab === "sa" && exam.sa_questions && (
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    {exam.sa_questions.map((sa: { question: number }, i: number) => {
                                        const studentSa = saStudentAnswers.find(a => a.question === sa.question)
                                        return (
                                            <div key={i} className="bg-white dark:bg-slate-900 p-4 rounded-lg border border-gray-100 dark:border-slate-800 shadow-sm">
                                                <div className="flex items-center gap-3 mb-2">
                                                    <span className="font-bold text-gray-700 dark:text-gray-300 w-16">Câu {sa.question}</span>
                                                    <input
                                                        type="text"
                                                        value={studentSa?.answer || ""}
                                                        onChange={(e) => {
                                                            const newSa = [...saStudentAnswers]
                                                            const idx = newSa.findIndex(a => a.question === sa.question)
                                                            if (idx >= 0) newSa[idx] = { ...newSa[idx], answer: e.target.value }
                                                            else newSa.push({ question: sa.question, answer: e.target.value })
                                                            setSaStudentAnswers(newSa)
                                                        }}
                                                        placeholder="Nhập đáp án của bạn..."
                                                        className="flex-1 px-3 py-2 bg-gray-50 dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-lg text-gray-900 dark:text-white text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white dark:focus:bg-slate-900 transition-all placeholder:text-gray-400"
                                                    />
                                                </div>
                                            </div>
                                        )
                                    })}
                                </div>
                            )}
                        </div>
                    </div>
                </main>

                {/* Mobile Submit FAB */}
                <div className="md:hidden fixed bottom-6 right-6 z-50">
                    <Button
                        onClick={() => setShowConfirm(true)}
                        size="icon"
                        className="h-14 w-14 rounded-full bg-green-600 hover:bg-green-700 shadow-lg shadow-green-300"
                    >
                        <Send className="w-6 h-6 ml-0.5" />
                    </Button>
                </div>

                {/* Confirm Dialog */}
                {showConfirm && (
                    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
                        <Card className="w-full max-w-sm bg-white dark:bg-slate-900 border-0 shadow-2xl">
                            <CardContent className="p-6">
                                <div className="flex flex-col items-center text-center mb-6">
                                    <div className="w-16 h-16 bg-blue-50 dark:bg-blue-900/20 rounded-full flex items-center justify-center mb-4">
                                        <FileText className="w-8 h-8 text-blue-600 dark:text-blue-400" />
                                    </div>
                                    <h3 className="text-xl font-bold text-gray-800 dark:text-white">Nộp bài thi?</h3>
                                    <p className="text-gray-500 dark:text-gray-400 mt-2">
                                        Bạn đã hoàn thành <span className="font-bold text-gray-800 dark:text-white">{answeredCount}/{exam.total_questions}</span> câu hỏi.
                                    </p>
                                    {answeredCount < exam.total_questions && (
                                        <div className="mt-4 px-4 py-2 bg-amber-50 dark:bg-amber-900/20 text-amber-700 dark:text-amber-400 text-sm font-medium rounded-lg border border-amber-100 dark:border-amber-900">
                                            ⚠️ Bạn còn {exam.total_questions - answeredCount} câu chưa làm
                                        </div>
                                    )}
                                </div>

                                <div className="grid grid-cols-2 gap-3">
                                    <Button
                                        variant="outline"
                                        onClick={() => setShowConfirm(false)}
                                        className="border-gray-200 dark:border-slate-700 text-gray-600 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-slate-800"
                                    >
                                        Làm tiếp
                                    </Button>
                                    <Button
                                        onClick={() => handleSubmit(false)}
                                        disabled={submitting}
                                        className="bg-green-600 hover:bg-green-700 text-white shadow-green-200 dark:shadow-none shadow-md"
                                    >
                                        {submitting ? (
                                            <>
                                                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                                                Đang nộp...
                                            </>
                                        ) : (
                                            "Nộp bài ngay"
                                        )}
                                    </Button>
                                </div>
                            </CardContent>
                        </Card>
                    </div>
                )}
            </div>
        </AntiCheatProvider>
    )
}

"use client"

import { useState, useEffect } from "react"
import { useRouter } from "next/navigation"
import Link from "next/link"
import { createClient } from "@/lib/supabase/client"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card"
import { Textarea } from "@/components/ui/textarea"
import {
    Plus,
    Swords,
    Calendar,
    Clock,
    Users,
    Edit,
    Trash2,
    Loader2,
    Play,
    Pause,
    CheckCircle,
    FileText,
    X,
    GraduationCap
} from "lucide-react"
import { EmptyState } from "@/components/shared"
import { TeacherSidebar } from "@/components/TeacherSidebar"
import { NotificationBell } from "@/components/NotificationBell"
import { UserMenu } from "@/components/UserMenu"
import { TeacherBottomNav } from "@/components/BottomNav"

interface ArenaSession {
    id: string
    name: string
    description: string | null
    exam_id: string | null
    start_time: string
    end_time: string
    duration: number
    status: string
    created_at: string
    participant_count?: number
    exam?: {
        id: string
        title: string
        subject: string
        total_questions: number
    }
}

interface Exam {
    id: string
    title: string
    subject: string
    total_questions: number
    created_at: string
}

export default function ArenaAdminPage() {
    const router = useRouter()
    const supabase = createClient()

    const [sessions, setSessions] = useState<ArenaSession[]>([])
    const [exams, setExams] = useState<Exam[]>([])
    const [loading, setLoading] = useState(true)
    const [showCreate, setShowCreate] = useState(false)
    const [saving, setSaving] = useState(false)
    const [fullName, setFullName] = useState("")

    // Form state
    const [name, setName] = useState("")
    const [description, setDescription] = useState("")
    const [examId, setExamId] = useState("")
    const [startTime, setStartTime] = useState("")
    const [endTime, setEndTime] = useState("")
    const [duration, setDuration] = useState(60)
    const [editingId, setEditingId] = useState<string | null>(null)

    useEffect(() => {
        fetchData()
    }, [])

    const fetchData = async () => {
        const { data: { user } } = await supabase.auth.getUser()
        if (!user) {
            router.push("/login")
            return
        }

        // Check if teacher and get profile
        const { data: profile } = await supabase
            .from("profiles")
            .select("role, full_name")
            .eq("id", user.id)
            .single()

        if (profile?.role !== "teacher") {
            router.push("/student/dashboard")
            return
        }

        setFullName(profile.full_name || "")

        // Fetch exams for dropdown
        const { data: examsData } = await supabase
            .from("exams")
            .select("id, title, subject, total_questions, created_at")
            .eq("created_by", user.id)
            .order("created_at", { ascending: false })

        if (examsData) {
            setExams(examsData)
        }

        // Fetch sessions with exam info and participant count
        const { data: sessionsData } = await supabase
            .from("arena_sessions")
            .select(`
                *,
                arena_results(count),
                exams:exam_id (id, title, subject, total_questions)
            `)
            .eq("created_by", user.id)
            .order("created_at", { ascending: false })

        if (sessionsData) {
            const formatted = sessionsData.map((s: { id: string, name: string, description: string | null, exam_id: string | null, start_time: string, end_time: string, duration: number, status: string, created_at: string, arena_results: { count: number }[], exams: Exam }) => ({
                ...s,
                participant_count: s.arena_results?.[0]?.count || 0,
                exam: s.exams
            }))
            setSessions(formatted)
        }

        setLoading(false)
    }

    const resetForm = () => {
        setName("")
        setDescription("")
        setExamId("")
        setStartTime("")
        setEndTime("")
        setDuration(60)
        setEditingId(null)
    }

    const handleEdit = (session: ArenaSession) => {
        setEditingId(session.id)
        setName(session.name)
        setDescription(session.description || "")
        setExamId(session.exam_id || "")
        setStartTime(session.start_time.slice(0, 16))
        setEndTime(session.end_time.slice(0, 16))
        setDuration(session.duration)
        setShowCreate(true)
    }

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()

        if (!name || !examId || !startTime || !endTime) {
            alert("Vui lòng nhập đầy đủ thông tin và chọn đề thi")
            return
        }

        setSaving(true)

        try {
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) throw new Error("Not authenticated")

            const data = {
                name,
                description: description || null,
                exam_id: examId,
                start_time: new Date(startTime).toISOString(),
                end_time: new Date(endTime).toISOString(),
                duration,
                status: "active",
                created_by: user.id
            }

            if (editingId) {
                const { error } = await supabase
                    .from("arena_sessions")
                    .update(data)
                    .eq("id", editingId)

                if (error) throw error
            } else {
                const { error } = await supabase
                    .from("arena_sessions")
                    .insert(data)

                if (error) throw error
            }

            await fetchData()
            setShowCreate(false)
            resetForm()
        } catch (err) {
            alert("Lỗi: " + (err as Error).message)
        } finally {
            setSaving(false)
        }
    }

    const handleDelete = async (id: string) => {
        if (!confirm("Xóa đợt thi này? Tất cả kết quả sẽ bị xóa.")) return

        const { error } = await supabase
            .from("arena_sessions")
            .delete()
            .eq("id", id)

        if (error) {
            alert("Lỗi xóa: " + error.message)
            return
        }

        await fetchData()
    }

    const getStatusBadge = (session: ArenaSession) => {
        const now = new Date()
        const start = new Date(session.start_time)
        const end = new Date(session.end_time)

        if (now < start) {
            return (
                <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 dark:bg-blue-900/30 text-blue-800 dark:text-blue-300">
                    <Clock className="w-3 h-3 mr-1" />
                    Sắp diễn ra
                </span>
            )
        } else if (now >= start && now <= end) {
            return (
                <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 dark:bg-green-900/30 text-green-800 dark:text-green-300 animate-pulse">
                    <Play className="w-3 h-3 mr-1" />
                    Đang diễn ra
                </span>
            )
        } else {
            return (
                <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-gray-100 dark:bg-slate-800 text-gray-800 dark:text-gray-300">
                    <CheckCircle className="w-3 h-3 mr-1" />
                    Đã kết thúc
                </span>
            )
        }
    }

    if (loading) {
        return (
            <div className="min-h-screen bg-gray-50 dark:bg-slate-900 flex items-center justify-center">
                <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
            </div>
        )
    }

    const handleLogout = async () => {
        await supabase.auth.signOut()
        router.push("/login")
    }

    return (
        <div className="min-h-screen bg-gray-50 dark:bg-slate-900 flex">
            {/* Sidebar */}
            <TeacherSidebar onLogout={handleLogout} />

            {/* Mobile Header */}
            <header className="lg:hidden fixed top-0 w-full z-50 bg-white dark:bg-slate-800 border-b border-gray-200 dark:border-slate-700 px-4 h-16 flex items-center justify-between">
                <div className="flex items-center gap-2">
                    <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center">
                        <GraduationCap className="w-4 h-4 text-white" />
                    </div>
                    <span className="text-lg font-bold text-gray-800 dark:text-white">ExamHub</span>
                </div>
                <div className="flex items-center gap-2">
                    <NotificationBell />
                    <UserMenu userName={fullName} userClass="Giáo viên" onLogout={handleLogout} role="teacher" />
                </div>
            </header>

            {/* Main Content */}
            <main className="flex-1 lg:ml-64 p-4 lg:p-8 pt-20 lg:pt-8 pb-24 lg:pb-8">
                {/* Desktop Header */}
                <div className="hidden lg:flex items-center justify-between mb-8">
                    <div>
                        <h1 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
                            <Swords className="w-6 h-6 text-purple-600" />
                            Quản lý Đấu trường
                        </h1>
                        <p className="text-gray-500 dark:text-gray-400">Tạo và quản lý các đợt thi tập trung</p>
                    </div>
                    <div className="flex items-center gap-4">
                        <Button
                            onClick={() => {
                                resetForm()
                                setShowCreate(true)
                            }}
                            className="bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-700 hover:to-indigo-700 text-white shadow-sm"
                        >
                            <Plus className="w-4 h-4 mr-2" />
                            Tạo đợt thi
                        </Button>
                        <NotificationBell />
                        <UserMenu userName={fullName} userClass="Giáo viên" onLogout={handleLogout} role="teacher" />
                    </div>
                </div>

                {/* Add button for mobile */}
                <div className="lg:hidden mb-4">
                    <Button
                        onClick={() => {
                            resetForm()
                            setShowCreate(true)
                        }}
                        className="w-full bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-700 hover:to-indigo-700 text-white shadow-sm"
                    >
                        <Plus className="w-4 h-4 mr-2" />
                        Tạo đợt thi
                    </Button>
                </div>


                {/* Sessions List */}
                {sessions.length === 0 ? (
                    <EmptyState
                        icon={Swords}
                        title="Chưa có đợt thi nào"
                        description="Tạo đợt thi mới để tổ chức thi đấu cho học sinh"
                        actionLabel="Tạo đợt thi đầu tiên"
                        onAction={() => setShowCreate(true)}
                        iconColor="text-purple-500"
                        iconBgColor="bg-purple-50 dark:bg-purple-900/20"
                    />
                ) : (
                    <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
                        {sessions.map(session => (
                            <Card key={session.id} className="border-gray-200 dark:border-slate-800 shadow-sm bg-white dark:bg-slate-900 hover:shadow-md transition-shadow group">
                                <CardHeader className="pb-3 border-b border-gray-50 dark:border-slate-800">
                                    <div className="flex items-start justify-between mb-2">
                                        <div className="space-y-1">
                                            <CardTitle className="text-lg font-bold text-gray-800 dark:text-white line-clamp-1" title={session.name}>
                                                {session.name}
                                            </CardTitle>
                                            {session.exam && (
                                                <div className="flex items-center text-xs text-purple-600 dark:text-purple-400 font-medium bg-purple-50 dark:bg-purple-900/20 px-2 py-0.5 rounded w-fit">
                                                    <FileText className="w-3 h-3 mr-1" />
                                                    {session.exam.title}
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                    <div className="flex justify-between items-center mt-2">
                                        {getStatusBadge(session)}
                                    </div>
                                </CardHeader>
                                <CardContent className="pt-4 space-y-4">
                                    <div className="space-y-2 text-sm text-gray-600 dark:text-gray-400">
                                        <div className="flex items-center gap-2">
                                            <Calendar className="w-4 h-4 text-gray-400" />
                                            <span>
                                                {new Date(session.start_time).toLocaleDateString("vi-VN", {
                                                    day: "2-digit",
                                                    month: "2-digit",
                                                    hour: "2-digit",
                                                    minute: "2-digit"
                                                })}
                                            </span>
                                        </div>
                                        <div className="flex items-center gap-2">
                                            <Clock className="w-4 h-4 text-gray-400" />
                                            <span>{session.duration} phút</span>
                                        </div>
                                        <div className="flex items-center gap-2">
                                            <Users className="w-4 h-4 text-gray-400" />
                                            <span className="font-medium text-gray-900 dark:text-white">{session.participant_count || 0}</span>
                                            <span>người tham gia</span>
                                        </div>
                                    </div>

                                    <div className="flex gap-2 pt-2">
                                        <Button
                                            variant="outline"
                                            size="sm"
                                            onClick={() => handleEdit(session)}
                                            className="flex-1 border-gray-200 dark:border-slate-700 text-gray-600 dark:text-gray-400 hover:bg-blue-50 dark:hover:bg-blue-900/20 hover:text-blue-600 dark:hover:text-blue-400 hover:border-blue-200 dark:hover:border-blue-800"
                                        >
                                            <Edit className="w-4 h-4 mr-1" />
                                            Sửa
                                        </Button>
                                        <Button
                                            variant="outline"
                                            size="sm"
                                            onClick={() => handleDelete(session.id)}
                                            className="flex-1 border-gray-200 dark:border-slate-700 text-gray-600 dark:text-gray-400 hover:bg-red-50 dark:hover:bg-red-900/20 hover:text-red-600 dark:hover:text-red-400 hover:border-red-200 dark:hover:border-red-800"
                                        >
                                            <Trash2 className="w-4 h-4 mr-1" />
                                            Xóa
                                        </Button>
                                    </div>
                                </CardContent>
                            </Card>
                        ))}
                    </div>
                )}

                {/* Create/Edit Modal */}
                {showCreate && (
                    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center z-50 p-4 animate-in fade-in duration-200">
                        <Card className="w-full max-w-lg border-gray-200 dark:border-slate-700 bg-white dark:bg-slate-800 shadow-xl">
                            <CardHeader className="flex flex-row items-center justify-between border-b border-gray-100 dark:border-slate-700 pb-4">
                                <CardTitle className="text-gray-800 dark:text-white text-xl">
                                    {editingId ? "Cập nhật đợt thi" : "Tạo đợt thi mới"}
                                </CardTitle>
                                <Button
                                    variant="ghost"
                                    size="icon"
                                    onClick={() => {
                                        setShowCreate(false)
                                        resetForm()
                                    }}
                                    className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 hover:bg-gray-100 dark:hover:bg-slate-700 -mr-2"
                                >
                                    <X className="w-5 h-5" />
                                </Button>
                            </CardHeader>
                            <CardContent className="pt-6">
                                <form onSubmit={handleSubmit} className="space-y-5">
                                    <div className="space-y-2">
                                        <Label className="text-gray-700 dark:text-gray-300 font-medium">Tên đợt thi <span className="text-red-500">*</span></Label>
                                        <Input
                                            value={name}
                                            onChange={(e) => setName(e.target.value)}
                                            placeholder="VD: Kiểm tra Toán 15 phút - Lớp 12A"
                                            className="bg-white dark:bg-slate-900 border-gray-300 dark:border-slate-600 focus:ring-purple-500 focus:border-purple-500 text-gray-900 dark:text-white"
                                            required
                                        />
                                    </div>

                                    <div className="space-y-2">
                                        <Label className="text-gray-700 dark:text-gray-300 font-medium">Chọn đề thi <span className="text-red-500">*</span></Label>
                                        <select
                                            value={examId}
                                            onChange={(e) => setExamId(e.target.value)}
                                            className="w-full px-3 py-2 rounded-md border border-gray-300 dark:border-slate-600 text-sm focus:outline-none focus:ring-2 focus:ring-purple-500 focus:border-purple-500 bg-white dark:bg-slate-900 text-gray-900 dark:text-white"
                                            required
                                        >
                                            <option value="">-- Chọn đề thi --</option>
                                            {exams.map(exam => (
                                                <option key={exam.id} value={exam.id}>
                                                    {exam.title} ({exam.total_questions} câu - {exam.subject})
                                                </option>
                                            ))}
                                        </select>
                                        {exams.length === 0 && (
                                            <p className="text-sm text-yellow-600 bg-yellow-50 p-2 rounded border border-yellow-200">
                                                ⚠ Bạn chưa có đề thi nào. <Link href="/teacher/exams/create" className="underline font-medium hover:text-yellow-800">Tạo ngay</Link>
                                            </p>
                                        )}
                                    </div>

                                    <div className="space-y-2">
                                        <Label className="text-gray-700 dark:text-gray-300 font-medium">Mô tả</Label>
                                        <Textarea
                                            value={description}
                                            onChange={(e) => setDescription(e.target.value)}
                                            placeholder="Thông tin thêm về đợt thi..."
                                            className="bg-white dark:bg-slate-900 border-gray-300 dark:border-slate-600 focus:ring-purple-500 focus:border-purple-500 resize-none text-gray-900 dark:text-white"
                                            rows={3}
                                        />
                                    </div>

                                    <div className="grid grid-cols-2 gap-4">
                                        <div className="space-y-2">
                                            <Label className="text-gray-700 dark:text-gray-300 font-medium">Bắt đầu <span className="text-red-500">*</span></Label>
                                            <Input
                                                type="datetime-local"
                                                value={startTime}
                                                onChange={(e) => setStartTime(e.target.value)}
                                                className="bg-white dark:bg-slate-900 border-gray-300 dark:border-slate-600 focus:ring-purple-500 focus:border-purple-500 text-gray-900 dark:text-white"
                                                required
                                            />
                                        </div>
                                        <div className="space-y-2">
                                            <Label className="text-gray-700 dark:text-gray-300 font-medium">Kết thúc <span className="text-red-500">*</span></Label>
                                            <Input
                                                type="datetime-local"
                                                value={endTime}
                                                onChange={(e) => setEndTime(e.target.value)}
                                                className="bg-white dark:bg-slate-900 border-gray-300 dark:border-slate-600 focus:ring-purple-500 focus:border-purple-500 text-gray-900 dark:text-white"
                                                required
                                            />
                                        </div>
                                    </div>

                                    <div className="space-y-2">
                                        <Label className="text-gray-700 dark:text-gray-300 font-medium">Thời gian làm bài (phút)</Label>
                                        <div className="relative">
                                            <Input
                                                type="number"
                                                value={duration}
                                                onChange={(e) => setDuration(Number(e.target.value))}
                                                min={5}
                                                max={180}
                                                className="bg-white dark:bg-slate-900 border-gray-300 dark:border-slate-600 focus:ring-purple-500 focus:border-purple-500 pl-10 text-gray-900 dark:text-white"
                                            />
                                            <Clock className="w-4 h-4 text-gray-400 absolute left-3 top-3" />
                                        </div>
                                    </div>

                                    <div className="flex gap-3 pt-4 font-medium">
                                        <Button
                                            type="button"
                                            variant="outline"
                                            onClick={() => {
                                                setShowCreate(false)
                                                resetForm()
                                            }}
                                            className="flex-1 border-gray-300 dark:border-slate-600 text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-slate-700"
                                        >
                                            Hủy
                                        </Button>
                                        <Button
                                            type="submit"
                                            disabled={saving}
                                            className="flex-1 bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-700 hover:to-indigo-700 text-white"
                                        >
                                            {saving ? (
                                                <Loader2 className="w-4 h-4 animate-spin mr-2" />
                                            ) : editingId ? (
                                                "Cập nhật"
                                            ) : (
                                                <><Plus className="w-4 h-4 mr-2" /> Tạo đợt thi</>
                                            )}
                                        </Button>
                                    </div>
                                </form>
                            </CardContent>
                        </Card>
                    </div>
                )
                }
            </main>

            {/* Mobile Bottom Nav */}
            <TeacherBottomNav />
        </div>
    )
}

"use client"

import { useState, useEffect, useRef } from "react"
import { useRouter } from "next/navigation"
import Link from "next/link"
import { createClient } from "@/lib/supabase/client"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card"
import { Textarea } from "@/components/ui/textarea"
import {
    Plus,
    FileText,
    Upload,
    Trash2,
    Loader2,
    Eye,
    Calendar,
    HelpCircle,
    X,
    CheckCircle,
    AlertTriangle,
    Sparkles,
    Wand2,
    GraduationCap
} from "lucide-react"
import { FilterBar, EmptyState } from "@/components/shared"
import { TeacherSidebar } from "@/components/TeacherSidebar"
import { NotificationBell } from "@/components/NotificationBell"
import { UserMenu } from "@/components/UserMenu"
import { TeacherBottomNav } from "@/components/BottomNav"

interface ExamInBank {
    id: string
    title: string
    subject: string
    description: string | null
    pdf_url: string | null
    answer_key: string | null // JSON string of answers
    total_questions: number
    created_at: string
    questions?: Array<{ question: string, options: string[], answer: string }> // Parsed from AI or manual input
}

const SUBJECTS = [
    { value: "math", label: "Toán" },
    { value: "physics", label: "Vật Lý" },
    { value: "chemistry", label: "Hóa Học" },
    { value: "english", label: "Tiếng Anh" },
    { value: "biology", label: "Sinh Học" },
    { value: "history", label: "Lịch Sử" },
    { value: "geography", label: "Địa Lý" },
    { value: "et", label: "Giáo dục kinh tế & pháp luật" },
]

// Python worker URL for AI extraction
const WORKER_URL = process.env.NEXT_PUBLIC_WORKER_URL || "http://localhost:8000"

export default function ExamBankPage() {
    const router = useRouter()
    const supabase = createClient()
    const fileInputRef = useRef<HTMLInputElement>(null)
    const answerPdfRef = useRef<HTMLInputElement>(null)
    const [fullName, setFullName] = useState("")

    const [exams, setExams] = useState<ExamInBank[]>([])
    const [loading, setLoading] = useState(true)
    const [showCreate, setShowCreate] = useState(false)
    const [saving, setSaving] = useState(false)
    const [uploadingPdf, setUploadingPdf] = useState(false)

    // AI Scan state
    const [answerPdfFile, setAnswerPdfFile] = useState<File | null>(null)
    const [scanning, setScanning] = useState(false)
    const [scanResult, setScanResult] = useState<{ multiple_choice?: string[], true_false?: string[] } | null>(null)

    // Form state
    const [title, setTitle] = useState("")
    const [subject, setSubject] = useState("physics")
    const [description, setDescription] = useState("")
    const [pdfFile, setPdfFile] = useState<File | null>(null)
    const [pdfUrl, setPdfUrl] = useState("")
    const [answerKey, setAnswerKey] = useState("") // Format: 1A,2B,3C,...
    const [totalQuestions, setTotalQuestions] = useState(30)
    const [editingId, setEditingId] = useState<string | null>(null)

    // Preview
    const [previewExam, setPreviewExam] = useState<ExamInBank | null>(null)

    useEffect(() => {
        fetchExams()
    }, [])

    const fetchExams = async () => {
        const { data: { user } } = await supabase.auth.getUser()
        if (!user) {
            router.push("/login")
            return
        }

        const { data: profile } = await supabase
            .from("profiles")
            .select("full_name")
            .eq("id", user.id)
            .single()

        if (profile) setFullName(profile.full_name || "")

        // Use existing exams table
        const { data: examsData } = await supabase
            .from("exams")
            .select("*")
            .eq("created_by", user.id)
            .order("created_at", { ascending: false })

        if (examsData) {
            setExams(examsData.map((e: { id: string, title: string, subject: string, description: string | null, pdf_url: string | null, answer_key: string | null, total_questions: number, created_at: string, questions: Array<{ question: string, options: string[], answer: string }> }) => ({
                id: e.id,
                title: e.title,
                subject: e.subject || "physics",
                description: e.description,
                pdf_url: e.pdf_url,
                answer_key: e.answer_key,
                total_questions: e.total_questions || 0,
                created_at: e.created_at,
                questions: e.questions
            })))
        }

        setLoading(false)
    }

    const resetForm = () => {
        setTitle("")
        setSubject("physics")
        setDescription("")
        setPdfFile(null)
        setPdfUrl("")
        setAnswerKey("")
        setTotalQuestions(30)
        setEditingId(null)
        setAnswerPdfFile(null)
        setScanResult(null)
    }

    // AI Scan answer key from PDF
    const handleAIScan = async () => {
        if (!answerPdfFile) {
            alert("Vui lòng chọn file PDF đáp án")
            return
        }

        setScanning(true)
        setScanResult(null)

        try {
            const formData = new FormData()
            formData.append("file", answerPdfFile)

            const response = await fetch(`${WORKER_URL}/extract-answers`, {
                method: "POST",
                body: formData
            })

            if (!response.ok) {
                throw new Error(`HTTP ${response.status}`)
            }

            const data = await response.json()
            console.log("AI Scan result:", data)
            setScanResult(data)

            // Convert to answer key format: 1A,2B,3C,...
            if (data.multiple_choice && data.multiple_choice.length > 0) {
                const answerStr = data.multiple_choice
                    .map((ans: string, idx: number) => `${idx + 1}${ans}`)
                    .join(",")
                setAnswerKey(answerStr)
                setTotalQuestions(data.multiple_choice.length)
            }
        } catch (err) {
            console.error("AI Scan error:", err)
            alert("Lỗi quét AI: " + (err as Error).message + "\n\nĐảm bảo Python worker đang chạy!")
        } finally {
            setScanning(false)
        }
    }

    const handleEdit = (exam: ExamInBank) => {
        setEditingId(exam.id)
        setTitle(exam.title)
        setSubject(exam.subject)
        setDescription(exam.description || "")
        setPdfUrl(exam.pdf_url || "")
        setAnswerKey(exam.answer_key || "")
        setTotalQuestions(exam.total_questions)
        setShowCreate(true)
    }

    const handlePdfUpload = async () => {
        if (!pdfFile) return

        setUploadingPdf(true)
        try {
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) throw new Error("Not authenticated")

            const fileName = `${user.id}/${Date.now()}_${pdfFile.name}`
            const { error } = await supabase.storage
                .from("exams")
                .upload(fileName, pdfFile)

            if (error) throw error

            const { data: urlData } = supabase.storage
                .from("exams")
                .getPublicUrl(fileName)

            setPdfUrl(urlData.publicUrl)
        } catch (err) {
            alert("Lỗi upload PDF: " + (err as Error).message)
        } finally {
            setUploadingPdf(false)
        }
    }

    const parseAnswerKey = (input: string): Record<number, string> => {
        // Parse format: 1A,2B,3C,4D or 1.A,2.B or 1-A,2-B
        const result: Record<number, string> = {}
        const parts = input.split(/[,;\s]+/).filter(Boolean)

        for (const part of parts) {
            const match = part.match(/(\d+)[.\-]?([A-Da-d])/)
            if (match) {
                result[parseInt(match[1])] = match[2].toUpperCase()
            }
        }
        return result
    }

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()

        if (!title) {
            alert("Vui lòng nhập tên đề thi")
            return
        }

        setSaving(true)

        try {
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) throw new Error("Not authenticated")

            // Parse answer key to create questions array
            const parsedAnswers = parseAnswerKey(answerKey)
            const questions = Object.entries(parsedAnswers).map(([num, ans]) => ({
                question: `Câu ${num}`,
                options: ["A", "B", "C", "D"],
                answer: ans
            }))

            const data = {
                title,
                subject,
                description: description || null,
                pdf_url: pdfUrl || null,
                answer_key: answerKey || null,
                total_questions: totalQuestions,
                questions: questions.length > 0 ? questions : null,
                status: "published",
                created_by: user.id
            }

            if (editingId) {
                const { error } = await supabase
                    .from("exams")
                    .update(data)
                    .eq("id", editingId)

                if (error) throw error
            } else {
                const { error } = await supabase
                    .from("exams")
                    .insert(data)

                if (error) throw error
            }

            await fetchExams()
            setShowCreate(false)
            resetForm()
        } catch (err) {
            alert("Lỗi: " + (err as Error).message)
        } finally {
            setSaving(false)
        }
    }

    const handleDelete = async (id: string) => {
        const examToDelete = exams.find(e => e.id === id)
        if (!confirm(`Xóa đề thi "${examToDelete?.title}"?`)) return

        // Get students who submitted this exam
        const { data: submissions } = await supabase
            .from("submissions")
            .select("student_id")
            .eq("exam_id", id)

        // Send notifications to students
        if (submissions && submissions.length > 0) {
            const studentIds = [...new Set(submissions.map((s: { student_id: string }) => s.student_id))]
            const notifications = studentIds.map(studentId => ({
                user_id: studentId,
                type: "exam_deleted",
                title: "Đề thi đã bị xóa",
                message: `Đề thi "${examToDelete?.title}" đã bị giáo viên xóa khỏi hệ thống.`,
                is_read: false
            }))
            await supabase.from("notifications").insert(notifications)
        }

        const { error } = await supabase
            .from("exams")
            .delete()
            .eq("id", id)

        if (error) {
            alert("Lỗi xóa: " + error.message)
            return
        }

        await fetchExams()
    }


    if (loading) {
        return (
            <div className="min-h-screen bg-gray-50 dark:bg-slate-900 flex items-center justify-center">
                <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
            </div>
        )
    }

    const handleLogout = async () => {
        await supabase.auth.signOut()
        router.push("/login")
    }

    return (
        <div className="min-h-screen bg-gray-50 dark:bg-slate-900 flex">
            {/* Sidebar */}
            <TeacherSidebar onLogout={handleLogout} />

            {/* Mobile Header */}
            <header className="lg:hidden fixed top-0 w-full z-50 bg-white dark:bg-slate-800 border-b border-gray-200 dark:border-slate-700 px-4 h-16 flex items-center justify-between">
                <div className="flex items-center gap-2">
                    <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center">
                        <GraduationCap className="w-4 h-4 text-white" />
                    </div>
                    <span className="text-lg font-bold text-gray-800 dark:text-white">ExamHub</span>
                </div>
                <div className="flex items-center gap-2">
                    <NotificationBell />
                    <UserMenu userName={fullName} userClass="Giáo viên" onLogout={handleLogout} role="teacher" />
                </div>
            </header>

            {/* Main Content */}
            <main className="flex-1 lg:ml-64 p-4 lg:p-8 pt-20 lg:pt-8 pb-24 lg:pb-8">
                {/* Desktop Header */}
                <div className="hidden lg:flex items-center justify-between mb-8">
                    <div>
                        <h1 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
                            <FileText className="w-6 h-6 text-blue-600" />
                            Ngân hàng Đề thi
                        </h1>
                        <p className="text-gray-500 dark:text-gray-400">Lưu trữ và quản lý đề thi của bạn</p>
                    </div>
                    <div className="flex items-center gap-4">
                        <Button
                            onClick={() => {
                                resetForm()
                                setShowCreate(true)
                            }}
                            className="bg-blue-600 hover:bg-blue-700 text-white shadow-sm"
                        >
                            <Plus className="w-4 h-4 mr-2" />
                            Thêm đề thi
                        </Button>
                        <NotificationBell />
                        <UserMenu userName={fullName} userClass="Giáo viên" onLogout={handleLogout} role="teacher" />
                    </div>
                </div>

                {/* Add button for mobile */}
                <div className="lg:hidden mb-4">
                    <Button
                        onClick={() => {
                            resetForm()
                            setShowCreate(true)
                        }}
                        className="w-full bg-blue-600 hover:bg-blue-700 text-white shadow-sm"
                    >
                        <Plus className="w-4 h-4 mr-2" />
                        Thêm đề thi
                    </Button>
                </div>

                {/* Filters */}
                <FilterBar
                    searchPlaceholder="Tìm kiếm đề thi..."
                    showFilter={false}
                    className="mb-6"
                />

                {/* Exams Grid */}
                {exams.length === 0 ? (
                    <EmptyState
                        icon={FileText}
                        title="Chưa có đề thi nào"
                        description="Tạo đề thi đầu tiên bằng cách upload PDF và đáp án"
                        actionLabel="Thêm đề thi đầu tiên"
                        onAction={() => setShowCreate(true)}
                        iconColor="text-blue-500"
                        iconBgColor="bg-blue-50 dark:bg-blue-900/30"
                    />
                ) : (
                    <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
                        {exams.map(exam => (
                            <Card key={exam.id} className="border-gray-200 dark:border-slate-800 shadow-sm bg-white dark:bg-slate-800 hover:shadow-md transition-all group">
                                <CardHeader className="pb-3 border-b border-gray-50 dark:border-slate-700">
                                    <div className="flex items-start justify-between mb-2">
                                        <CardTitle className="text-lg font-bold text-gray-800 dark:text-white line-clamp-1" title={exam.title}>
                                            {exam.title}
                                        </CardTitle>
                                        {exam.pdf_url ? (
                                            <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-green-50 text-green-700 border border-green-100">
                                                <CheckCircle className="w-3 h-3 mr-1" />
                                                PDF
                                            </span>
                                        ) : (
                                            <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-yellow-50 text-yellow-700 border border-yellow-100">
                                                <AlertTriangle className="w-3 h-3 mr-1" />
                                                No PDF
                                            </span>
                                        )}
                                    </div>
                                    <p className="text-sm font-medium text-blue-600 bg-blue-50 px-2 py-0.5 rounded w-fit">
                                        {SUBJECTS.find(s => s.value === exam.subject)?.label || exam.subject}
                                    </p>
                                </CardHeader>
                                <CardContent className="pt-4 space-y-4">
                                    <div className="space-y-2 text-sm text-gray-600 dark:text-gray-400">
                                        <div className="flex items-center gap-2">
                                            <HelpCircle className="w-4 h-4 text-gray-400" />
                                            <span>{exam.total_questions} câu hỏi</span>
                                        </div>
                                        <div className="flex items-center gap-2">
                                            <Calendar className="w-4 h-4 text-gray-400" />
                                            <span>{new Date(exam.created_at).toLocaleDateString("vi-VN")}</span>
                                        </div>
                                    </div>

                                    <div className="flex gap-2 pt-2 border-t border-gray-50">
                                        {exam.pdf_url && (
                                            <Button
                                                variant="outline"
                                                size="sm"
                                                onClick={() => setPreviewExam(exam)}
                                                className="flex-1 border-gray-200 text-blue-600 hover:bg-blue-50 hover:border-blue-200"
                                            >
                                                <Eye className="w-4 h-4 mr-1" />
                                                Xem
                                            </Button>
                                        )}
                                        <Button
                                            variant="outline"
                                            size="sm"
                                            onClick={() => handleEdit(exam)}
                                            className="flex-1 border-gray-200 dark:border-slate-700 text-gray-600 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-slate-700"
                                        >
                                            Sửa
                                        </Button>
                                        <Button
                                            variant="outline"
                                            size="sm"
                                            onClick={() => handleDelete(exam.id)}
                                            className="border-gray-200 dark:border-slate-700 text-gray-600 dark:text-gray-300 hover:bg-red-50 dark:hover:bg-red-900/20 hover:text-red-600 dark:hover:text-red-400 hover:border-red-200 dark:hover:border-red-900"
                                        >
                                            <Trash2 className="w-4 h-4" />
                                        </Button>
                                    </div>
                                </CardContent>
                            </Card>
                        ))}
                    </div>
                )}

                {/* Create/Edit Modal */}
                {showCreate && (
                    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center z-50 p-4 animate-in fade-in duration-200 overflow-y-auto">
                        <Card className="w-full max-w-2xl border-gray-200 dark:border-slate-800 bg-white dark:bg-slate-900 shadow-xl my-8">
                            <CardHeader className="flex flex-row items-center justify-between border-b border-gray-100 dark:border-slate-800 pb-4">
                                <CardTitle className="text-gray-800 dark:text-white text-xl">
                                    {editingId ? "Cập nhật đề thi" : "Thêm đề thi mới"}
                                </CardTitle>
                                <Button
                                    variant="ghost"
                                    size="icon"
                                    onClick={() => {
                                        setShowCreate(false)
                                        resetForm()
                                    }}
                                    className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-200 hover:bg-gray-100 dark:hover:bg-slate-800 -mr-2"
                                >
                                    <X className="w-5 h-5" />
                                </Button>
                            </CardHeader>
                            <CardContent className="pt-6">
                                <form onSubmit={handleSubmit} className="space-y-6">
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                        <div className="space-y-2">
                                            <Label className="text-gray-700 dark:text-gray-300 font-medium">Tên đề thi <span className="text-red-500">*</span></Label>
                                            <Input
                                                value={title}
                                                onChange={(e) => setTitle(e.target.value)}
                                                placeholder="VD: Đề thi HK1 Vật Lý 12"
                                                className="bg-white dark:bg-slate-800 border-gray-300 dark:border-slate-700 focus:ring-blue-500 focus:border-blue-500 text-gray-900 dark:text-white"
                                                required
                                            />
                                        </div>
                                        <div className="space-y-2">
                                            <Label className="text-gray-700 dark:text-gray-300 font-medium">Môn học</Label>
                                            <select
                                                value={subject}
                                                onChange={(e) => setSubject(e.target.value)}
                                                className="w-full px-3 py-2 rounded-md border border-gray-300 dark:border-slate-700 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500 bg-white dark:bg-slate-800 text-gray-900 dark:text-white"
                                            >
                                                {SUBJECTS.map(s => (
                                                    <option key={s.value} value={s.value}>{s.label}</option>
                                                ))}
                                            </select>
                                        </div>
                                    </div>

                                    <div className="space-y-2">
                                        <Label className="text-gray-700 dark:text-gray-300 font-medium">Mô tả</Label>
                                        <Textarea
                                            value={description}
                                            onChange={(e) => setDescription(e.target.value)}
                                            placeholder="Mô tả chi tiết về đề thi..."
                                            className="bg-white dark:bg-slate-800 border-gray-300 dark:border-slate-700 focus:ring-blue-500 focus:border-blue-500 resize-none text-gray-900 dark:text-white"
                                            rows={2}
                                        />
                                    </div>

                                    {/* Upload Section */}
                                    <div className="grid grid-cols-1 gap-6">
                                        {/* Exam File */}
                                        <div className="p-4 bg-blue-50 dark:bg-blue-900/10 rounded-lg border border-blue-100 dark:border-blue-900/30">
                                            <Label className="text-blue-800 dark:text-blue-400 font-semibold flex items-center gap-2 mb-2">
                                                <FileText className="w-4 h-4" />
                                                File đề thi (PDF)
                                            </Label>
                                            <p className="text-xs text-blue-600 mb-3">
                                                File này sẽ được hiển thị cho học sinh khi làm bài.
                                            </p>
                                            <div className="flex gap-2">
                                                <Input
                                                    type="file"
                                                    accept=".pdf"
                                                    ref={fileInputRef}
                                                    onChange={(e) => setPdfFile(e.target.files?.[0] || null)}
                                                    className="bg-white dark:bg-slate-800 border-blue-200 dark:border-blue-800 text-gray-700 dark:text-gray-300 file:bg-blue-100 dark:file:bg-blue-900/30 file:text-blue-700 dark:file:text-blue-400 file:border-0 file:rounded-md file:px-2 file:py-1 file:mr-2 file:text-xs hover:file:bg-blue-200 dark:hover:file:bg-blue-900/50"
                                                />
                                                <Button
                                                    type="button"
                                                    onClick={handlePdfUpload}
                                                    disabled={!pdfFile || uploadingPdf}
                                                    className="bg-blue-600 hover:bg-blue-700 text-white min-w-[40px]"
                                                >
                                                    {uploadingPdf ? (
                                                        <Loader2 className="w-4 h-4 animate-spin" />
                                                    ) : (
                                                        <Upload className="w-4 h-4" />
                                                    )}
                                                </Button>
                                            </div>
                                            {pdfUrl && (
                                                <p className="text-sm text-green-600 mt-2 flex items-center">
                                                    <CheckCircle className="w-3 h-3 mr-1" />
                                                    Đã tải lên thành công: {pdfUrl.split('/').pop()}
                                                </p>
                                            )}
                                        </div>

                                        {/* Answer Key & AI Scan */}
                                        <div className="p-4 bg-purple-50 dark:bg-purple-900/10 rounded-lg border border-purple-100 dark:border-purple-900/30">
                                            <Label className="text-purple-800 dark:text-purple-400 font-semibold flex items-center gap-2 mb-2">
                                                <Wand2 className="w-4 h-4" />
                                                File đáp án & Quét AI
                                            </Label>
                                            <p className="text-xs text-purple-600 mb-3">
                                                Tải lên PDF đáp án để AI tự động trích xuất hoặc nhập tay bên dưới.
                                            </p>
                                            <div className="flex gap-2 mb-3">
                                                <Input
                                                    type="file"
                                                    accept=".pdf"
                                                    ref={answerPdfRef}
                                                    onChange={(e) => setAnswerPdfFile(e.target.files?.[0] || null)}
                                                    className="bg-white dark:bg-slate-800 border-purple-200 dark:border-purple-800 text-gray-700 dark:text-gray-300 file:bg-purple-100 dark:file:bg-purple-900/30 file:text-purple-700 dark:file:text-purple-400 file:border-0 file:rounded-md file:px-2 file:py-1 file:mr-2 file:text-xs hover:file:bg-purple-200 dark:hover:file:bg-purple-900/50"
                                                />
                                                <Button
                                                    type="button"
                                                    onClick={handleAIScan}
                                                    disabled={!answerPdfFile || scanning}
                                                    className="bg-purple-600 hover:bg-purple-700 text-white whitespace-nowrap"
                                                >
                                                    {scanning ? (
                                                        <>
                                                            <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                                                            Đang quét...
                                                        </>
                                                    ) : (
                                                        <>
                                                            <Sparkles className="w-4 h-4 mr-2" />
                                                            Quét AI
                                                        </>
                                                    )}
                                                </Button>
                                            </div>

                                            {scanResult && (
                                                <div className="text-sm space-y-1 mb-3 p-2 bg-white dark:bg-slate-800 rounded border border-purple-100 dark:border-purple-900">
                                                    <p className="text-green-600 dark:text-green-400 font-medium">
                                                        ✓ Tìm thấy: {scanResult.multiple_choice?.length || 0} câu trắc nghiệm
                                                    </p>
                                                    {scanResult.true_false && scanResult.true_false.length > 0 && (
                                                        <p className="text-blue-600 font-medium">
                                                            + {scanResult.true_false.length} câu đúng/sai
                                                        </p>
                                                    )}
                                                </div>
                                            )}

                                            <div className="space-y-2">
                                                <div className="flex justify-between">
                                                    <Label className="text-gray-700 dark:text-gray-300 font-medium text-xs">Chuỗi đáp án</Label>
                                                    <span className="text-xs text-gray-500 dark:text-gray-400">Định dạng: 1A,2B,3C...</span>
                                                </div>
                                                <Textarea
                                                    value={answerKey}
                                                    onChange={(e) => setAnswerKey(e.target.value)}
                                                    placeholder="1A,2B,3C,4D..."
                                                    className="bg-white dark:bg-slate-800 border-gray-300 dark:border-slate-700 font-mono text-sm text-gray-900 dark:text-white"
                                                    rows={3}
                                                />
                                            </div>
                                        </div>

                                        <div className="space-y-2">
                                            <Label className="text-gray-700 dark:text-gray-300 font-medium">Tổng số câu hỏi</Label>
                                            <Input
                                                type="number"
                                                value={totalQuestions}
                                                onChange={(e) => setTotalQuestions(Number(e.target.value))}
                                                min={1}
                                                max={200}
                                                className="bg-white dark:bg-slate-800 border-gray-300 dark:border-slate-700 text-gray-900 dark:text-white w-32"
                                            />
                                        </div>
                                    </div>

                                    <div className="flex gap-3 pt-4 border-t border-gray-100 dark:border-slate-800">
                                        <Button
                                            type="button"
                                            variant="outline"
                                            onClick={() => {
                                                setShowCreate(false)
                                                resetForm()
                                            }}
                                            className="flex-1 border-gray-300 dark:border-slate-700 text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-slate-800"
                                        >
                                            Hủy
                                        </Button>
                                        <Button
                                            type="submit"
                                            disabled={saving}
                                            className="flex-1 bg-blue-600 hover:bg-blue-700 text-white"
                                        >
                                            {saving ? (
                                                <Loader2 className="w-4 h-4 animate-spin mr-2" />
                                            ) : editingId ? (
                                                "Cập nhật"
                                            ) : (
                                                "Lưu đề thi"
                                            )}
                                        </Button>
                                    </div>
                                </form>
                            </CardContent>
                        </Card>
                    </div>
                )
                }

                {/* PDF Preview Modal */}
                {
                    previewExam && previewExam.pdf_url && (
                        <div className="fixed inset-0 bg-black/90 backdrop-blur-sm flex items-center justify-center z-50 p-4 animate-in fade-in duration-200">
                            <div className="w-full max-w-5xl h-[90vh] bg-white dark:bg-slate-900 rounded-lg overflow-hidden flex flex-col shadow-2xl">
                                <div className="flex items-center justify-between p-4 border-b border-gray-200 dark:border-slate-800 bg-gray-50 dark:bg-slate-800">
                                    <h3 className="text-gray-900 dark:text-white font-semibold text-lg">{previewExam.title}</h3>
                                    <Button
                                        variant="ghost"
                                        size="icon"
                                        onClick={() => setPreviewExam(null)}
                                        className="text-gray-500 hover:bg-gray-200 rounded-full"
                                    >
                                        <X className="w-5 h-5" />
                                    </Button>
                                </div>
                                <iframe
                                    src={previewExam.pdf_url}
                                    className="w-full flex-1 bg-gray-100"
                                    title="PDF Preview"
                                />
                            </div>
                        </div>
                    )
                }
            </main>

            {/* Mobile Bottom Nav */}
            <TeacherBottomNav />
        </div>
    )
}

"use client"

import { useState, useEffect } from "react"
import { useRouter, useParams } from "next/navigation"
import Link from "next/link"
import { createClient } from "@/lib/supabase/client"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import {
    ArrowLeft,
    Save,
    Loader2,
    CheckCircle2,
    HelpCircle,
    FileText,
    RefreshCw,
    AlertCircle
} from "lucide-react"
import { cn } from "@/lib/utils"

const OPTIONS = ["A", "B", "C", "D"] as const
type Option = typeof OPTIONS[number]
type TFAnswer = { question: number; a: boolean; b: boolean; c: boolean; d: boolean }
type SAAnswer = { question: number; answer: number | string }

export default function EditExamPage() {
    const router = useRouter()
    const params = useParams()
    const examId = params.id as string
    const supabase = createClient()

    const [loading, setLoading] = useState(true)
    const [authError, setAuthError] = useState<string | null>(null)
    const [saving, setSaving] = useState(false)
    const [regrading, setRegrading] = useState(false)
    const [error, setError] = useState<string | null>(null)
    const [success, setSuccess] = useState<string | null>(null)

    const [title, setTitle] = useState("")
    const [duration, setDuration] = useState(15)
    const [mcCount, setMcCount] = useState(12)
    const [tfCount, setTfCount] = useState(4)
    const [saCount, setSaCount] = useState(6)

    const [mcAnswers, setMcAnswers] = useState<(Option | null)[]>([])
    const [tfAnswers, setTfAnswers] = useState<TFAnswer[]>([])
    const [saAnswers, setSaAnswers] = useState<SAAnswer[]>([])

    const [answerTab, setAnswerTab] = useState<"mc" | "tf" | "sa">("mc")

    useEffect(() => {
        const fetchExam = async () => {
            console.log("=== EDIT PAGE DEBUG ===")
            console.log("Exam ID:", examId)

            const { data: { user }, error: authError } = await supabase.auth.getUser()
            console.log("Auth error:", authError)
            console.log("User ID:", user?.id)

            if (!user) {
                console.error("No user found, redirecting to login")
                router.push("/login")
                return
            }

            console.log("Fetching exam with teacher_id:", user.id)
            const { data: exam, error: examError } = await supabase
                .from("exams")
                .select("*")
                .eq("id", examId)
                .eq("teacher_id", user.id)
                .single()

            console.log("Exam fetch error:", examError)
            console.log("Exam data:", exam)

            if (examError) {
                console.error("Exam query failed:", examError.message, examError.details, examError.hint)
                alert(`Exam fetch error: ${examError.message}`)
            }

            if (!exam) {
                console.error("No exam found, redirecting to dashboard")
                // Try without teacher_id check
                const { data: anyExam } = await supabase
                    .from("exams")
                    .select("teacher_id, title")
                    .eq("id", examId)
                    .single()

                if (anyExam) {
                    console.error("Exam exists but teacher_id mismatch!")
                    console.error("Exam teacher_id:", anyExam.teacher_id)
                    console.error("Current user ID:", user.id)
                    setAuthError(`Bạn không có quyền chỉnh sửa đề thi này. Đề thi thuộc về giáo viên khác.`)
                } else {
                    console.error("Exam does not exist at all!")
                    router.push("/teacher/dashboard")
                }

                setLoading(false)
                return
            }

            console.log("Exam loaded successfully:", exam.title)

            // Load exam data
            setTitle(exam.title)
            setDuration(exam.duration)

            // Load MC answers
            if (exam.mc_answers && exam.mc_answers.length > 0) {
                const mc = exam.mc_answers as { question: number; answer: Option }[]
                setMcCount(mc.length)
                // Initialize array with explicit size to avoid index issues
                const newMc: (Option | null)[] = Array(mc.length).fill(null)
                mc.forEach(item => {
                    const idx = item.question - 1
                    if (idx >= 0 && idx < mc.length) {
                        newMc[idx] = item.answer
                    }
                })
                setMcAnswers(newMc)
            } else if (exam.correct_answers) {
                setMcCount(exam.correct_answers.length)
                setMcAnswers(exam.correct_answers)
            }

            // Load TF answers
            if (exam.tf_answers && exam.tf_answers.length > 0) {
                setTfCount(exam.tf_answers.length)
                setTfAnswers(exam.tf_answers)
            } else {
                setTfCount(0)
                setTfAnswers([])
            }

            // Load SA answers
            if (exam.sa_answers && exam.sa_answers.length > 0) {
                setSaCount(exam.sa_answers.length)
                setSaAnswers(exam.sa_answers)
            } else {
                setSaCount(0)
                setSaAnswers([])
            }

            setLoading(false)
        }

        fetchExam()
    }, [examId, router, supabase])

    // Update MC array when count changes
    const handleMcCountChange = (newCount: number) => {
        setMcCount(newCount)
        const newMc = Array(newCount).fill(null).map((_, i) => mcAnswers[i] || null)
        setMcAnswers(newMc)
    }

    // Update TF array when count changes
    const handleTfCountChange = (newCount: number) => {
        setTfCount(newCount)
        const newTf = Array.from({ length: newCount }, (_, i) =>
            tfAnswers[i] || { question: mcCount + 1 + i, a: true, b: true, c: true, d: true }
        )
        setTfAnswers(newTf)
    }

    // Update SA array when count changes
    const handleSaCountChange = (newCount: number) => {
        setSaCount(newCount)
        const newSa = Array.from({ length: newCount }, (_, i) =>
            saAnswers[i] || { question: mcCount + tfCount + 1 + i, answer: "" }
        )
        setSaAnswers(newSa)
    }

    const handleSave = async () => {
        if (!title.trim()) {
            setError("Vui lòng nhập tên đề thi")
            return
        }

        setSaving(true)
        setError(null)

        try {
            // Prepare MC answers
            const mcAnswerObjects = mcAnswers.map((ans, i) => ({
                question: i + 1,
                answer: ans
            })).filter(a => a.answer !== null)

            // Prepare TF answers with correct question numbers
            const finalTfAnswers = tfAnswers.length > 0 ? tfAnswers.map((tf, i) => ({
                ...tf,
                question: mcCount + 1 + i
            })) : Array.from({ length: tfCount }, (_, i) => ({
                question: mcCount + 1 + i,
                a: true, b: true, c: true, d: true
            }))

            // Prepare SA answers with correct question numbers
            const finalSaAnswers = saAnswers.length > 0 ? saAnswers.map((sa, i) => ({
                ...sa,
                question: mcCount + tfCount + 1 + i
            })) : Array.from({ length: saCount }, (_, i) => ({
                question: mcCount + tfCount + 1 + i,
                answer: ""
            }))

            const { error: updateError } = await supabase
                .from("exams")
                .update({
                    title: title.trim(),
                    duration,
                    total_questions: mcCount + tfCount + saCount,
                    correct_answers: mcAnswers,
                    mc_answers: mcAnswerObjects,
                    tf_answers: tfCount > 0 ? finalTfAnswers : [],
                    sa_answers: saCount > 0 ? finalSaAnswers : []
                })
                .eq("id", examId)

            if (updateError) throw updateError

            router.push("/teacher/dashboard")
        } catch (err) {
            setError("Lỗi cập nhật: " + (err as Error).message)
        } finally {
            setSaving(false)
        }
    }

    const handleRegrade = async () => {
        if (!confirm("Chấm lại điểm tất cả bài nộp? Hành động này sẽ tính lại điểm dựa trên đáp án hiện tại.")) {
            return
        }

        setRegrading(true)
        setError(null)
        setSuccess(null)

        try {
            // First save current answers
            const mcAnswerObjects = mcAnswers.map((ans, i) => ({
                question: i + 1,
                answer: ans
            })).filter(a => a.answer !== null)

            const finalTfAnswers = tfAnswers.map((tf, i) => ({
                ...tf,
                question: mcCount + 1 + i
            }))

            const finalSaAnswers = saAnswers.map((sa, i) => ({
                ...sa,
                question: mcCount + tfCount + 1 + i
            }))

            await supabase
                .from("exams")
                .update({
                    correct_answers: mcAnswers,
                    mc_answers: mcAnswerObjects,
                    tf_answers: tfCount > 0 ? finalTfAnswers : [],
                    sa_answers: saCount > 0 ? finalSaAnswers : []
                })
                .eq("id", examId)

            // Get all submissions for this exam
            const { data: submissions } = await supabase
                .from("submissions")
                .select("id, answers, tf_answers, sa_answers")
                .eq("exam_id", examId)

            if (!submissions || submissions.length === 0) {
                setSuccess("Không có bài nộp nào để chấm lại.")
                setRegrading(false)
                return
            }

            // Recalculate each submission
            let updatedCount = 0
            for (const sub of submissions) {
                let correctCount = 0
                const totalQuestions = mcCount + tfCount + saCount

                // Grade MC answers
                if (sub.answers && mcAnswers.length > 0) {
                    const studentMc = sub.answers as string[]
                    for (let i = 0; i < mcAnswers.length; i++) {
                        if (mcAnswers[i] && studentMc[i]?.toUpperCase() === mcAnswers[i]) {
                            correctCount++
                        }
                    }
                }

                // Grade TF answers (0.25 per correct sub-part)
                if (sub.tf_answers && finalTfAnswers.length > 0) {
                    const studentTf = sub.tf_answers as TFAnswer[]
                    for (let i = 0; i < finalTfAnswers.length; i++) {
                        const correct = finalTfAnswers[i]
                        const student = studentTf.find(t => t.question === correct.question)
                        if (student && correct) {
                            let tfScore = 0
                            if (student.a === correct.a) tfScore += 0.25
                            if (student.b === correct.b) tfScore += 0.25
                            if (student.c === correct.c) tfScore += 0.25
                            if (student.d === correct.d) tfScore += 0.25
                            correctCount += tfScore
                        }
                    }
                }

                // Grade SA answers
                if (sub.sa_answers && finalSaAnswers.length > 0) {
                    const studentSa = sub.sa_answers as SAAnswer[]
                    for (let i = 0; i < finalSaAnswers.length; i++) {
                        const correct = finalSaAnswers[i]
                        const student = studentSa.find(s => s.question === correct.question)
                        if (student && correct) {
                            const correctVal = correct.answer?.toString().trim().toLowerCase()
                            const studentVal = student.answer?.toString().trim().toLowerCase()
                            if (correctVal && studentVal && correctVal === studentVal) {
                                correctCount++
                            }
                        }
                    }
                }

                // Calculate score
                const score = totalQuestions > 0 ? (correctCount / totalQuestions) * 10 : 0

                // Update submission
                await supabase
                    .from("submissions")
                    .update({ score, correct_count: Math.round(correctCount * 100) / 100 })
                    .eq("id", sub.id)

                updatedCount++
            }

            setSuccess(`✅ Đã chấm lại ${updatedCount} bài nộp thành công!`)
        } catch (err) {
            setError("Lỗi chấm lại: " + (err as Error).message)
        } finally {
            setRegrading(false)
        }
    }

    if (loading) {
        return (
            <div className="min-h-screen bg-gray-50 dark:bg-slate-900 flex items-center justify-center">
                <Loader2 className="w-8 h-8 animate-spin text-blue-500" />
            </div>
        )
    }

    if (authError) {
        return (
            <div className="min-h-screen bg-gray-50 dark:bg-slate-900 flex items-center justify-center p-4">
                <div className="max-w-md w-full bg-white dark:bg-slate-800 rounded-xl shadow-lg border border-red-100 dark:border-slate-700 p-6 text-center">
                    <div className="w-16 h-16 bg-red-100 dark:bg-red-900/20 text-red-600 dark:text-red-400 rounded-full flex items-center justify-center mx-auto mb-4">
                        <AlertCircle className="w-8 h-8" />
                    </div>
                    <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-2">Không đủ quyền truy cập</h2>
                    <p className="text-gray-500 dark:text-gray-400 mb-6">{authError}</p>
                    <Link href="/teacher/dashboard">
                        <Button className="w-full bg-blue-600 hover:bg-blue-700 text-white shadow-sm">
                            Quay lại Dashboard
                        </Button>
                    </Link>
                </div>
            </div>
        )
    }

    return (
        <div className="min-h-screen bg-gray-50 dark:bg-slate-900 p-4 md:p-8">
            <div className="max-w-4xl mx-auto">
                {/* Header */}
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
                    <div className="flex items-center gap-4">
                        <Link href="/teacher/dashboard">
                            <Button variant="ghost" size="icon" className="text-gray-500 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white hover:bg-white dark:hover:bg-slate-700 bg-white dark:bg-slate-800 shadow-sm border border-gray-100 dark:border-slate-700">
                                <ArrowLeft className="w-5 h-5" />
                            </Button>
                        </Link>
                        <div>
                            <h1 className="text-2xl font-bold text-gray-800 dark:text-white">Chỉnh sửa đề thi</h1>
                            <p className="text-gray-500 dark:text-gray-400 text-sm mt-1">Cập nhật thông tin và đáp án</p>
                        </div>
                    </div>
                    <div className="flex flex-wrap gap-3">
                        <Button
                            onClick={handleRegrade}
                            disabled={regrading}
                            variant="outline"
                            className="border-orange-200 text-orange-600 bg-orange-50 hover:bg-orange-100 hover:text-orange-700"
                        >
                            {regrading ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <RefreshCw className="w-4 h-4 mr-2" />}
                            Chấm lại tất cả
                        </Button>
                        <Button
                            onClick={handleSave}
                            disabled={saving}
                            className="bg-blue-600 hover:bg-blue-700 text-white"
                        >
                            {saving ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Save className="w-4 h-4 mr-2" />}
                            Lưu thay đổi
                        </Button>
                    </div>
                </div>

                {error && (
                    <div className="mb-6 p-4 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg text-red-600 dark:text-red-400 flex items-center gap-3">
                        <AlertCircle className="w-5 h-5 flex-shrink-0" />
                        {error}
                    </div>
                )}

                {success && (
                    <div className="mb-6 p-4 bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800 rounded-lg text-green-600 dark:text-green-400 flex items-center gap-3">
                        <CheckCircle2 className="w-5 h-5 flex-shrink-0" />
                        {success}
                    </div>
                )}

                {/* Configuration Cards */}
                <div className="grid md:grid-cols-2 gap-6 mb-6">
                    <Card className="border-gray-200 dark:border-slate-800 shadow-sm bg-white dark:bg-slate-900">
                        <CardHeader className="pb-4">
                            <CardTitle className="text-base text-gray-800 dark:text-white">Thông tin cơ bản</CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            <div className="space-y-2">
                                <Label className="text-gray-700 dark:text-gray-300 font-medium">Tên đề thi</Label>
                                <Input
                                    value={title}
                                    onChange={(e) => setTitle(e.target.value)}
                                    className="bg-white dark:bg-slate-800 border-gray-300 dark:border-slate-700 text-gray-900 dark:text-white focus:ring-blue-500"
                                />
                            </div>
                            <div className="space-y-2">
                                <Label className="text-gray-700 dark:text-gray-300 font-medium">Thời gian (phút)</Label>
                                <Input
                                    type="number"
                                    value={duration}
                                    onChange={(e) => setDuration(Math.max(1, parseInt(e.target.value) || 1))}
                                    className="bg-white dark:bg-slate-800 border-gray-300 dark:border-slate-700 text-gray-900 dark:text-white focus:ring-blue-500"
                                />
                            </div>
                        </CardContent>
                    </Card>

                    <Card className="border-gray-200 dark:border-slate-800 shadow-sm bg-white dark:bg-slate-900">
                        <CardHeader className="pb-4">
                            <CardTitle className="text-base text-gray-800 dark:text-white flex justify-between items-center">
                                <span>Cấu trúc đề thi</span>
                                <span className="text-sm font-normal text-gray-500 dark:text-gray-400 bg-gray-100 dark:bg-slate-800 px-3 py-1 rounded-full">
                                    Tổng: {mcCount + tfCount + saCount} câu
                                </span>
                            </CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            <div className="grid grid-cols-3 gap-4">
                                <div className="space-y-2">
                                    <Label className="text-xs text-blue-600 dark:text-blue-400 font-semibold uppercase">Trắc nghiệm</Label>
                                    <Input
                                        type="number"
                                        value={mcCount}
                                        onChange={(e) => handleMcCountChange(Math.max(0, parseInt(e.target.value) || 0))}
                                        className="bg-white dark:bg-slate-800 border-blue-200 dark:border-blue-900 text-gray-900 dark:text-white focus:ring-blue-500 h-10"
                                    />
                                </div>
                                <div className="space-y-2">
                                    <Label className="text-xs text-green-600 dark:text-green-400 font-semibold uppercase">Đúng/Sai</Label>
                                    <Input
                                        type="number"
                                        value={tfCount}
                                        onChange={(e) => handleTfCountChange(Math.max(0, parseInt(e.target.value) || 0))}
                                        className="bg-white dark:bg-slate-800 border-green-200 dark:border-green-900 text-gray-900 dark:text-white focus:ring-green-500 h-10"
                                    />
                                </div>
                                <div className="space-y-2">
                                    <Label className="text-xs text-purple-600 dark:text-purple-400 font-semibold uppercase">Điền đáp án</Label>
                                    <Input
                                        type="number"
                                        value={saCount}
                                        onChange={(e) => handleSaCountChange(Math.max(0, parseInt(e.target.value) || 0))}
                                        className="bg-white dark:bg-slate-800 border-purple-200 dark:border-purple-900 text-gray-900 dark:text-white focus:ring-purple-500 h-10"
                                    />
                                </div>
                            </div>
                        </CardContent>
                    </Card>
                </div>

                {/* Answer Keys */}
                <Card className="border-gray-200 dark:border-slate-800 shadow-sm bg-white dark:bg-slate-900">
                    <CardHeader className="border-b border-gray-100 dark:border-slate-800 pb-4">
                        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                            <CardTitle className="text-gray-800 dark:text-white">Bảng đáp án</CardTitle>
                            <div className="flex gap-2">
                                <button
                                    onClick={() => setAnswerTab("mc")}
                                    className={cn(
                                        "px-4 py-2 rounded-lg text-sm font-medium transition-colors border",
                                        answerTab === "mc"
                                            ? "bg-blue-50 dark:bg-blue-900/20 text-blue-700 dark:text-blue-400 border-blue-200 dark:border-blue-900"
                                            : "bg-white dark:bg-slate-800 text-gray-500 dark:text-gray-400 border-transparent hover:bg-gray-50 dark:hover:bg-slate-800"
                                    )}
                                >
                                    Trắc nghiệm ({mcCount})
                                </button>
                                <button
                                    onClick={() => setAnswerTab("tf")}
                                    className={cn(
                                        "px-4 py-2 rounded-lg text-sm font-medium transition-colors border",
                                        answerTab === "tf"
                                            ? "bg-green-50 dark:bg-green-900/20 text-green-700 dark:text-green-400 border-green-200 dark:border-green-900"
                                            : "bg-white dark:bg-slate-800 text-gray-500 dark:text-gray-400 border-transparent hover:bg-gray-50 dark:hover:bg-slate-800"
                                    )}
                                >
                                    Đúng/Sai ({tfCount})
                                </button>
                                <button
                                    onClick={() => setAnswerTab("sa")}
                                    className={cn(
                                        "px-4 py-2 rounded-lg text-sm font-medium transition-colors border",
                                        answerTab === "sa"
                                            ? "bg-purple-50 dark:bg-purple-900/20 text-purple-700 dark:text-purple-400 border-purple-200 dark:border-purple-900"
                                            : "bg-white dark:bg-slate-800 text-gray-500 dark:text-gray-400 border-transparent hover:bg-gray-50 dark:hover:bg-slate-800"
                                    )}
                                >
                                    Điền đáp án ({saCount})
                                </button>
                            </div>
                        </div>
                    </CardHeader>
                    <CardContent className="pt-6">
                        {/* MC Answers */}
                        {answerTab === "mc" && (
                            <div className="grid grid-cols-2 sm:grid-cols-5 md:grid-cols-6 lg:grid-cols-8 gap-3">
                                {Array.from({ length: mcCount }, (_, i) => (
                                    <div key={i} className="flex flex-col items-center gap-2 p-2 bg-gray-50 dark:bg-slate-800 rounded border border-gray-100 dark:border-slate-700">
                                        <span className="text-xs font-semibold text-gray-500 dark:text-gray-400">Câu {i + 1}</span>
                                        <div className="grid grid-cols-2 gap-1 w-full">
                                            {OPTIONS.map((option) => (
                                                <button
                                                    key={option}
                                                    onClick={() => {
                                                        const newMc = [...mcAnswers]
                                                        newMc[i] = option
                                                        setMcAnswers(newMc)
                                                    }}
                                                    className={cn(
                                                        "h-7 rounded text-xs font-bold transition-all shadow-sm",
                                                        mcAnswers[i] === option
                                                            ? "bg-blue-600 text-white"
                                                            : "bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 text-gray-400 dark:text-gray-500 hover:border-blue-300 dark:hover:border-blue-700 hover:text-blue-600 dark:hover:text-blue-400"
                                                    )}
                                                >
                                                    {option}
                                                </button>
                                            ))}
                                        </div>
                                    </div>
                                ))}
                                {mcCount === 0 && (
                                    <div className="col-span-full py-12 text-center text-gray-400">
                                        Chưa có câu hỏi trắc nghiệm nào
                                    </div>
                                )}
                            </div>
                        )}

                        {/* TF Answers */}
                        {answerTab === "tf" && (
                            <div className="space-y-3">
                                {Array.from({ length: tfCount }, (_, i) => {
                                    const qNum = mcCount + 1 + i
                                    const answer = tfAnswers[i] || { question: qNum, a: true, b: true, c: true, d: true }
                                    return (
                                        <div key={i} className="flex items-center gap-4 p-4 bg-gray-50 dark:bg-slate-800 rounded-xl border border-gray-100 dark:border-slate-700">
                                            <span className="text-sm font-bold text-gray-700 dark:text-gray-300 w-16">Câu {qNum}</span>
                                            <div className="flex gap-6">
                                                {(['a', 'b', 'c', 'd'] as const).map((sub) => (
                                                    <div key={sub} className="flex flex-col items-center gap-2">
                                                        <span className="text-xs font-semibold text-gray-500 uppercase">{sub}</span>
                                                        <div className="flex rounded-md shadow-sm">
                                                            <button
                                                                onClick={() => {
                                                                    const newTf = [...tfAnswers]
                                                                    if (!newTf[i]) {
                                                                        newTf[i] = { question: qNum, a: true, b: true, c: true, d: true }
                                                                    }
                                                                    newTf[i] = { ...newTf[i], [sub]: true }
                                                                    setTfAnswers(newTf)
                                                                }}
                                                                className={cn(
                                                                    "px-2.5 py-1 rounded-l-md text-xs font-bold border-y border-l transition-colors",
                                                                    answer[sub] === true
                                                                        ? "bg-green-600 border-green-600 text-white"
                                                                        : "bg-white dark:bg-slate-800 border-gray-200 dark:border-slate-700 text-gray-400 dark:text-gray-500 hover:bg-gray-50 dark:hover:bg-slate-700"
                                                                )}
                                                            >
                                                                Đ
                                                            </button>
                                                            <button
                                                                onClick={() => {
                                                                    const newTf = [...tfAnswers]
                                                                    if (!newTf[i]) {
                                                                        newTf[i] = { question: qNum, a: true, b: true, c: true, d: true }
                                                                    }
                                                                    newTf[i] = { ...newTf[i], [sub]: false }
                                                                    setTfAnswers(newTf)
                                                                }}
                                                                className={cn(
                                                                    "px-2.5 py-1 rounded-r-md text-xs font-bold border transition-colors",
                                                                    answer[sub] === false
                                                                        ? "bg-red-500 border-red-500 text-white"
                                                                        : "bg-white dark:bg-slate-800 border-gray-200 dark:border-slate-700 text-gray-400 dark:text-gray-500 hover:bg-gray-50 dark:hover:bg-slate-700"
                                                                )}
                                                            >
                                                                S
                                                            </button>
                                                        </div>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    )
                                })}
                                {tfCount === 0 && (
                                    <div className="py-12 text-center text-gray-400 dark:text-gray-500">
                                        Chưa có câu hỏi Đúng/Sai nào
                                    </div>
                                )}
                            </div>
                        )}

                        {/* SA Answers */}
                        {answerTab === "sa" && (
                            <div className="space-y-3">
                                {Array.from({ length: saCount }, (_, i) => {
                                    const qNum = mcCount + tfCount + 1 + i
                                    const answer = saAnswers[i] || { question: qNum, answer: "" }
                                    return (
                                        <div key={i} className="flex items-center gap-4 p-3 bg-gray-50 dark:bg-slate-800 rounded-xl border border-gray-100 dark:border-slate-700">
                                            <span className="text-sm font-bold text-gray-700 dark:text-gray-300 w-16">Câu {qNum}</span>
                                            <Input
                                                value={answer.answer?.toString() || ""}
                                                onChange={(e) => {
                                                    const newSa = [...saAnswers]
                                                    newSa[i] = { question: qNum, answer: e.target.value }
                                                    setSaAnswers(newSa)
                                                }}
                                                placeholder="Nhập đáp án (số hoặc chữ)..."
                                                className="bg-white dark:bg-slate-900 border-gray-300 dark:border-slate-600 text-gray-900 dark:text-white focus:ring-purple-500 flex-1 max-w-md"
                                            />
                                        </div>
                                    )
                                })}
                                {saCount === 0 && (
                                    <div className="py-12 text-center text-gray-400">
                                        Chưa có câu hỏi điền đáp án nào
                                    </div>
                                )}
                            </div>
                        )}
                    </CardContent>
                </Card>
            </div>
        </div>
    )
}

"use client"

import { useState, useEffect, useCallback } from "react"
import { useParams, useRouter } from "next/navigation"
import Link from "next/link"
import { createClient } from "@/lib/supabase/client"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Progress } from "@/components/ui/progress"
import {
    Users, Clock, AlertTriangle, CheckCircle2,
    ArrowLeft, RefreshCw, Eye, Wifi, WifiOff,
    TrendingUp, Timer
} from "lucide-react"
import { cn } from "@/lib/utils"

interface Participant {
    user_id: string
    student_name: string
    status: "active" | "submitted" | "disconnected"
    started_at: string
    last_active: string
    progress?: number
}

interface ExamStats {
    total_participants: number
    active_count: number
    submitted_count: number
    disconnected_count: number
    avg_progress: number
}

export default function ExamMonitorPage() {
    const params = useParams()
    const router = useRouter()
    const examId = params.id as string
    const supabase = createClient()

    const [exam, setExam] = useState<{ title: string; duration: number } | null>(null)
    const [participants, setParticipants] = useState<Participant[]>([])
    const [stats, setStats] = useState<ExamStats>({
        total_participants: 0,
        active_count: 0,
        submitted_count: 0,
        disconnected_count: 0,
        avg_progress: 0
    })
    const [loading, setLoading] = useState(true)
    const [isLive, setIsLive] = useState(false)
    const [lastUpdate, setLastUpdate] = useState<Date>(new Date())

    const fetchData = useCallback(async () => {
        // Fetch exam info
        const { data: examData } = await supabase
            .from("exams")
            .select("title, duration")
            .eq("id", examId)
            .single()

        if (examData) setExam(examData)

        // Fetch participants
        const { data: participantData } = await supabase
            .from("exam_participants")
            .select("*")
            .eq("exam_id", examId)
            .order("started_at", { ascending: false })

        if (participantData) {
            // Calculate disconnected status (inactive for more than 2 minutes)
            const now = new Date()
            interface ParticipantData {
                user_id: string
                student_name: string
                status: string
                started_at: string
                last_active: string
            }

            const processed = participantData.map((p: ParticipantData) => {
                const lastActive = new Date(p.last_active)
                const inactiveMs = now.getTime() - lastActive.getTime()
                const isDisconnected = p.status === "active" && inactiveMs > 120000 // 2 minutes

                return {
                    ...p,
                    status: isDisconnected ? "disconnected" : p.status
                }
            })

            setParticipants(processed)

            // Calculate stats
            const active = processed.filter((p: { status: string }) => p.status === "active").length
            const submitted = processed.filter((p: { status: string }) => p.status === "submitted").length
            const disconnected = processed.filter((p: { status: string }) => p.status === "disconnected").length

            setStats({
                total_participants: processed.length,
                active_count: active,
                submitted_count: submitted,
                disconnected_count: disconnected,
                avg_progress: 0 // Would need submission progress data
            })
        }

        setLastUpdate(new Date())
        setLoading(false)
    }, [examId, supabase])

    // Initial fetch
    useEffect(() => {
        fetchData()
    }, [fetchData])

    // Real-time subscription
    useEffect(() => {
        const channel = supabase
            .channel(`exam-monitor-${examId}`)
            .on(
                "postgres_changes",
                {
                    event: "*",
                    schema: "public",
                    table: "exam_participants",
                    filter: `exam_id=eq.${examId}`
                },
                () => {
                    fetchData()
                    setIsLive(true)
                }
            )
            .subscribe((status: string) => {
                setIsLive(status === "SUBSCRIBED")
            })

        return () => {
            supabase.removeChannel(channel)
        }
    }, [examId, supabase, fetchData])

    // Auto-refresh every 30 seconds
    useEffect(() => {
        const interval = setInterval(fetchData, 30000)
        return () => clearInterval(interval)
    }, [fetchData])

    const getStatusColor = (status: string) => {
        switch (status) {
            case "active": return "bg-green-100 text-green-700 border-green-200"
            case "submitted": return "bg-blue-100 text-blue-700 border-blue-200"
            case "disconnected": return "bg-red-100 text-red-700 border-red-200"
            default: return "bg-gray-100 text-gray-700 border-gray-200"
        }
    }

    const getStatusIcon = (status: string) => {
        switch (status) {
            case "active": return <Eye className="w-4 h-4" />
            case "submitted": return <CheckCircle2 className="w-4 h-4" />
            case "disconnected": return <WifiOff className="w-4 h-4" />
            default: return null
        }
    }

    const formatTime = (dateStr: string) => {
        const date = new Date(dateStr)
        return date.toLocaleTimeString("vi-VN", { hour: "2-digit", minute: "2-digit" })
    }

    const getTimeSinceStart = (startedAt: string) => {
        const start = new Date(startedAt)
        const now = new Date()
        const diffMs = now.getTime() - start.getTime()
        const minutes = Math.floor(diffMs / 60000)
        return `${minutes} phút`
    }

    if (loading) {
        return (
            <div className="min-h-screen bg-gray-50 dark:bg-slate-950 flex items-center justify-center">
                <div className="w-8 h-8 border-4 border-blue-500 border-t-transparent rounded-full animate-spin" />
            </div>
        )
    }

    return (
        <div className="min-h-screen bg-gray-50 dark:bg-slate-950">
            {/* Header */}
            <header className="bg-white dark:bg-slate-900 border-b border-gray-200 dark:border-slate-800 sticky top-0 z-50">
                <div className="max-w-7xl mx-auto px-4 py-4 flex items-center justify-between">
                    <div className="flex items-center gap-4">
                        <Button variant="ghost" size="icon" onClick={() => router.back()}>
                            <ArrowLeft className="w-5 h-5" />
                        </Button>
                        <div>
                            <h1 className="text-lg font-bold text-gray-900 dark:text-white">
                                {exam?.title || "Đang tải..."}
                            </h1>
                            <p className="text-sm text-gray-500 dark:text-gray-400">
                                Giám sát thời gian thực
                            </p>
                        </div>
                    </div>
                    <div className="flex items-center gap-4">
                        <div className={cn(
                            "flex items-center gap-2 px-3 py-1.5 rounded-full text-sm font-medium",
                            isLive
                                ? "bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400"
                                : "bg-gray-100 text-gray-600 dark:bg-slate-800 dark:text-gray-400"
                        )}>
                            {isLive ? <Wifi className="w-4 h-4" /> : <WifiOff className="w-4 h-4" />}
                            {isLive ? "Live" : "Offline"}
                        </div>
                        <Button variant="outline" size="sm" onClick={fetchData}>
                            <RefreshCw className="w-4 h-4 mr-2" />
                            Làm mới
                        </Button>
                    </div>
                </div>
            </header>

            <main className="max-w-7xl mx-auto px-4 py-6 space-y-6">
                {/* Stats Cards */}
                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                    <Card className="bg-white dark:bg-slate-900">
                        <CardContent className="p-4">
                            <div className="flex items-center gap-3">
                                <div className="p-2 bg-blue-100 dark:bg-blue-900/30 rounded-lg">
                                    <Users className="w-5 h-5 text-blue-600 dark:text-blue-400" />
                                </div>
                                <div>
                                    <p className="text-2xl font-bold text-gray-900 dark:text-white">
                                        {stats.total_participants}
                                    </p>
                                    <p className="text-sm text-gray-500 dark:text-gray-400">Tổng số</p>
                                </div>
                            </div>
                        </CardContent>
                    </Card>

                    <Card className="bg-white dark:bg-slate-900">
                        <CardContent className="p-4">
                            <div className="flex items-center gap-3">
                                <div className="p-2 bg-green-100 dark:bg-green-900/30 rounded-lg">
                                    <Eye className="w-5 h-5 text-green-600 dark:text-green-400" />
                                </div>
                                <div>
                                    <p className="text-2xl font-bold text-green-600 dark:text-green-400">
                                        {stats.active_count}
                                    </p>
                                    <p className="text-sm text-gray-500 dark:text-gray-400">Đang làm</p>
                                </div>
                            </div>
                        </CardContent>
                    </Card>

                    <Card className="bg-white dark:bg-slate-900">
                        <CardContent className="p-4">
                            <div className="flex items-center gap-3">
                                <div className="p-2 bg-blue-100 dark:bg-blue-900/30 rounded-lg">
                                    <CheckCircle2 className="w-5 h-5 text-blue-600 dark:text-blue-400" />
                                </div>
                                <div>
                                    <p className="text-2xl font-bold text-blue-600 dark:text-blue-400">
                                        {stats.submitted_count}
                                    </p>
                                    <p className="text-sm text-gray-500 dark:text-gray-400">Đã nộp</p>
                                </div>
                            </div>
                        </CardContent>
                    </Card>

                    <Card className="bg-white dark:bg-slate-900">
                        <CardContent className="p-4">
                            <div className="flex items-center gap-3">
                                <div className="p-2 bg-red-100 dark:bg-red-900/30 rounded-lg">
                                    <AlertTriangle className="w-5 h-5 text-red-600 dark:text-red-400" />
                                </div>
                                <div>
                                    <p className="text-2xl font-bold text-red-600 dark:text-red-400">
                                        {stats.disconnected_count}
                                    </p>
                                    <p className="text-sm text-gray-500 dark:text-gray-400">Mất kết nối</p>
                                </div>
                            </div>
                        </CardContent>
                    </Card>
                </div>

                {/* Progress Overview */}
                <Card className="bg-white dark:bg-slate-900">
                    <CardHeader className="pb-2">
                        <CardTitle className="text-base flex items-center gap-2">
                            <TrendingUp className="w-5 h-5 text-blue-500" />
                            Tiến độ tổng quan
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="space-y-2">
                            <div className="flex justify-between text-sm">
                                <span className="text-gray-600 dark:text-gray-400">Đã nộp bài</span>
                                <span className="font-medium text-gray-900 dark:text-white">
                                    {stats.submitted_count}/{stats.total_participants}
                                    ({stats.total_participants > 0
                                        ? Math.round((stats.submitted_count / stats.total_participants) * 100)
                                        : 0}%)
                                </span>
                            </div>
                            <Progress
                                value={stats.total_participants > 0
                                    ? (stats.submitted_count / stats.total_participants) * 100
                                    : 0
                                }
                                className="h-3"
                            />
                        </div>
                    </CardContent>
                </Card>

                {/* Participants List */}
                <Card className="bg-white dark:bg-slate-900">
                    <CardHeader className="pb-2">
                        <div className="flex items-center justify-between">
                            <CardTitle className="text-base flex items-center gap-2">
                                <Users className="w-5 h-5 text-blue-500" />
                                Danh sách học sinh ({participants.length})
                            </CardTitle>
                            <span className="text-xs text-gray-400">
                                Cập nhật: {lastUpdate.toLocaleTimeString("vi-VN")}
                            </span>
                        </div>
                    </CardHeader>
                    <CardContent>
                        {participants.length === 0 ? (
                            <div className="text-center py-8 text-gray-500 dark:text-gray-400">
                                Chưa có học sinh nào tham gia
                            </div>
                        ) : (
                            <div className="space-y-2">
                                {participants.map((p) => (
                                    <div
                                        key={p.user_id}
                                        className="flex items-center justify-between p-3 bg-gray-50 dark:bg-slate-800 rounded-lg hover:bg-gray-100 dark:hover:bg-slate-700 transition-colors"
                                    >
                                        <div className="flex items-center gap-3">
                                            <div className="w-10 h-10 bg-blue-100 dark:bg-blue-900/30 rounded-full flex items-center justify-center">
                                                <span className="text-blue-600 dark:text-blue-400 font-medium">
                                                    {p.student_name?.charAt(0) || "?"}
                                                </span>
                                            </div>
                                            <div>
                                                <p className="font-medium text-gray-900 dark:text-white">
                                                    {p.student_name || "Học sinh"}
                                                </p>
                                                <div className="flex items-center gap-2 text-xs text-gray-500 dark:text-gray-400">
                                                    <Timer className="w-3 h-3" />
                                                    <span>Bắt đầu: {formatTime(p.started_at)}</span>
                                                    <span>•</span>
                                                    <span>{getTimeSinceStart(p.started_at)}</span>
                                                </div>
                                            </div>
                                        </div>
                                        <div className={cn(
                                            "flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-medium border",
                                            getStatusColor(p.status)
                                        )}>
                                            {getStatusIcon(p.status)}
                                            {p.status === "active" && "Đang làm"}
                                            {p.status === "submitted" && "Đã nộp"}
                                            {p.status === "disconnected" && "Mất kết nối"}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </CardContent>
                </Card>
            </main>
        </div>
    )
}

"use client"

import { useState, useRef } from "react"
import { useRouter } from "next/navigation"
import Link from "next/link"
import { createClient } from "@/lib/supabase/client"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import {
    ArrowLeft,
    Upload,
    FileText,
    Clock,
    Save,
    Eye,
    Loader2,
    CheckCircle2,
    X,
    Wand2,
    Sparkles,
    Calendar,
    HelpCircle,
    Copy,
    Trash
} from "lucide-react"
import { cn } from "@/lib/utils"
import { SUBJECTS } from "@/lib/subjects"
import { ExamLinkDialog } from "@/components/ExamLinkDialog"

const OPTIONS = ["A", "B", "C", "D"] as const
type Option = typeof OPTIONS[number]

export default function CreateExamPage() {
    const router = useRouter()
    const supabase = createClient()
    const fileInputRef = useRef<HTMLInputElement>(null)

    const [title, setTitle] = useState("")
    const [subject, setSubject] = useState("other")
    const [duration, setDuration] = useState(15)
    const [maxAttempts, setMaxAttempts] = useState(1)

    // Scheduling
    const [isScheduled, setIsScheduled] = useState(false)
    const [startTime, setStartTime] = useState("")
    const [endTime, setEndTime] = useState("")

    // Question type toggles
    const [enableTF, setEnableTF] = useState(false)
    const [enableSA, setEnableSA] = useState(false)

    // Question counts per type
    const [mcCount, setMcCount] = useState(12)
    const [tfCount, setTfCount] = useState(4)
    const [saCount, setSaCount] = useState(6)

    // Legacy support
    const [totalQuestions, setTotalQuestions] = useState(10)
    const [correctAnswers, setCorrectAnswers] = useState<(Option | null)[]>([])

    // New structured answers
    type TFAnswer = { question: number; a: boolean; b: boolean; c: boolean; d: boolean }
    type SAAnswer = { question: number; answer: number | string }

    const [mcAnswers, setMcAnswers] = useState<(Option | null)[]>([])
    const [tfAnswers, setTfAnswers] = useState<TFAnswer[]>([])
    const [saAnswers, setSaAnswers] = useState<SAAnswer[]>([])

    const [pdfFile, setPdfFile] = useState<File | null>(null)
    const [pdfUrl, setPdfUrl] = useState<string | null>(null)
    const [answerPdfFile, setAnswerPdfFile] = useState<File | null>(null)
    const [loading, setLoading] = useState(false)
    const [uploadingPdf, setUploadingPdf] = useState(false)
    const [parsingPdf, setParsingPdf] = useState(false)
    const [parseSuccess, setParseSuccess] = useState(false)
    const [error, setError] = useState<string | null>(null)
    const [step, setStep] = useState<"info" | "answers">("info")
    const [answerTab, setAnswerTab] = useState<"mc" | "tf" | "sa">("mc")

    const WORKER_URL = process.env.NEXT_PUBLIC_WORKER_URL || "http://localhost:8000"

    const [sendNotification, setSendNotification] = useState(true)

    // Score visibility settings
    const [scoreVisibilityMode, setScoreVisibilityMode] = useState<'always' | 'never' | 'threshold'>('always')
    const [scoreThreshold, setScoreThreshold] = useState(5.0)

    // Exam link dialog
    const [showLinkDialog, setShowLinkDialog] = useState(false)
    const [createdExamId, setCreatedExamId] = useState<string | null>(null)

    const handleTotalQuestionsChange = (value: number) => {
        const newValue = Math.max(1, Math.min(100, value))
        setTotalQuestions(newValue)

        const newAnswers: (Option | null)[] = Array(newValue).fill(null)
        correctAnswers.forEach((answer, i) => {
            if (i < newValue) newAnswers[i] = answer
        })
        setCorrectAnswers(newAnswers)
    }

    const handlePdfUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]
        if (!file) return

        if (file.type !== "application/pdf") {
            setError("Chỉ chấp nhận file PDF")
            return
        }

        setPdfFile(file)
        setUploadingPdf(true)
        setError(null)

        try {
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) throw new Error("Chưa đăng nhập")

            const sanitizeFileName = (name: string) => {
                return name
                    .normalize("NFD")
                    .replace(/[\u0300-\u036f]/g, "")
                    .replace(/[đĐ]/g, "d")
                    .replace(/[^a-zA-Z0-9._-]/g, "_")
            }
            const safeFileName = sanitizeFileName(file.name)
            const fileName = `${user.id}/${Date.now()}_${safeFileName}`
            const { data, error: uploadError } = await supabase.storage
                .from("exam-pdfs")
                .upload(fileName, file)

            if (uploadError) throw uploadError

            const { data: { publicUrl } } = supabase.storage
                .from("exam-pdfs")
                .getPublicUrl(fileName)

            setPdfUrl(publicUrl)
        } catch (err) {
            setError("Lỗi upload file: " + (err as Error).message)
            setPdfFile(null)
        } finally {
            setUploadingPdf(false)
        }
    }

    const parsePdfAnswers = async (fileToUse?: File) => {
        const targetFile = fileToUse || answerPdfFile || pdfFile

        if (!targetFile) {
            setError("Vui lòng upload file PDF đáp án trước")
            return
        }

        setParsingPdf(true)
        setError(null)
        setParseSuccess(false)

        try {
            const formData = new FormData()
            formData.append("file", targetFile)

            const response = await fetch(`${WORKER_URL}/extract-answers`, {
                method: "POST",
                body: formData,
            })

            if (!response.ok) {
                const errorData = await response.json()
                throw new Error(errorData.detail || "Không thể parse PDF")
            }

            const data = await response.json()
            console.log("API Response:", data)

            const mcData = data.multiple_choice || []
            const validMc = mcData.filter((a: string | null) =>
                a && ["A", "B", "C", "D"].includes(a.toUpperCase())
            )
            if (validMc.length > 0) {
                const parsedMc: (Option | null)[] = mcData.map((a: string | null) => {
                    if (a && ["A", "B", "C", "D"].includes(a.toUpperCase())) {
                        return a.toUpperCase() as Option
                    }
                    return null
                }).filter((a: Option | null) => a !== null)
                setMcAnswers(parsedMc)
                setMcCount(parsedMc.length)
                setCorrectAnswers(parsedMc)
                setTotalQuestions(parsedMc.length)
            }

            const parsedMcCount = validMc.length > 0 ? validMc.length : mcCount

            const tfData = data.true_false || []
            if (tfData.length > 0) {
                const parsedTf: TFAnswer[] = tfData.map((tf: { question: number; answers?: { a: boolean; b: boolean; c: boolean; d: boolean }; a?: boolean; b?: boolean; c?: boolean; d?: boolean }, index: number) => {
                    const correctQNum = parsedMcCount + 1 + index
                    if (tf.answers) {
                        return {
                            question: correctQNum,
                            a: tf.answers.a,
                            b: tf.answers.b,
                            c: tf.answers.c,
                            d: tf.answers.d
                        }
                    } else {
                        return {
                            question: correctQNum,
                            a: tf.a ?? true,
                            b: tf.b ?? true,
                            c: tf.c ?? true,
                            d: tf.d ?? true
                        }
                    }
                })
                setTfAnswers(parsedTf)
                setTfCount(parsedTf.length)
                setEnableTF(true)
            }

            const saData = data.short_answer || []
            if (saData.length > 0) {
                const effectiveTfCount = tfData.length || tfCount
                const parsedSa: SAAnswer[] = saData.map((sa: { question: number; answer: number | string }, index: number) => ({
                    question: parsedMcCount + effectiveTfCount + 1 + index,
                    answer: sa.answer
                }))
                setSaAnswers(parsedSa)
                setSaCount(parsedSa.length)
                setEnableSA(true)
            }

            if (validMc.length > 0 || tfData.length > 0 || saData.length > 0) {
                setParseSuccess(true)
            } else {
                throw new Error("Không tìm thấy đáp án trong PDF")
            }
        } catch (err) {
            setError("Lỗi parse PDF: " + (err as Error).message)
        } finally {
            setParsingPdf(false)
        }
    }

    const handleAnswerSelect = (questionIndex: number, option: Option) => {
        const newAnswers = [...correctAnswers]
        newAnswers[questionIndex] = option
        setCorrectAnswers(newAnswers)
        // Also update mcAnswers if applicable
        if (mcAnswers.length > 0) {
            const newMc = [...mcAnswers]
            newMc[questionIndex] = option
            setMcAnswers(newMc)
        }
    }

    const handleSave = async (publish: boolean = false) => {
        if (!title.trim()) {
            setError("Vui lòng nhập tên đề thi")
            return
        }

        const filledMc = (mcAnswers.length > 0 ? mcAnswers : correctAnswers).filter(a => a !== null).length
        if (filledMc < mcCount && mcCount > 0) {
            setError(`Vui lòng chọn đáp án cho tất cả ${mcCount} câu trắc nghiệm`)
            return
        }

        setLoading(true)
        setError(null)

        try {
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) throw new Error("Chưa đăng nhập")

            const mcAnswerObjects = (mcAnswers.length > 0 ? mcAnswers : correctAnswers).map((ans, i) => ({
                question: i + 1,
                answer: ans
            })).filter(a => a.answer !== null)

            let finalTfAnswers: TFAnswer[] = []
            const effectiveTfCount = enableTF ? tfCount : 0
            if (enableTF && tfCount > 0) {
                if (tfAnswers.length === 0) {
                    finalTfAnswers = Array.from({ length: tfCount }, (_, i) => ({
                        question: mcCount + 1 + i,
                        a: true, b: true, c: true, d: true
                    }))
                } else {
                    finalTfAnswers = tfAnswers
                }
            }

            let finalSaAnswers: SAAnswer[] = []
            const effectiveSaCount = enableSA ? saCount : 0
            if (enableSA && saCount > 0) {
                if (saAnswers.length === 0) {
                    finalSaAnswers = Array.from({ length: saCount }, (_, i) => ({
                        question: mcCount + effectiveTfCount + 1 + i,
                        answer: ""
                    }))
                } else {
                    finalSaAnswers = saAnswers
                }
            }

            const { data, error: insertError } = await supabase
                .from("exams")
                .insert({
                    teacher_id: user.id,
                    title: title.trim(),
                    duration,
                    total_questions: mcCount + effectiveTfCount + effectiveSaCount,
                    correct_answers: mcAnswers.length > 0 ? mcAnswers : correctAnswers,
                    mc_answers: mcAnswerObjects,
                    tf_answers: finalTfAnswers,
                    sa_answers: finalSaAnswers,
                    pdf_url: pdfUrl,
                    max_attempts: maxAttempts,
                    status: publish ? "published" : "draft",
                    subject,
                    is_scheduled: isScheduled,
                    start_time: isScheduled && startTime ? new Date(startTime).toISOString() : null,
                    end_time: isScheduled && endTime ? new Date(endTime).toISOString() : null,
                    score_visibility_mode: scoreVisibilityMode,
                    score_visibility_threshold: scoreVisibilityMode === 'threshold' ? scoreThreshold : null
                })
                .select()
                .single()

            if (insertError) throw insertError

            // Show link dialog after successful creation
            if (data) {
                setCreatedExamId(data.id)
                setShowLinkDialog(true)
            }

            if (publish && sendNotification && data) {
                try {
                    const { data: profile } = await supabase.from("profiles").select("full_name").eq("id", user.id).single()
                    const { data: students } = await supabase.from("profiles").select("id").eq("role", "student")

                    if (students && students.length > 0) {
                        const notifications = students.map((s: { id: string }) => ({
                            user_id: s.id,
                            title: `📝 Đề thi mới: ${title.trim()}`,
                            message: `${profile?.full_name || "Giáo viên"} đã đăng đề thi mới`,
                            type: "exam",
                            link: `/student/exams/${data.id}/take`,
                            is_read: false
                        }))
                        await supabase.from("notifications").insert(notifications)
                    }
                } catch (notifyErr) {
                    console.error("Failed to create notifications:", notifyErr)
                }
            }

            // Don't auto-redirect, let user close the dialog first
            // router.push("/teacher/dashboard")
        } catch (err) {
            setError("Lỗi lưu đề thi: " + (err as Error).message)
        } finally {
            setLoading(false)
        }
    }

    return (
        <div className="min-h-screen bg-gray-50 dark:bg-slate-900 p-4 md:p-8">
            <div className="max-w-4xl mx-auto">
                {/* Header */}
                <div className="flex items-center gap-4 mb-8">
                    <Link href="/teacher/dashboard">
                        <Button variant="ghost" size="icon" className="text-gray-500 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white hover:bg-white dark:hover:bg-slate-700 bg-white dark:bg-slate-800 shadow-sm border border-gray-100 dark:border-slate-700">
                            <ArrowLeft className="w-5 h-5" />
                        </Button>
