                            <CardHeader>
                                <CardTitle className="text-gray-800 dark:text-white">Thông tin cơ bản</CardTitle>
                                <CardDescription className="text-gray-500 dark:text-gray-400">
                                    Điền các thông tin bắt buộc cho đề thi
