                                                const val = Number(e.target.value)
                                                setMcCount(val)
                                                handleTotalQuestionsChange(val) // Sync with legacy logic
                                            }}
                                            className="bg-white dark:bg-slate-800 border-gray-300 dark:border-slate-700 text-gray-900 dark:text-white"
