"use client"

import { useState, useRef } from "react"
import { Upload, X, Loader2, User } from "lucide-react"
import { Button } from "@/components/ui/button"
import Image from "next/image"

interface AvatarUploadProps {
    currentUrl?: string | null
    onUploadComplete: (url: string) => void
    onRemove?: () => void
}

export function AvatarUpload({ currentUrl, onUploadComplete, onRemove }: AvatarUploadProps) {
    const [preview, setPreview] = useState<string | null>(currentUrl || null)
    const [uploading, setUploading] = useState(false)
    const [error, setError] = useState<string | null>(null)
    const [isDragging, setIsDragging] = useState(false)
    const fileInputRef = useRef<HTMLInputElement>(null)

    const handleFileSelect = async (file: File) => {
        setError(null)

        // Validate file type
        if (!file.type.startsWith("image/")) {
            setError("Vui lòng chọn file ảnh")
            return
        }

        // Validate file size (2MB)
        if (file.size > 2 * 1024 * 1024) {
            setError("Kích thước file tối đa 2MB")
            return
        }

        // Show preview
        const reader = new FileReader()
        reader.onloadend = () => {
            setPreview(reader.result as string)
        }
        reader.readAsDataURL(file)

        // Upload to server
        setUploading(true)
        try {
            const formData = new FormData()
            formData.append("file", file)

            const response = await fetch("/api/upload-avatar", {
                method: "POST",
                body: formData
            })

            const data = await response.json()

            if (!response.ok) {
                throw new Error(data.error || "Upload failed")
            }

            onUploadComplete(data.url)
            setError(null)
        } catch (err) {
            setError(err instanceof Error ? err.message : "Lỗi khi tải ảnh lên")
            setPreview(currentUrl || null)
        } finally {
            setUploading(false)
        }
    }

    const handleDrop = (e: React.DragEvent) => {
        e.preventDefault()
        setIsDragging(false)

        const file = e.dataTransfer.files[0]
        if (file) {
            handleFileSelect(file)
        }
    }

    const handleDragOver = (e: React.DragEvent) => {
        e.preventDefault()
        setIsDragging(true)
    }

    const handleDragLeave = () => {
        setIsDragging(false)
    }

    const handleRemove = async () => {
        if (!onRemove) return

        setUploading(true)
        try {
            const response = await fetch("/api/upload-avatar", {
                method: "DELETE"
            })

            if (!response.ok) {
                throw new Error("Failed to remove avatar")
            }

            setPreview(null)
            onRemove()
        } catch (err) {
            setError("Lỗi khi xóa ảnh")
        } finally {
            setUploading(false)
        }
    }

    return (
        <div className="flex flex-col items-center gap-4">
            {/* Avatar Preview */}
            <div
                className={`relative w-32 h-32 rounded-full overflow-hidden border-4 transition-all ${isDragging
                        ? "border-blue-500 border-dashed scale-105"
                        : "border-gray-200 dark:border-slate-700"
                    } ${uploading ? "opacity-50" : ""}`}
                onDrop={handleDrop}
                onDragOver={handleDragOver}
                onDragLeave={handleDragLeave}
            >
                {preview ? (
                    <Image
                        src={preview}
                        alt="Avatar"
                        fill
                        className="object-cover"
                    />
                ) : (
                    <div className="w-full h-full bg-gradient-to-br from-blue-500 to-purple-500 flex items-center justify-center">
                        <User className="w-16 h-16 text-white" />
                    </div>
                )}

                {uploading && (
                    <div className="absolute inset-0 bg-black/50 flex items-center justify-center">
                        <Loader2 className="w-8 h-8 text-white animate-spin" />
                    </div>
                )}
            </div>

            {/* Upload Buttons */}
            <div className="flex gap-2">
                <Button
                    type="button"
                    onClick={() => fileInputRef.current?.click()}
                    disabled={uploading}
                    className="bg-blue-600 hover:bg-blue-700 text-white"
                >
                    <Upload className="w-4 h-4 mr-2" />
                    Tải ảnh lên
                </Button>

                {preview && onRemove && (
                    <Button
                        type="button"
                        onClick={handleRemove}
                        disabled={uploading}
                        variant="outline"
                        className="text-red-600 hover:bg-red-50 dark:hover:bg-red-900/10"
                    >
                        <X className="w-4 h-4 mr-2" />
                        Xóa
                    </Button>
                )}
            </div>

            {/* Hidden file input */}
            <input
                ref={fileInputRef}
                type="file"
                accept="image/jpeg,image/jpg,image/png,image/webp"
                onChange={(e) => {
                    const file = e.target.files?.[0]
                    if (file) handleFileSelect(file)
                }}
                className="hidden"
            />

            {/* Error message */}
            {error && (
                <p className="text-sm text-red-600 dark:text-red-400">
                    {error}
                </p>
            )}

            {/* Help text */}
            <p className="text-xs text-gray-500 dark:text-gray-400 text-center">
                JPG, PNG, WebP • Tối đa 2MB<br />
                Kéo thả hoặc click để tải lên
            </p>
        </div>
    )
}

'use client'

import { useEffect, useRef, useState, useCallback } from 'react'

// Cloudflare Turnstile Site Key - Get from https://dash.cloudflare.com/turnstile
// For development, use the test key: 1x00000000000000000000AA (always passes)
const TURNSTILE_SITE_KEY = process.env.NEXT_PUBLIC_TURNSTILE_SITE_KEY || '1x00000000000000000000AA'

declare global {
    interface Window {
        turnstile?: {
            render: (container: HTMLElement, options: TurnstileOptions) => string
            reset: (widgetId: string) => void
            remove: (widgetId: string) => void
        }
        onloadTurnstileCallback?: () => void
    }
}

interface TurnstileOptions {
    sitekey: string
    callback: (token: string) => void
    'error-callback'?: () => void
    'expired-callback'?: () => void
    theme?: 'light' | 'dark' | 'auto'
    size?: 'normal' | 'compact'
}

interface CaptchaProps {
    onVerify: (token: string) => void
    onError?: () => void
    onExpire?: () => void
    theme?: 'light' | 'dark' | 'auto'
    className?: string
}

export function Captcha({ onVerify, onError, onExpire, theme = 'auto', className }: CaptchaProps) {
    const containerRef = useRef<HTMLDivElement>(null)
    const widgetIdRef = useRef<string | null>(null)
    const [loaded, setLoaded] = useState(false)
    const [error, setError] = useState(false)

    const renderWidget = useCallback(() => {
        if (!containerRef.current || !window.turnstile) return

        // Clear any existing widget
        if (widgetIdRef.current) {
            try {
                window.turnstile.remove(widgetIdRef.current)
            } catch (e) {
                // Widget might already be removed
            }
        }

        widgetIdRef.current = window.turnstile.render(containerRef.current, {
            sitekey: TURNSTILE_SITE_KEY,
            callback: (token: string) => {
                onVerify(token)
            },
            'error-callback': () => {
                setError(true)
                onError?.()
            },
            'expired-callback': () => {
                onExpire?.()
            },
            theme
        })
    }, [onVerify, onError, onExpire, theme])

    useEffect(() => {
        // Load Turnstile script
        if (typeof window !== 'undefined' && !window.turnstile) {
            const script = document.createElement('script')
            script.src = 'https://challenges.cloudflare.com/turnstile/v0/api.js?onload=onloadTurnstileCallback'
            script.async = true
            script.defer = true

            window.onloadTurnstileCallback = () => {
                setLoaded(true)
            }

            document.head.appendChild(script)

            return () => {
                document.head.removeChild(script)
                delete window.onloadTurnstileCallback
            }
        } else if (window.turnstile) {
            setLoaded(true)
        }
    }, [])

    useEffect(() => {
        if (loaded) {
            renderWidget()
        }
    }, [loaded, renderWidget])

    // Cleanup on unmount
    useEffect(() => {
        return () => {
            if (widgetIdRef.current && window.turnstile) {
                try {
                    window.turnstile.remove(widgetIdRef.current)
                } catch (e) {
                    // Widget might already be removed
                }
            }
        }
    }, [])

    if (error) {
        return (
            <div className={`p-4 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg text-center ${className}`}>
                <p className="text-red-600 dark:text-red-400 text-sm">
                    Failed to load CAPTCHA. Please refresh the page.
                </p>
            </div>
        )
    }

    return (
        <div className={className}>
            <div ref={containerRef} className="flex justify-center" />
            {!loaded && (
                <div className="flex justify-center py-4">
                    <div className="w-6 h-6 border-2 border-blue-500 border-t-transparent rounded-full animate-spin" />
                </div>
            )}
        </div>
    )
}

/**
 * Hook to manage CAPTCHA state in forms
 */
export function useCaptcha() {
    const [token, setToken] = useState<string | null>(null)
    const [verified, setVerified] = useState(false)

    const onVerify = useCallback((newToken: string) => {
        setToken(newToken)
        setVerified(true)
    }, [])

    const onExpire = useCallback(() => {
        setToken(null)
        setVerified(false)
    }, [])

    const reset = useCallback(() => {
        setToken(null)
        setVerified(false)
    }, [])

    return {
        token,
        verified,
        onVerify,
        onExpire,
        reset
    }
}

/**
 * Server-side token verification
 * Call this in your API route to verify the CAPTCHA token
 */
export async function verifyCaptchaToken(token: string): Promise<boolean> {
    const secretKey = process.env.TURNSTILE_SECRET_KEY

    if (!secretKey) {
        console.warn('TURNSTILE_SECRET_KEY not set, skipping verification')
        return true // Skip verification in development
    }

    try {
        const response = await fetch('https://challenges.cloudflare.com/turnstile/v0/siteverify', {
            method: 'POST',
            headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
            body: new URLSearchParams({
                secret: secretKey,
                response: token
            })
        })

        const data = await response.json()
        return data.success === true
    } catch (error) {
        console.error('CAPTCHA verification failed:', error)
        return false
    }
}

"use client"

import { useState, useEffect, useRef } from "react"
import { createClient } from "@/lib/supabase/client"
import { Bell, Check, ExternalLink, X } from "lucide-react"
import { cn } from "@/lib/utils"
import Link from "next/link"

interface Notification {
    id: string
    title: string
    message: string | null
    type: string
    link: string | null
    is_read: boolean
    created_at: string
}

export function NotificationBell() {
    const [notifications, setNotifications] = useState<Notification[]>([])
    const [unreadCount, setUnreadCount] = useState(0)
    const [isOpen, setIsOpen] = useState(false)
    const [loading, setLoading] = useState(true)
    const dropdownRef = useRef<HTMLDivElement>(null)
    const supabase = createClient()

    // Fetch notifications
    useEffect(() => {
        const fetchNotifications = async () => {
            const { data: { user } } = await supabase.auth.getUser()
            if (!user) return

            const { data, error } = await supabase
                .from("notifications")
                .select("*")
                .eq("user_id", user.id)
                .order("created_at", { ascending: false })
                .limit(10)

            if (!error && data) {
                setNotifications(data)
                setUnreadCount(data.filter((n: Notification) => !n.is_read).length)
            }
            setLoading(false)
        }

        fetchNotifications()

        // Subscribe to realtime changes
        const channel = supabase
            .channel("notifications")
            .on(
                "postgres_changes",
                {
                    event: "INSERT",
                    schema: "public",
                    table: "notifications"
                },
                (payload: { new: Notification }) => {
                    const newNotification = payload.new
                    setNotifications(prev => [newNotification, ...prev.slice(0, 9)])
                    setUnreadCount(prev => prev + 1)
                }
            )
            .subscribe()

        return () => {
            supabase.removeChannel(channel)
        }
    }, [supabase])

    // Close dropdown on outside click
    useEffect(() => {
        const handleClickOutside = (e: MouseEvent) => {
            if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
                setIsOpen(false)
            }
        }
        document.addEventListener("mousedown", handleClickOutside)
        return () => document.removeEventListener("mousedown", handleClickOutside)
    }, [])

    // Mark as read
    const markAsRead = async (id: string) => {
        await supabase
            .from("notifications")
            .update({ is_read: true })
            .eq("id", id)

        setNotifications(prev =>
            prev.map(n => n.id === id ? { ...n, is_read: true } : n)
        )
        setUnreadCount(prev => Math.max(0, prev - 1))
    }

    // Mark all as read
    const markAllAsRead = async () => {
        const { data: { user } } = await supabase.auth.getUser()
        if (!user) return

        await supabase
            .from("notifications")
            .update({ is_read: true })
            .eq("user_id", user.id)
            .eq("is_read", false)

        setNotifications(prev => prev.map(n => ({ ...n, is_read: true })))
        setUnreadCount(0)
    }

    // Format time ago
    const timeAgo = (date: string) => {
        const now = new Date()
        const past = new Date(date)
        const diffMs = now.getTime() - past.getTime()
        const diffMins = Math.floor(diffMs / 60000)
        const diffHours = Math.floor(diffMins / 60)
        const diffDays = Math.floor(diffHours / 24)

        if (diffMins < 1) return "Vừa xong"
        if (diffMins < 60) return `${diffMins} phút trước`
        if (diffHours < 24) return `${diffHours} giờ trước`
        return `${diffDays} ngày trước`
    }

    return (
        <div className="relative" ref={dropdownRef}>
            {/* Bell Button */}
            <button
                onClick={() => setIsOpen(!isOpen)}
                className="relative p-2 rounded-lg hover:bg-slate-700/50 transition-colors"
            >
                <Bell className="w-5 h-5 text-slate-300" />
                {unreadCount > 0 && (
                    <span className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 text-white text-xs font-bold rounded-full flex items-center justify-center animate-pulse">
                        {unreadCount > 9 ? "9+" : unreadCount}
                    </span>
                )}
            </button>

            {/* Dropdown */}
            {isOpen && (
                <div className="absolute right-0 top-12 w-80 bg-slate-800 border border-slate-700 rounded-xl shadow-2xl z-50 overflow-hidden">
                    {/* Header */}
                    <div className="flex items-center justify-between px-4 py-3 border-b border-slate-700 bg-slate-800/80">
                        <h3 className="font-semibold text-white">Thông báo</h3>
                        {unreadCount > 0 && (
                            <button
                                onClick={markAllAsRead}
                                className="text-xs text-blue-400 hover:text-blue-300 flex items-center gap-1"
                            >
                                <Check className="w-3 h-3" />
                                Đọc tất cả
                            </button>
                        )}
                    </div>

                    {/* Notifications List */}
                    <div className="max-h-80 overflow-y-auto">
                        {loading ? (
                            <div className="p-4 text-center text-slate-400">
                                Đang tải...
                            </div>
                        ) : notifications.length === 0 ? (
                            <div className="p-8 text-center">
