                        Tiếp tục
                    </button>
                </div>
            </div>
        </div>
    )
}

// Hook to manage achievement unlocks
export function useAchievementUnlock() {
    const [queue, setQueue] = useState<Achievement[]>([])
    const [current, setCurrent] = useState<Achievement | null>(null)

    useEffect(() => {
        if (!current && queue.length > 0) {
            setCurrent(queue[0])
            setQueue(prev => prev.slice(1))
        }
    }, [current, queue])

    const unlock = (achievement: Achievement) => {
        setQueue(prev => [...prev, achievement])
    }

    const close = () => {
        setCurrent(null)
    }

    return {
        current,
        unlock,
        close,
        AchievementPopup: current ? (
            <AchievementUnlockAnimation achievement={current} onClose={close} />
        ) : null
    }
}

"use client"

import { useState, useEffect } from "react"
import { Trophy, Lock, Check, Star, Loader2 } from "lucide-react"
import { cn } from "@/lib/utils"

interface Achievement {
    id: string
    code: string
    name: string
    description: string
    icon: string
    category: string
    rarity: string
    xp_reward: number
    condition_type: string
    condition_value: number
    is_hidden: boolean
    isUnlocked: boolean
    isFeatured: boolean
    currentValue: number
    progress: number
}

interface AchievementsData {
    achievements: Achievement[]
    grouped: Record<string, Achievement[]>
    stats: {
        total: number
        unlocked: number
        percentage: number
    }
}

const categoryNames: Record<string, string> = {
    study: "📚 Học tập",
    streak: "🔥 Chuỗi ngày",
    score: "⭐ Điểm số",
    xp: "💰 Tích lũy XP",
    level: "⬆️ Cấp độ"
}

const rarityColors: Record<string, string> = {
    common: "border-slate-500 bg-slate-500/10",
    rare: "border-blue-500 bg-blue-500/10",
    epic: "border-purple-500 bg-purple-500/10",
    legendary: "border-yellow-500 bg-yellow-500/10"
}

const rarityGlow: Record<string, string> = {
    common: "",
    rare: "shadow-blue-500/20",
    epic: "shadow-purple-500/30",
    legendary: "shadow-yellow-500/40 shadow-lg"
}

export function AchievementCard({ achievement }: { achievement: Achievement }) {
    const isLocked = !achievement.isUnlocked
    const showHidden = achievement.is_hidden && isLocked

    return (
        <div
            className={cn(
                "relative p-4 rounded-xl border-2 transition-all",
                isLocked ? "opacity-60 grayscale" : rarityColors[achievement.rarity],
                !isLocked && rarityGlow[achievement.rarity]
            )}
        >
            {/* Unlocked badge */}
            {!isLocked && (
                <div className="absolute -top-2 -right-2 w-6 h-6 bg-green-500 rounded-full flex items-center justify-center">
                    <Check className="w-4 h-4 text-white" />
                </div>
            )}

            {/* Icon */}
            <div className="text-4xl mb-3">
                {showHidden ? "❓" : achievement.icon}
            </div>

            {/* Name */}
            <h4 className="font-semibold text-white mb-1">
                {showHidden ? "???" : achievement.name}
            </h4>

            {/* Description */}
            <p className="text-xs text-slate-400 mb-3 line-clamp-2">
                {showHidden ? "Hoàn thành để mở khóa..." : achievement.description}
            </p>

            {/* Progress bar */}
            {!achievement.isUnlocked && !showHidden && (
                <div className="mt-2">
                    <div className="flex justify-between text-xs text-slate-400 mb-1">
                        <span>{Math.round(achievement.progress)}%</span>
                        <span>{achievement.currentValue}/{achievement.condition_value}</span>
                    </div>
                    <div className="h-2 bg-slate-700 rounded-full overflow-hidden">
                        <div
                            className="h-full bg-gradient-to-r from-blue-500 to-purple-500 transition-all"
                            style={{ width: `${achievement.progress}%` }}
                        />
                    </div>
                </div>
            )}

            {/* XP Reward */}
            {achievement.xp_reward > 0 && !isLocked && (
                <div className="mt-2 inline-flex items-center gap-1 px-2 py-0.5 bg-yellow-500/20 rounded-full text-xs text-yellow-400">
                    +{achievement.xp_reward} XP
                </div>
            )}

            {/* Rarity label */}
            <div className={cn(
                "absolute top-2 left-2 px-2 py-0.5 rounded text-[10px] font-medium uppercase",
                achievement.rarity === "legendary" && "bg-yellow-500/20 text-yellow-400",
                achievement.rarity === "epic" && "bg-purple-500/20 text-purple-400",
                achievement.rarity === "rare" && "bg-blue-500/20 text-blue-400",
                achievement.rarity === "common" && "bg-slate-500/20 text-slate-400"
            )}>
                {achievement.rarity}
            </div>
        </div>
    )
}

export function AchievementsGrid() {
    const [data, setData] = useState<AchievementsData | null>(null)
    const [loading, setLoading] = useState(true)
    const [activeCategory, setActiveCategory] = useState<string | null>(null)

    useEffect(() => {
        fetchAchievements()
    }, [])

    async function fetchAchievements() {
        try {
            const res = await fetch("/api/achievements")
            const json = await res.json()
            if (res.ok) {
                setData(json)
            }
        } catch (error) {
            console.error("Failed to fetch achievements:", error)
        } finally {
            setLoading(false)
        }
    }

    if (loading) {
        return (
            <div className="flex items-center justify-center py-12">
                <Loader2 className="w-8 h-8 animate-spin text-purple-500" />
            </div>
        )
    }

    if (!data) {
        return (
            <div className="text-center py-12 text-slate-400">
                Không thể tải thành tựu
            </div>
        )
    }

    const categories = Object.keys(data.grouped).filter(k => data.grouped[k].length > 0)
    const displayCategory = activeCategory || categories[0]
    const achievements = activeCategory
        ? data.grouped[activeCategory]
        : data.achievements

    return (
        <div className="space-y-6">
            {/* Stats header */}
            <div className="flex items-center justify-between p-4 bg-gradient-to-r from-purple-500/20 to-pink-500/20 rounded-xl border border-purple-500/30">
                <div className="flex items-center gap-3">
                    <div className="w-12 h-12 rounded-full bg-gradient-to-r from-purple-500 to-pink-500 flex items-center justify-center">
                        <Trophy className="w-6 h-6 text-white" />
                    </div>
                    <div>
                        <p className="text-sm text-slate-400">Thành tựu đã mở</p>
                        <p className="text-2xl font-bold text-white">
                            {data.stats.unlocked} / {data.stats.total}
                        </p>
                    </div>
                </div>
                <div className="text-right">
                    <p className="text-3xl font-bold text-purple-400">{data.stats.percentage}%</p>
                    <p className="text-xs text-slate-400">Hoàn thành</p>
                </div>
            </div>

            {/* Category tabs */}
            <div className="flex gap-2 overflow-x-auto pb-2">
                <button
                    onClick={() => setActiveCategory(null)}
                    className={cn(
                        "px-4 py-2 rounded-lg text-sm font-medium whitespace-nowrap transition-all",
                        !activeCategory
                            ? "bg-purple-500 text-white"
                            : "bg-slate-800 text-slate-400 hover:text-white"
                    )}
                >
                    Tất cả
                </button>
                {categories.map(cat => (
                    <button
                        key={cat}
                        onClick={() => setActiveCategory(cat)}
                        className={cn(
                            "px-4 py-2 rounded-lg text-sm font-medium whitespace-nowrap transition-all",
                            activeCategory === cat
                                ? "bg-purple-500 text-white"
                                : "bg-slate-800 text-slate-400 hover:text-white"
                        )}
                    >
                        {categoryNames[cat] || cat}
                    </button>
                ))}
            </div>

            {/* Achievements grid */}
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
                {achievements.map(achievement => (
                    <AchievementCard key={achievement.id} achievement={achievement} />
                ))}
            </div>
        </div>
    )
}

// Compact widget for dashboard
export function AchievementsWidget({ limit = 4 }: { limit?: number }) {
    const [achievements, setAchievements] = useState<Achievement[]>([])
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        fetch("/api/achievements")
            .then(res => res.json())
            .then(data => {
                // Show unlocked first, then closest to unlock
                const sorted = [...(data.achievements || [])]
                    .sort((a, b) => {
                        if (a.isUnlocked && !b.isUnlocked) return -1
                        if (!a.isUnlocked && b.isUnlocked) return 1
                        return b.progress - a.progress
                    })
                setAchievements(sorted.slice(0, limit))
            })
            .catch(() => { })
            .finally(() => setLoading(false))
    }, [limit])

    if (loading) {
        return (
            <div className="flex items-center justify-center py-8">
                <Loader2 className="w-5 h-5 animate-spin text-purple-500" />
            </div>
        )
    }

    return (
        <div className="space-y-3">
            <div className="flex items-center justify-between">
                <h3 className="font-semibold text-white flex items-center gap-2">
                    <Trophy className="w-5 h-5 text-purple-500" />
                    Thành tựu
                </h3>
                <a href="/student/achievements" className="text-sm text-purple-400 hover:underline">
                    Xem tất cả
                </a>
            </div>

            <div className="grid grid-cols-2 gap-3">
                {achievements.map(a => (
                    <div
                        key={a.id}
                        className={cn(
                            "p-3 rounded-lg border text-center",
                            a.isUnlocked
                                ? "bg-purple-500/10 border-purple-500/30"
                                : "bg-slate-800/50 border-slate-700 opacity-60"
                        )}
                    >
                        <div className="text-2xl mb-1">{a.icon}</div>
                        <p className="text-xs text-white font-medium truncate">{a.name}</p>
                        {!a.isUnlocked && (
                            <div className="mt-1 h-1 bg-slate-700 rounded-full overflow-hidden">
                                <div
                                    className="h-full bg-purple-500"
                                    style={{ width: `${a.progress}%` }}
                                />
                            </div>
                        )}
                    </div>
                ))}
            </div>
        </div>
    )
}

"use client"

import { useEffect, useState, useCallback } from "react"
import { Trophy, Medal, Crown, Zap } from "lucide-react"
import { getLeaderboard } from "@/lib/gamification"
import { createClient } from "@/lib/supabase/client"
import { cn } from "@/lib/utils"

interface LeaderboardEntry {
    rank: number
    userId: string
    fullName: string
    xp: number
    level: number
}

interface LeaderboardWidgetProps {
    currentUserId?: string
    limit?: number
    realtime?: boolean
}

export function LeaderboardWidget({ currentUserId, limit = 10, realtime = true }: LeaderboardWidgetProps) {
    const [entries, setEntries] = useState<LeaderboardEntry[]>([])
    const [loading, setLoading] = useState(true)
    const [lastUpdated, setLastUpdated] = useState<Date | null>(null)
    const [isLive, setIsLive] = useState(false)

    const fetchLeaderboard = useCallback(async () => {
        const data = await getLeaderboard(limit)
        setEntries(data)
        setLastUpdated(new Date())
        setLoading(false)
    }, [limit])

    useEffect(() => {
        fetchLeaderboard()

        // Setup realtime subscription
        if (!realtime) return

        const supabase = createClient()

        const channel = supabase
            .channel("leaderboard-realtime")
            .on(
                "postgres_changes",
                {
                    event: "*", // Listen to INSERT, UPDATE, DELETE
                    schema: "public",
                    table: "student_stats"
                },
                () => {
                    // Refetch leaderboard when stats change
                    fetchLeaderboard()
                    setIsLive(true)
                    // Reset live indicator after 2 seconds
                    setTimeout(() => setIsLive(false), 2000)
                }
            )
            .subscribe()

        return () => {
            supabase.removeChannel(channel)
        }
    }, [limit, realtime, fetchLeaderboard])

    const getRankIcon = (rank: number) => {
        switch (rank) {
            case 1:
                return <Crown className="w-5 h-5 text-yellow-500" />
            case 2:
                return <Medal className="w-5 h-5 text-slate-400" />
            case 3:
                return <Medal className="w-5 h-5 text-amber-600" />
            default:
                return <span className="w-5 text-center text-sm text-slate-500">{rank}</span>
        }
    }

    const getRankBg = (rank: number) => {
        switch (rank) {
            case 1:
                return "bg-gradient-to-r from-yellow-500/20 to-orange-500/20 border-yellow-500/30"
            case 2:
                return "bg-slate-500/10 border-slate-500/30"
            case 3:
                return "bg-amber-500/10 border-amber-500/30"
            default:
                return "bg-slate-800/30 border-slate-700/50"
        }
    }

    if (loading) {
        return (
            <div className="animate-pulse space-y-2">
                {[...Array(5)].map((_, i) => (
                    <div key={i} className="h-12 bg-slate-800/50 rounded-lg" />
                ))}
            </div>
        )
    }

    return (
        <div className="space-y-2">
            {/* Live indicator */}
            {realtime && (
                <div className="flex items-center justify-between text-xs text-slate-400 mb-2">
                    <div className="flex items-center gap-1">
                        <span className={cn(
                            "w-2 h-2 rounded-full",
                            isLive ? "bg-green-500 animate-pulse" : "bg-slate-600"
                        )} />
                        <span>Live</span>
                    </div>
                    {lastUpdated && (
                        <span>
                            Cập nhật: {lastUpdated.toLocaleTimeString("vi-VN")}
                        </span>
                    )}
                </div>
            )}

            {entries.map((entry) => (
                <div
                    key={entry.userId}
                    className={cn(
                        "flex items-center gap-3 p-3 rounded-lg border transition-all",
                        getRankBg(entry.rank),
                        entry.userId === currentUserId && "ring-2 ring-blue-500",
                        isLive && "animate-pulse"
                    )}
                >
                    <div className="w-8 flex justify-center">
                        {getRankIcon(entry.rank)}
                    </div>

                    <div className="flex-1 min-w-0">
                        <p className={cn(
                            "font-medium truncate",
                            entry.rank === 1 ? "text-yellow-500" : "text-white"
                        )}>
                            {entry.fullName}
                            {entry.userId === currentUserId && (
                                <span className="ml-2 text-xs text-blue-400">(Bạn)</span>
                            )}
                        </p>
                    </div>

                    <div className="flex items-center gap-3 text-sm">
                        <span className="text-slate-400">
                            Lv.{entry.level}
                        </span>
                        <span className="font-mono text-yellow-500">
                            {entry.xp.toLocaleString()} XP
                        </span>
                    </div>
                </div>
            ))}
        </div>
    )
}

export function LeaderboardCard({ currentUserId, compact = false }: { currentUserId?: string; compact?: boolean }) {
    if (compact) {
        return <LeaderboardWidget currentUserId={currentUserId} limit={5} realtime />
    }

    return (
        <div className="bg-slate-800/50 border border-slate-700 rounded-xl p-6">
            <div className="flex items-center gap-2 mb-4">
                <Trophy className="w-5 h-5 text-yellow-500" />
                <h3 className="font-semibold text-white">Bảng xếp hạng</h3>
                <Zap className="w-4 h-4 text-green-500 ml-auto" />
            </div>
            <LeaderboardWidget currentUserId={currentUserId} limit={10} realtime />
        </div>
    )
}

"use client"

import { useEffect, useState } from "react"
import { Star } from "lucide-react"
import { calculateLevel, levelProgress, xpForNextLevel } from "@/lib/gamification"
import { cn } from "@/lib/utils"

interface XpBarProps {
    xp: number
    showDetails?: boolean
    size?: "sm" | "md" | "lg"
    animated?: boolean
}

export function XpBar({ xp, showDetails = true, size = "md", animated = true }: XpBarProps) {
    const [displayXp, setDisplayXp] = useState(animated ? 0 : xp)
    const level = calculateLevel(xp)
    const progress = levelProgress(xp)
    const nextLevelXp = xpForNextLevel(level)

    useEffect(() => {
        if (!animated) {
            setDisplayXp(xp)
            return
        }

        // Animate XP counter
        const duration = 1000
        const steps = 30
        const increment = xp / steps
        let current = 0

        const timer = setInterval(() => {
            current += increment
            if (current >= xp) {
                setDisplayXp(xp)
                clearInterval(timer)
            } else {
                setDisplayXp(Math.floor(current))
            }
        }, duration / steps)

        return () => clearInterval(timer)
    }, [xp, animated])

    const sizeClasses = {
        sm: "h-1.5",
        md: "h-2",
        lg: "h-3"
    }

    return (
        <div className="flex items-center gap-3">
            {/* Level Badge */}
            <div className={cn(
                "flex items-center justify-center rounded-full bg-gradient-to-r from-yellow-500 to-orange-500 text-white font-bold shrink-0",
                size === "sm" ? "w-6 h-6 text-xs" : size === "md" ? "w-8 h-8 text-sm" : "w-10 h-10 text-base"
            )}>
                {level}
            </div>

            <div className="flex-1 min-w-0">
                {/* Progress Bar */}
                <div className={cn(
                    "w-full bg-slate-700 rounded-full overflow-hidden",
                    sizeClasses[size]
                )}>
                    <div
                        className="h-full bg-gradient-to-r from-yellow-400 via-orange-500 to-red-500 transition-all duration-500"
                        style={{ width: `${progress}%` }}
                    />
                </div>

                {/* Details */}
                {showDetails && (
                    <div className="flex justify-between mt-1">
                        <span className="text-xs text-slate-400">
                            {displayXp.toLocaleString()} XP
                        </span>
                        <span className="text-xs text-slate-500">
                            {nextLevelXp.toLocaleString()} XP để Level {level + 1}
                        </span>
                    </div>
                )}
            </div>
        </div>
    )
}

interface XpGainAnimationProps {
    xpGained: number
    onComplete?: () => void
}

export function XpGainAnimation({ xpGained, onComplete }: XpGainAnimationProps) {
    const [visible, setVisible] = useState(true)

    useEffect(() => {
        const timer = setTimeout(() => {
            setVisible(false)
            onComplete?.()
        }, 2000)

        return () => clearTimeout(timer)
    }, [onComplete])

    if (!visible) return null

    return (
        <div className="fixed top-1/3 left-1/2 -translate-x-1/2 -translate-y-1/2 z-50 animate-bounce">
            <div className="bg-gradient-to-r from-yellow-500 to-orange-500 text-white px-6 py-3 rounded-full font-bold text-2xl shadow-lg flex items-center gap-2">
                <Star className="w-6 h-6 fill-current" />
                +{xpGained} XP
            </div>
        </div>
    )
}

interface LevelUpAnimationProps {
    newLevel: number
    onComplete?: () => void
}

export function LevelUpAnimation({ newLevel, onComplete }: LevelUpAnimationProps) {
    const [visible, setVisible] = useState(true)

    useEffect(() => {
        const timer = setTimeout(() => {
            setVisible(false)
            onComplete?.()
        }, 3000)

        return () => clearTimeout(timer)
    }, [onComplete])

    if (!visible) return null

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm animate-in fade-in">
            <div className="text-center">
                <div className="text-6xl mb-4">🎉</div>
                <h2 className="text-3xl font-bold text-white mb-2">Level Up!</h2>
                <div className="w-24 h-24 mx-auto rounded-full bg-gradient-to-r from-yellow-500 to-orange-500 flex items-center justify-center text-4xl font-bold text-white shadow-lg">
                    {newLevel}
                </div>
            </div>
        </div>
    )
}

"use client"

import { useEffect, useRef, useState, useCallback } from "react"
import { AlertTriangle, Eye, Smartphone, CheckCircle } from "lucide-react"

interface GazeTrackerProps {
    enabled: boolean
    onViolation?: (type: string, details: { duration?: number; threshold?: number; confidence?: number; count?: number }) => void
    maxWarnings?: number
    onMaxWarningsReached?: () => void
    lookAwayThreshold?: number // seconds before warning
}

interface GazeState {
    isCalibrated: boolean
    isLookingAway: boolean
    lookAwayCount: number
    lookAwayStartTime: number | null
    currentLookAwayDuration: number
    phoneDetected: boolean
    phoneCount: number
}

export function GazeTracker({
    enabled,
    onViolation,
    maxWarnings = 5,
    onMaxWarningsReached,
    lookAwayThreshold = 15 // 15 seconds default
}: GazeTrackerProps) {
    const videoRef = useRef<HTMLVideoElement>(null)
    const canvasRef = useRef<HTMLCanvasElement>(null)
    const [gazeState, setGazeState] = useState<GazeState>({
        isCalibrated: false,
        isLookingAway: false,
        lookAwayCount: 0,
        lookAwayStartTime: null,
        currentLookAwayDuration: 0,
        phoneDetected: false,
        phoneCount: 0
    })
    const [calibrationStep, setCalibrationStep] = useState(0)
    const [showCalibration, setShowCalibration] = useState(false)
    const [faceDetected, setFaceDetected] = useState(false)
    const [status, setStatus] = useState<"initializing" | "ready" | "error">("initializing")

    const animationFrameRef = useRef<number | null>(null)
    const lookAwayTimerRef = useRef<NodeJS.Timeout | null>(null)
    const phoneDetectorRef = useRef<unknown>(null)

    // Calibration points (5-point calibration)
    const calibrationPoints = [
        { x: 50, y: 50, label: "Trung tâm" },
        { x: 10, y: 10, label: "Góc trên trái" },
        { x: 90, y: 10, label: "Góc trên phải" },
        { x: 10, y: 90, label: "Góc dưới trái" },
        { x: 90, y: 90, label: "Góc dưới phải" }
    ]

    // Initialize MediaPipe and Object Detection
    useEffect(() => {
        if (!enabled) return

        const initTracking = async () => {
            try {
                // Initialize MediaPipe Face Mesh
                const { FaceMesh } = await import("@mediapipe/face_mesh")
                const { Camera } = await import("@mediapipe/camera_utils")

                const mesh = new FaceMesh({
                    locateFile: (file) => {
                        return `https://cdn.jsdelivr.net/npm/@mediapipe/face_mesh/${file}`
                    }
                })

                mesh.setOptions({
                    maxNumFaces: 2,
                    refineLandmarks: true,
                    minDetectionConfidence: 0.5,
                    minTrackingConfidence: 0.5
                })

                mesh.onResults(onFaceMeshResults)

                // Initialize COCO-SSD for phone detection
                const cocoSsd = await import("@tensorflow-models/coco-ssd")
                const tf = await import("@tensorflow/tfjs")
                await tf.ready()
                phoneDetectorRef.current = await cocoSsd.load()

                // Start camera
                if (videoRef.current) {
                    const camera = new Camera(videoRef.current, {
                        onFrame: async () => {
                            if (videoRef.current) {
                                await mesh.send({ image: videoRef.current })
                                // Run phone detection every 2 seconds
                                detectPhone()
                            }
                        },
                        width: 640,
                        height: 480
                    })
                    await camera.start()
                    setStatus("ready")
                }
            } catch (error) {
                console.error("Failed to initialize tracking:", error)
                setStatus("error")
            }
        }

        initTracking()

        return () => {
            if (lookAwayTimerRef.current) {
                clearInterval(lookAwayTimerRef.current)
            }
            if (animationFrameRef.current) {
                cancelAnimationFrame(animationFrameRef.current)
            }
        }
    }, [enabled])

    // Timer to track look-away duration
    useEffect(() => {
        if (!enabled) return

        lookAwayTimerRef.current = setInterval(() => {
            setGazeState(prev => {
                if (prev.lookAwayStartTime && prev.isLookingAway) {
                    const duration = (Date.now() - prev.lookAwayStartTime) / 1000

                    // Check if exceeded threshold
                    if (duration >= lookAwayThreshold && duration < lookAwayThreshold + 1) {
                        // Just crossed threshold - trigger warning
                        onViolation?.("look_away_exceeded", {
                            duration: Math.round(duration),
                            threshold: lookAwayThreshold
                        })

                        const newCount = prev.lookAwayCount + 1
                        if (newCount >= maxWarnings) {
                            onMaxWarningsReached?.()
                        }

                        return {
                            ...prev,
                            currentLookAwayDuration: duration,
                            lookAwayCount: newCount
                        }
                    }

                    return { ...prev, currentLookAwayDuration: duration }
                }
                return prev
            })
        }, 1000)

        return () => {
            if (lookAwayTimerRef.current) {
                clearInterval(lookAwayTimerRef.current)
            }
        }
    }, [enabled, lookAwayThreshold, maxWarnings])

    // Phone detection using COCO-SSD
    const detectPhone = useCallback(async () => {
        if (!phoneDetectorRef.current || !videoRef.current) return

        try {
            const detector = phoneDetectorRef.current as { detect: (v: HTMLVideoElement) => Promise<Array<{ class: string, score: number }>> }
            const predictions = await detector.detect(videoRef.current)

            // Look for cell phone class
            const phoneDetection = predictions.find(
                (p: { class: string; score: number }) => p.class === "cell phone" && p.score > 0.5
            )

            if (phoneDetection) {
                setGazeState(prev => {
                    const newCount = prev.phoneCount + 1
                    onViolation?.("phone_detected", {
                        confidence: phoneDetection.score,
                        count: newCount
                    })
                    return {
                        ...prev,
                        phoneDetected: true,
                        phoneCount: newCount
                    }
                })
            } else {
                setGazeState(prev => ({ ...prev, phoneDetected: false }))
            }
        } catch (error) {
            console.error("Phone detection error:", error)
        }
    }, [onViolation])

    const onFaceMeshResults = useCallback((results: { multiFaceLandmarks?: Array<Array<{ x: number; y: number; z: number }>> }) => {
        if (!results.multiFaceLandmarks) return

        const faceCount = results.multiFaceLandmarks.length

        // Multi-face detection
        if (faceCount > 1) {
            onViolation?.("multi_face", { count: faceCount })
        }

        // No face detected - start look-away timer
        if (faceCount === 0) {
            setFaceDetected(false)
            setGazeState(prev => {
                if (!prev.isLookingAway) {
                    return {
                        ...prev,
                        isLookingAway: true,
                        lookAwayStartTime: Date.now()
                    }
                }
                return prev
            })
            return
        }

        setFaceDetected(true)
        const landmarks = results.multiFaceLandmarks[0]

        // Get iris landmarks for gaze estimation
        const leftIris = landmarks[468]
        const rightIris = landmarks[473]
        const noseTip = landmarks[1]

        // Eye corner landmarks
        const leftEyeInner = landmarks[133]
        const leftEyeOuter = landmarks[33]
        const rightEyeInner = landmarks[362]
        const rightEyeOuter = landmarks[263]

        // Calculate gaze direction
        const leftGazeX = (leftIris.x - leftEyeInner.x) / (leftEyeOuter.x - leftEyeInner.x)
        const rightGazeX = (rightIris.x - rightEyeInner.x) / (rightEyeOuter.x - rightEyeInner.x)
        const avgGazeX = (leftGazeX + rightGazeX) / 2
        const gazeY = noseTip.y

        // Check if looking away (wider threshold to allow calculator use)
        const isLookingAway = avgGazeX < 0.15 || avgGazeX > 0.85 || gazeY < 0.25 || gazeY > 0.75

        setGazeState(prev => {
            if (isLookingAway && !prev.isLookingAway) {
                // Just started looking away
                return {
                    ...prev,
                    isLookingAway: true,
                    lookAwayStartTime: Date.now(),
                    currentLookAwayDuration: 0
                }
            } else if (!isLookingAway && prev.isLookingAway) {
                // Returned to looking at screen - reset timer
                return {
                    ...prev,
                    isLookingAway: false,
                    lookAwayStartTime: null,
                    currentLookAwayDuration: 0
                }
            }
            return prev
        })

        // Draw on canvas for debugging (optional)
        if (canvasRef.current) {
            drawFaceMesh(landmarks, canvasRef.current)
        }
    }, [onViolation])

    const drawFaceMesh = (landmarks: Array<{ x: number; y: number; z: number }>, canvas: HTMLCanvasElement) => {
        const ctx = canvas.getContext("2d")
        if (!ctx) return

        ctx.clearRect(0, 0, canvas.width, canvas.height)
        ctx.fillStyle = "#00ff00"

        // Draw iris points
        const irisIndices = [468, 469, 470, 471, 472, 473, 474, 475, 476, 477]
        irisIndices.forEach(idx => {
            const point = landmarks[idx]
            ctx.beginPath()
            ctx.arc(point.x * canvas.width, point.y * canvas.height, 2, 0, 2 * Math.PI)
            ctx.fill()
        })
    }

    const startCalibration = () => {
        setShowCalibration(true)
        setCalibrationStep(0)
    }

    const nextCalibrationStep = () => {
        if (calibrationStep < calibrationPoints.length - 1) {
            setCalibrationStep(calibrationStep + 1)
        } else {
            setShowCalibration(false)
            setGazeState(prev => ({ ...prev, isCalibrated: true }))
        }
    }

    if (!enabled) return null

    return (
        <div className="fixed top-4 right-4 z-50">
            {/* Hidden video for camera capture */}
            <video
                ref={videoRef}
                className="hidden"
                autoPlay
                playsInline
                muted
            />
            <canvas
                ref={canvasRef}
                width={160}
                height={120}
                className="hidden"
            />

            {/* Status indicator */}
            <div className="bg-slate-800/90 backdrop-blur-sm rounded-lg p-3 border border-slate-700 shadow-lg min-w-[200px]">
                {/* Status header */}
                <div className="flex items-center gap-2 text-sm mb-2">
                    {status === "initializing" && (
                        <>
                            <div className="w-4 h-4 border-2 border-blue-400 border-t-transparent rounded-full animate-spin" />
                            <span className="text-blue-400">Đang khởi tạo...</span>
                        </>
                    )}
                    {status === "ready" && faceDetected && !gazeState.isLookingAway && (
                        <>
                            <Eye className="w-4 h-4 text-green-400" />
                            <span className="text-green-400">Đang giám sát</span>
                        </>
                    )}
                    {status === "ready" && !faceDetected && (
                        <>
                            <AlertTriangle className="w-4 h-4 text-yellow-400" />
                            <span className="text-yellow-400">Không thấy khuôn mặt</span>
                        </>
                    )}
                    {status === "ready" && gazeState.isLookingAway && (
                        <>
                            <AlertTriangle className="w-4 h-4 text-orange-400" />
                            <span className="text-orange-400">
                                Nhìn đi: {Math.round(gazeState.currentLookAwayDuration)}s
                            </span>
                        </>
                    )}
                    {status === "error" && (
                        <>
                            <AlertTriangle className="w-4 h-4 text-red-400" />
                            <span className="text-red-400">Lỗi camera</span>
                        </>
                    )}
                </div>

                {/* Progress bar for look-away */}
                {gazeState.isLookingAway && (
                    <div className="mb-2">
                        <div className="h-1 bg-slate-700 rounded-full overflow-hidden">
                            <div
                                className={`h-full transition-all duration-1000 ${gazeState.currentLookAwayDuration >= lookAwayThreshold
                                    ? "bg-red-500"
                                    : "bg-yellow-500"
                                    }`}
                                style={{
                                    width: `${Math.min(100, (gazeState.currentLookAwayDuration / lookAwayThreshold) * 100)}%`
                                }}
                            />
                        </div>
                        <p className="text-xs text-slate-500 mt-1">
                            {gazeState.currentLookAwayDuration < lookAwayThreshold
                                ? `Còn ${Math.round(lookAwayThreshold - gazeState.currentLookAwayDuration)}s`
                                : "⚠️ Vượt ngưỡng!"}
                        </p>
                    </div>
                )}

                {/* Phone detection alert */}
                {gazeState.phoneDetected && (
                    <div className="flex items-center gap-2 text-sm text-red-400 bg-red-500/20 rounded px-2 py-1 mb-2">
                        <Smartphone className="w-4 h-4" />
                        <span>Phát hiện điện thoại!</span>
                    </div>
                )}

                {/* Warning counter */}
                {gazeState.lookAwayCount > 0 && (
                    <div className="text-xs text-yellow-400 border-t border-slate-700 pt-2">
                        Cảnh báo: {gazeState.lookAwayCount}/{maxWarnings}
                    </div>
                )}

                {gazeState.phoneCount > 0 && (
                    <div className="text-xs text-red-400">
                        Điện thoại: {gazeState.phoneCount} lần
                    </div>
                )}

                {/* Calibration button */}
                {status === "ready" && !gazeState.isCalibrated && (
                    <button
                        onClick={startCalibration}
                        className="mt-2 w-full px-3 py-1.5 bg-blue-600 hover:bg-blue-700 text-white text-xs rounded transition-colors"
                    >
                        Hiệu chuẩn camera
                    </button>
                )}
            </div>

            {/* Calibration overlay */}
            {showCalibration && (
                <div className="fixed inset-0 bg-black/90 z-[100] flex items-center justify-center">
                    <div className="text-center">
                        <h2 className="text-white text-2xl font-bold mb-4">
                            Hiệu chuẩn Camera
                        </h2>
                        <p className="text-slate-300 mb-8">
                            Nhìn vào điểm màu xanh và bấm <strong>Tiếp tục</strong>
                        </p>

                        {/* Calibration point */}
                        <div
                            className="fixed w-8 h-8 bg-green-500 rounded-full animate-pulse shadow-lg shadow-green-500/50"
                            style={{
                                left: `${calibrationPoints[calibrationStep].x}%`,
                                top: `${calibrationPoints[calibrationStep].y}%`,
                                transform: "translate(-50%, -50%)"
                            }}
                        />

                        <p className="text-slate-400 text-sm mb-4">
                            {calibrationPoints[calibrationStep].label}
                            <span className="text-slate-500 ml-2">
                                ({calibrationStep + 1}/{calibrationPoints.length})
                            </span>
                        </p>

                        <button
                            onClick={nextCalibrationStep}
                            className="px-8 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-medium transition-colors"
                        >
                            {calibrationStep === calibrationPoints.length - 1
                                ? "✓ Hoàn thành"
                                : "Tiếp tục →"}
                        </button>
                    </div>
                </div>
            )}
        </div>
    )
}

"use client"

import { useState, useEffect } from "react"
import { Download, X, Smartphone } from "lucide-react"
import { cn } from "@/lib/utils"

interface BeforeInstallPromptEvent extends Event {
    prompt: () => Promise<void>
    userChoice: Promise<{ outcome: "accepted" | "dismissed" }>
}

export function InstallPrompt() {
    const [deferredPrompt, setDeferredPrompt] = useState<BeforeInstallPromptEvent | null>(null)
    const [showBanner, setShowBanner] = useState(false)
    const [isIOS, setIsIOS] = useState(false)
    const [showIOSGuide, setShowIOSGuide] = useState(false)

    useEffect(() => {
        // Check if already installed
        if (window.matchMedia("(display-mode: standalone)").matches) {
            return
        }

        // Check if dismissed recently
        const dismissed = localStorage.getItem("pwa-install-dismissed")
        if (dismissed) {
            const dismissedTime = parseInt(dismissed)
            const daysSinceDismissed = (Date.now() - dismissedTime) / (1000 * 60 * 60 * 24)
            if (daysSinceDismissed < 7) return
        }

        // Detect iOS
        const isIOSDevice = /iPad|iPhone|iPod/.test(navigator.userAgent) && !(window as unknown as { MSStream?: unknown }).MSStream
        setIsIOS(isIOSDevice)

        if (isIOSDevice) {
            // Show iOS guide after a delay
            const timer = setTimeout(() => setShowBanner(true), 3000)
            return () => clearTimeout(timer)
        }

        // Handle beforeinstallprompt for Android/Desktop
        const handler = (e: Event) => {
            e.preventDefault()
            setDeferredPrompt(e as BeforeInstallPromptEvent)
            setTimeout(() => setShowBanner(true), 2000)
        }

        window.addEventListener("beforeinstallprompt", handler)
        return () => window.removeEventListener("beforeinstallprompt", handler)
    }, [])

    const handleInstall = async () => {
        if (!deferredPrompt) {
            if (isIOS) {
                setShowIOSGuide(true)
            }
            return
        }

        await deferredPrompt.prompt()
        const { outcome } = await deferredPrompt.userChoice

        if (outcome === "accepted") {
            setShowBanner(false)
        }
        setDeferredPrompt(null)
    }

    const handleDismiss = () => {
        setShowBanner(false)
        setShowIOSGuide(false)
        localStorage.setItem("pwa-install-dismissed", Date.now().toString())
    }

    if (!showBanner) return null

    return (
        <>
            {/* Install Banner */}
            <div className={cn(
                "fixed bottom-20 left-4 right-4 md:left-auto md:right-4 md:w-96 z-50",
                "bg-gradient-to-r from-blue-600 to-purple-600 rounded-2xl shadow-2xl",
                "animate-in slide-in-from-bottom-5 duration-300"
            )}>
                <div className="p-4">
                    <button
                        onClick={handleDismiss}
                        className="absolute top-3 right-3 text-white/70 hover:text-white"
                    >
                        <X className="w-5 h-5" />
                    </button>

                    <div className="flex items-start gap-4">
                        <div className="w-14 h-14 rounded-xl bg-white/20 flex items-center justify-center shrink-0">
                            <Smartphone className="w-7 h-7 text-white" />
                        </div>
                        <div className="flex-1 min-w-0">
                            <h3 className="font-bold text-white mb-1">
                                Cài đặt ExamHub
                            </h3>
                            <p className="text-sm text-white/80 mb-3">
                                Thêm vào màn hình chính để truy cập nhanh hơn
                            </p>
                            <button
                                onClick={handleInstall}
                                className="inline-flex items-center gap-2 px-4 py-2 bg-white text-blue-600 rounded-lg font-semibold text-sm hover:bg-blue-50 transition-colors"
                            >
                                <Download className="w-4 h-4" />
                                {isIOS ? "Xem hướng dẫn" : "Cài đặt ngay"}
                            </button>
                        </div>
                    </div>
                </div>
            </div>

            {/* iOS Installation Guide Modal */}
            {showIOSGuide && (
                <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/60 backdrop-blur-sm animate-in fade-in">
                    <div className="w-full max-w-lg bg-slate-900 rounded-t-3xl p-6 animate-in slide-in-from-bottom">
                        <div className="flex items-center justify-between mb-6">
                            <h2 className="text-xl font-bold text-white">
                                Cài đặt trên iOS
                            </h2>
                            <button
                                onClick={handleDismiss}
                                className="text-slate-400 hover:text-white"
                            >
                                <X className="w-6 h-6" />
                            </button>
                        </div>

                        <div className="space-y-4">
                            <div className="flex items-start gap-4 p-4 bg-slate-800 rounded-xl">
                                <div className="w-8 h-8 rounded-full bg-blue-500 flex items-center justify-center text-white font-bold shrink-0">
                                    1
                                </div>
                                <div>
                                    <p className="text-white font-medium">
                                        Nhấn nút Chia sẻ
                                    </p>
                                    <p className="text-sm text-slate-400">
                                        Biểu tượng <span className="text-blue-400">⬆️</span> ở thanh công cụ Safari
                                    </p>
                                </div>
                            </div>

                            <div className="flex items-start gap-4 p-4 bg-slate-800 rounded-xl">
                                <div className="w-8 h-8 rounded-full bg-blue-500 flex items-center justify-center text-white font-bold shrink-0">
                                    2
                                </div>
                                <div>
                                    <p className="text-white font-medium">
                                        Chọn &quot;Thêm vào Màn hình chính&quot;
                                    </p>
                                    <p className="text-sm text-slate-400">
                                        Cuộn xuống và tìm tùy chọn này
                                    </p>
                                </div>
                            </div>

                            <div className="flex items-start gap-4 p-4 bg-slate-800 rounded-xl">
                                <div className="w-8 h-8 rounded-full bg-blue-500 flex items-center justify-center text-white font-bold shrink-0">
                                    3
                                </div>
                                <div>
                                    <p className="text-white font-medium">
                                        Nhấn &quot;Thêm&quot;
                                    </p>
                                    <p className="text-sm text-slate-400">
                                        ExamHub sẽ xuất hiện trên màn hình chính
                                    </p>
                                </div>
                            </div>
                        </div>

                        <button
                            onClick={handleDismiss}
                            className="w-full mt-6 py-3 bg-gradient-to-r from-blue-500 to-purple-500 text-white font-semibold rounded-xl"
                        >
                            Đã hiểu
                        </button>
                    </div>
                </div>
            )}
        </>
    )
}

"use client"

import { useTheme } from "@/components/ThemeProvider"
import { Button } from "@/components/ui/button"
import { Sun, Moon, Monitor } from "lucide-react"
import { useState, useRef, useEffect } from "react"

export function ThemeToggle() {
    const [mounted, setMounted] = useState(false)
    const [isOpen, setIsOpen] = useState(false)
    const dropdownRef = useRef<HTMLDivElement>(null)

    // Only access theme context after mount
    useEffect(() => {
        setMounted(true)
    }, [])

    // Close dropdown when clicking outside
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
                setIsOpen(false)
            }
        }
        document.addEventListener("mousedown", handleClickOutside)
        return () => document.removeEventListener("mousedown", handleClickOutside)
    }, [])

    const themes = [
        { value: "light" as const, label: "Sáng", icon: Sun },
        { value: "dark" as const, label: "Tối", icon: Moon },
        { value: "system" as const, label: "Hệ thống", icon: Monitor },
    ]

    // Show placeholder while not mounted
    if (!mounted) {
        return (
            <Button
                variant="ghost"
                size="icon"
                className="h-9 w-9 rounded-lg hover:bg-muted"
                aria-label="Chọn giao diện"
            >
                <Sun className="h-5 w-5" />
            </Button>
        )
    }

    // Now safe to use the hook
    return <ThemeToggleInner isOpen={isOpen} setIsOpen={setIsOpen} dropdownRef={dropdownRef} themes={themes} />
}

function ThemeToggleInner({
    isOpen,
    setIsOpen,
    dropdownRef,
    themes
}: {
    isOpen: boolean
    setIsOpen: (open: boolean) => void
    dropdownRef: React.RefObject<HTMLDivElement | null>
    themes: { value: "light" | "dark" | "system"; label: string; icon: typeof Sun }[]
}) {
    const { theme, setTheme, resolvedTheme } = useTheme()
    const CurrentIcon = resolvedTheme === "dark" ? Moon : Sun

    return (
        <div className="relative" ref={dropdownRef}>
            <Button
                variant="ghost"
                size="icon"
                onClick={() => setIsOpen(!isOpen)}
                className="h-9 w-9 rounded-lg hover:bg-muted"
                aria-label="Chọn giao diện"
            >
                <CurrentIcon className="h-5 w-5 transition-transform duration-300" />
            </Button>

            {isOpen && (
                <div className="absolute right-0 top-full mt-2 w-36 rounded-lg border border-border bg-popover p-1 shadow-lg animate-in fade-in-0 zoom-in-95 z-50">
                    {themes.map(({ value, label, icon: Icon }) => (
                        <button
                            key={value}
                            onClick={() => {
                                setTheme(value)
                                setIsOpen(false)
                            }}
                            className={`flex w-full items-center gap-2 rounded-md px-3 py-2 text-sm transition-colors hover:bg-muted ${theme === value ? "bg-muted text-foreground" : "text-muted-foreground"
                                }`}
                        >
                            <Icon className="h-4 w-4" />
                            {label}
                        </button>
                    ))}
                </div>
            )}
        </div>
    )
}

import * as React from "react"

import { cn } from "@/lib/utils"

